-- Poems batch 54
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1cef0b00-5ac6-4047-95d7-1950f37b4880','偶題','杜光庭','唐','唐诗','tang','','[]','似鶴如雲一箇身，不憂家國不憂貧。',32,'全唐诗/poet.tang.47000.json','["似鶴如雲一箇身，不憂家國不憂貧。", "擬將枕上日高睡，賣與世間榮貴人。"]'),
('bbd0a42f-6b89-43a6-9200-69c70c1ae200','思山詠','杜光庭','唐','唐诗','tang','','[]','因賣丹砂下白雲，鹿裘惟惹九衢塵。',32,'全唐诗/poet.tang.47000.json','["因賣丹砂下白雲，鹿裘惟惹九衢塵。", "不如將耳入山去，萬是千非愁殺人。"]'),
('d687e169-b293-4a84-af21-f476fe3044b9','景福中作','杜光庭','唐','唐诗','tang','','[]','悶見戈鋋匝四溟，恨無奇策救生靈。',32,'全唐诗/poet.tang.47000.json','["悶見戈鋋匝四溟，恨無奇策救生靈。", "如何飲酒得長醉，直到太平時節醒。"]'),
('268a3ed6-dad4-4c42-ae5f-30e283589193','招友人遊春','杜光庭','唐','唐诗','tang','','[]','難把長繩繫日烏，芳時偷取醉功夫。',32,'全唐诗/poet.tang.47000.json','["難把長繩繫日烏，芳時偷取醉功夫。", "任堆金璧磨星斗，買得花枝不老無。"]'),
('3ce5c277-0f7f-4459-9cad-d7a7f94d9376','山居三首 一','杜光庭','唐','唐诗','tang','','[]','悶見有人尋，移菴更入深。',48,'全唐诗/poet.tang.47000.json','["悶見有人尋，移菴更入深。", "落花流澗水，明月照松林。", "醉勸頭陀酒，閑教孺子吟。", "身同雲外鶴，斷得世塵侵。"]'),
('1f020388-0b7b-46f6-8aea-46a37083f541','山居三首 二','杜光庭','唐','唐诗','tang','','[]','冥心栖太室，散髮浸流泉。',48,'全唐诗/poet.tang.47000.json','["冥心栖太室，散髮浸流泉。", "採柏時逢麝，看雲忽見仙。", "夏狂衝雨戲，春醉戴花眠。", "絕頂登雲望，東都一點煙。"]'),
('ae2d07a5-ef54-41d9-9bec-447c5ff0131b','山居三首 三','杜光庭','唐','唐诗','tang','','[]','不求朝野知，臥見歲華移。',48,'全唐诗/poet.tang.47000.json','["不求朝野知，臥見歲華移。", "採藥歸侵夜，聽松飯過時。", "荷竿尋水釣，背局上岩棊。", "祭廟人來說，中原正亂離。"]'),
('90e52042-fe23-4354-b08c-5d047e636ec1','紀道德','杜光庭','唐','唐诗','tang','','[]','道，德。',270,'全唐诗/poet.tang.47000.json','["道，德。", "清虛，玄默。", "生帝先，爲聖則。", "聽之不聞，摶之不得。", "至德本無爲，人中多自惑。", "在洗心而息慮，亦知白而守黑。", "百姓日用而不知，上士勤行而必克。", "既鼓鑄於乾坤品物，信充仞乎東西南北。", "三皇高拱兮任以自然，五帝垂衣兮修之不忒。", "以心體之者爲四海之主，以身彎之者爲萬夫之特。", "有皓齒青娥者爲伐命之斧，蘊奇謀廣智者爲盜國之賊。", "曾未若軒后順風兮清靜自化，曾未若臯陶邁種兮溫恭允塞。", "故可以越圓清方濁兮不始不終，何止乎居九流五常兮理家理國。", "豈不聞乎天地於道德也無以清寧，豈不聞乎道德於天地也有踰繩墨。", "語不云乎仲尼有言朝聞道夕死可矣，所以垂萬古歷百王不敢離之於頃刻。"]'),
('ccc5a6c0-8ffa-47c5-a56d-02a62848e266','懷古今','杜光庭','唐','唐诗','tang','','[]','古，今。',270,'全唐诗/poet.tang.47000.json','["古，今。", "感事，傷心。", "驚得喪，歎浮沈。", "風駈寒署，川注光陰。", "始衒朱顏麗，俄悲白髮侵。", "嗟四豪之不返，痛七貴以難尋。", "夸父興懷於落照，田文起怨於鳴琴。", "鴈足淒涼兮傳恨緒，鳳臺寂寞兮有遺音。", "朔漠幽囚兮天長地久，瀟湘隔別兮水闊煙深。", "誰能絕聖韜賢餐芝餌朮，誰能含光遁世鍊石燒金。", "君不見屈大夫紉蘭而發諫，君不見賈太傅忌鵩而愁吟。", "君不見四皓避秦峨峨戀商嶺，君不見二疎辭漢飄飄歸故林。", "胡爲乎冒進貪名踐危途與傾轍，胡爲乎怙權恃寵顧華飾與彫簪。", "吾所以思抗跡忘機用虛無爲師範，吾所以思去奢滅慾保道德爲規箴。", "不能勞神傚蘇子張生兮於時而縱辯，不能勞神傚楊朱墨翟兮揮涕以沾襟。"]'),
('15d17d1f-bfe1-4f57-a310-8b880f34402d','句','杜光庭','唐','唐诗','tang','','[]','銅壺滴滴禁漏起，三十六宮爭捲簾。',144,'全唐诗/poet.tang.47000.json','["銅壺滴滴禁漏起，三十六宮爭捲簾。", "斜陽古岸歸鴉晚，紅蓼低沙宿雁愁。", "霜彫曲徑寒蕪白，雁下遙村落照黃。", "恩威欲寄黃丞相，仁信先聞郭細侯。", "兵氣此時來世上，文星今日到人間。", "降因天下思姚宋，出爲儒門繼孔顏。", "丹竈河車休矻矻，蚌胎龜息且緜緜。", "馭景必能趨日域，騎箕終擬躡星躔。", "返樸還淳皆至理，遺形忘性盡真銓。"]'),
('7df6ef7b-d31d-4feb-9f65-938edb8106f9','山居 一','鄭遨','唐','唐诗','tang','','[]','悶見有人尋，移庵更入深。',48,'全唐诗/poet.tang.47000.json','["悶見有人尋，移庵更入深。", "落花流澗水，明月照松林。", "醉勸頭陀酒，閑教孺子吟。", "身同雲外鶴，斷得世塵侵。"]'),
('cba7999a-efb2-422e-bd1a-ec7faa57f6e5','山居 二','鄭遨','唐','唐诗','tang','','[]','冥心棲太室，散髮浸流泉。',48,'全唐诗/poet.tang.47000.json','["冥心棲太室，散髮浸流泉。", "採柏時逢麝，看雲忽見山。", "夏狂衝雨戲，春醉戴花眠。", "絕頂登雲望，東都一點煙。"]'),
('3deb5cd3-49f3-40d3-a0bd-9d554fdb1369','山居 三','鄭遨','唐','唐诗','tang','','[]','不求朝野知，臥見歲華移。',48,'全唐诗/poet.tang.47000.json','["不求朝野知，臥見歲華移。", "採藥歸侵夜，聽松飯過時。", "荷竿尋水釣，背局上巖碁。", "祭廟人來說，中原正亂離。"]'),
('217daaab-0171-486d-acfe-c358b2182742','茶詩','鄭遨','唐','唐诗','tang','','[]','嫩芽香且靈，吾謂草中英。',48,'全唐诗/poet.tang.47000.json','["嫩芽香且靈，吾謂草中英。", "夜臼和煙搗，寒鑪對雪烹。", "惟憂碧粉散，常見綠花生。", "最是堪珍重，能令睡思清。"]'),
('1567285f-556a-4c74-828d-3434c66439f1','哭張道古','鄭遨','唐','唐诗','tang','','[]','曾陳章疏忤昭皇，撲落西南事可傷。',64,'全唐诗/poet.tang.47000.json','["曾陳章疏忤昭皇，撲落西南事可傷。", "豈使諫臣終屈辱，直疑天道惡忠良。", "生前賣卜居三蜀，死後馳名遍大唐。", "誰是後來脩史者，言君力死正頹綱。"]'),
('0748716d-b669-4347-a5f0-a1579355a486','富貴曲','鄭遨','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u5973\u5b50", "\u8bbd\u523a"]','美人梳洗時，滿頭間珠翠。',24,'全唐诗/poet.tang.47000.json','["美人梳洗時，滿頭間珠翠。", "豈知兩片雲，戴却數鄉稅。"]'),
('9b543959-9716-4cb5-aaf8-12cc6946fdad','傷農','鄭遨','唐','唐诗','tang','','[]','一粒紅稻飯，幾滴牛頷血。',24,'全唐诗/poet.tang.47000.json','["一粒紅稻飯，幾滴牛頷血。", "珊瑚枝下人，銜杯吐不歇。"]'),
('c5f2ce83-f6c6-4187-ba8e-c4ec2672287f','詠西施','鄭遨','唐','唐诗','tang','','[]','素面已云妖，更著花鈿餙。',24,'全唐诗/poet.tang.47000.json','["素面已云妖，更著花鈿餙。", "臉橫一寸波，浸破吳王國。"]'),
('d3ba7bcd-92f8-4ca9-befb-609f0e2e4526','思山詠','鄭遨','唐','唐诗','tang','','[]','因賣丹砂下白雲，鹿裘惟惹九衢塵。',32,'全唐诗/poet.tang.47000.json','["因賣丹砂下白雲，鹿裘惟惹九衢塵。", "不如將耳入山去，萬是千非愁殺人。"]'),
('71e31d3b-1984-450b-b130-5e07881647dd','招友人遊春','鄭遨','唐','唐诗','tang','','[]','難把長繩繫日烏，芳時偷取醉工夫。',32,'全唐诗/poet.tang.47000.json','["難把長繩繫日烏，芳時偷取醉工夫。", "任堆金璧磨星斗，買得花枝不老無。"]'),
('45d94f54-64a8-4a1f-be70-b14b2ee6e0f2','宿洞庭','鄭遨','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','月到君山酒半醒，朗吟疑有水仙聽。',32,'全唐诗/poet.tang.47000.json','["月到君山酒半醒，朗吟疑有水仙聽。", "無人識我真閑事，贏得高秋看洞庭。"]'),
('8c7891f1-abbb-4cab-ba6d-423449815c10','題病僧寮','鄭遨','唐','唐诗','tang','','[]','佛前香印廢晨燒，金錫當門照寂寥。',32,'全唐诗/poet.tang.47000.json','["佛前香印廢晨燒，金錫當門照寂寥。", "童子不知師病困，報風吹折好芭蕉。"]'),
('6ef10faf-f259-472f-81e7-9fc6613974e7','題霍山秦尊師','鄭遨','唐','唐诗','tang','','[]','老鶴玄猨伴採芝，有時長歎獨移時。',32,'全唐诗/poet.tang.47000.json','["老鶴玄猨伴採芝，有時長歎獨移時。", "翠娥紅粉渾如劒，殺盡世人人不知。"]'),
('a016f202-51e3-4dce-9ad2-ed5bcd9799d3','偶題 一','鄭遨','唐','唐诗','tang','','[]','似鶴如雲一箇身，不憂家國不憂貧。',32,'全唐诗/poet.tang.47000.json','["似鶴如雲一箇身，不憂家國不憂貧。", "擬將枕上日高睡，賣與世間榮貴人。"]'),
('435c06d8-5129-483c-b02a-2731b0eeedca','偶題 二','鄭遨','唐','唐诗','tang','','[]','帆力劈開滄海浪，馬蹄踏破亂山青。',32,'全唐诗/poet.tang.47000.json','["帆力劈開滄海浪，馬蹄踏破亂山青。", "浮名浮利濃於酒，醉得人心死不醒。"]'),
('3bb2345e-65f2-4bce-b84a-9467dab0a9f0','景福中作','鄭遨','唐','唐诗','tang','','[]','悶見戈鋋匝四溟，恨無奇策救生靈。',32,'全唐诗/poet.tang.47000.json','["悶見戈鋋匝四溟，恨無奇策救生靈。", "如何飲酒得長醉，直到太平時節醒。"]'),
('8c7bba4d-eb5a-493f-accf-012b8e375600','題中條靜觀','鄭遨','唐','唐诗','tang','','[]','松頂留衣上玉霄，永傳異迹在中條。',32,'全唐诗/poet.tang.47000.json','["松頂留衣上玉霄，永傳異迹在中條。", "不知揖徧諸仙否，欲請還丹問昨宵。"]'),
('19252fe2-b344-49ee-8b88-5ab241d82a20','送臥雲道士','虞有賢','唐','唐诗','tang','','[]','臥雲道士來相辭，相辭倏忽何所之。',92,'全唐诗/poet.tang.47000.json','["臥雲道士來相辭，相辭倏忽何所之。", "紫閣春深煙靄靄，東風花柳折枝枝。", "藥成酒熟有時節，寒食恐失松間期。", "冥鴻一見傷弓翼，高飛展轉心無疑。", "滿酌數杯酒，狂吟幾首詩。", "留不住，去不悲，醯雞蜉蝣安得知。"]'),
('d5ec433e-8bd5-45a7-a676-c0fa91bbe5a7','示守庚申衆','程紫霄','唐','唐诗','tang','','[]','不守庚申亦不疑，此心長與道相依。',32,'全唐诗/poet.tang.47000.json','["不守庚申亦不疑，此心長與道相依。", "玉皇已自知行止，仁汝三彭說是非。"]'),
('c64146c3-c6b7-41a9-a6b3-4160bc007d43','蘭谿靈瑞觀','舒道紀','唐','唐诗','tang','','[]','澄心坐清境，虛白生林端。',48,'全唐诗/poet.tang.47000.json','["澄心坐清境，虛白生林端。", "夜靜笑聲出，月明松影寒。", "絳霞封藥竈，碧竇濺齋壇。", "海樹幾回老，先生棊未殘。"]'),
('b604ea3b-6364-4841-b985-d8b40c491d15','題赤松宮','舒道紀','唐','唐诗','tang','','[]','松老赤松原，松間廟宛然。',48,'全唐诗/poet.tang.47000.json','["松老赤松原，松間廟宛然。", "人皆有兄弟，誰得共神仙。", "雙鶴沖天去，羣羊化石眠。", "至今丹井水，香滿北山邊。"]'),
('ed0cf424-64a3-4779-8e7b-c21136034ab1','參同契明鏡圖訣詩二首 一','彭曉','唐','唐诗','tang','','[]','造化潛施跡莫窮，簇成真訣指蒙童。',64,'全唐诗/poet.tang.47000.json','["造化潛施跡莫窮，簇成真訣指蒙童。", "三篇祕列八環內，萬象門開一鏡中。", "離女駕龍爲木壻，坎男乘虎作金翁。", "同人好道宜精究，究得長生路便通。"]'),
('cc3bab63-46c3-4010-973a-251f97b433a7','參同契明鏡圖訣詩二首 二','彭曉','唐','唐诗','tang','','[]','至道希夷妙且深，燒丹先認大還心。',64,'全唐诗/poet.tang.47000.json','["至道希夷妙且深，燒丹先認大還心。", "日爻陰耦生真汞，月卦陽奇產正金。", "女妊朱砂男孕雪，北藏熒惑丙含壬。", "兩端指的鉛金祖，莫向諸般取次尋。"]'),
('d3cc1386-bfb9-4c25-abd7-12ead8f97b62','題柳公權書度人經後','魚又玄','唐','唐诗','tang','','[]','臥雲道士來相辭，相辭倏忽何所之。',92,'全唐诗/poet.tang.47000.json','["臥雲道士來相辭，相辭倏忽何所之。", "紫閣當春凝煙靄，東風吹岸花枝枝。", "藥成酒熟有時節，寒食恐失松間期。", "冥鴻復見傷弓翼，高飛展轉心無疑。", "滿瀉數杯酒，狂吟幾首詩。", "留不住，去不悲，醯雞蜉蝣可得知。"]'),
('27737fca-8666-46d6-b5bf-fd6599d8a976','呈鍾離雲房','呂巖','唐','唐诗','tang','','[]','生在儒家遇太平，懸纓重滯布衣輕。',32,'全唐诗/poet.tang.47000.json','["生在儒家遇太平，懸纓重滯布衣輕。", "誰能世上爭名利，臣事玉皇歸上清。"]'),
('6090aa67-1d8b-45c0-8c58-f28e6be621e0','獻鄭思遠施真人二仙','呂巖','唐','唐诗','tang','','[]','萬劫千生到此生，此生身始覺飛輕。',64,'全唐诗/poet.tang.47000.json','["萬劫千生到此生，此生身始覺飛輕。", "拋家別國雲山外，煉魄全魂日月精。", "比見至人論九鼎，欲窮大藥訪三清。", "如今獲遇真仙面，紫府仙扉得姓名。"]'),
('0d12c024-1618-4647-80b3-d5364d24f83e','得火龍真人劒法','呂巖','唐','唐诗','tang','','[]','昔年曾遇火龍君，一劒相傳伴此身。',64,'全唐诗/poet.tang.47000.json','["昔年曾遇火龍君，一劒相傳伴此身。", "天地山河從結沫，星辰日月任停輪。", "須知本性綿多劫，空向人間歷萬春。", "昨夜鍾離傳一語，六天宮殿欲成塵。"]'),
('07f22eba-b039-4724-b569-fb13b9240bd9','七言 一','呂巖','唐','唐诗','tang','','[]','周行獨力出群倫，默默昏昏亙古存。',64,'全唐诗/poet.tang.47000.json','["周行獨力出群倫，默默昏昏亙古存。", "無象無形潛造化，有門有戶在乾坤。", "色非色際誰窮處，空不空中自得根。", "此道非從它外得，千言萬語謾評論。"]'),
('f4eabf55-932b-4cc4-850a-fddcef11efc7','七言 二','呂巖','唐','唐诗','tang','','[]','通靈一顆正金丹，不在天涯地角安。',64,'全唐诗/poet.tang.47000.json','["通靈一顆正金丹，不在天涯地角安。", "討論窮經深莫究，登山臨水杳無看。", "光明暗寄希夷頂，赫赤高居混沌端。", "舉世若能知所寓，超凡入聖弗爲難。"]'),
('ff4043b2-5fac-4b3d-9a08-a79ca05f7553','七言 三','呂巖','唐','唐诗','tang','','[]','落魄紅塵四十春，無爲無事信天真。',64,'全唐诗/poet.tang.47000.json','["落魄紅塵四十春，無爲無事信天真。", "生涯只在乾坤鼎，活計惟憑日月輪。", "八卦氣中潛至寶，五行光裏隱元神。", "桑田改變依然在，永作人間出世人。"]'),
('abe64a05-e514-4b1e-bdd5-79543a32e607','七言 四','呂巖','唐','唐诗','tang','','[]','獨處乾坤萬象中，從頭歷歷運元功。',64,'全唐诗/poet.tang.47000.json','["獨處乾坤萬象中，從頭歷歷運元功。", "縱橫北斗心機大，顛倒南辰膽氣雄。", "鬼哭神號金鼎結，雞飛犬化玉爐空。", "如何俗士尋常覓，不達希夷不可窮。"]'),
('7dca253a-f490-4f11-b90c-d034883b7ff1','七言 五','呂巖','唐','唐诗','tang','','[]','誰信華池路最深，非遐非邇奧難尋。',64,'全唐诗/poet.tang.47000.json','["誰信華池路最深，非遐非邇奧難尋。", "九年採煉如紅玉，一日圓成似紫金。", "得了永袪寒署逼，服之應免死生侵。", "勸君門外修身者，端念思惟此道心。"]'),
('2e4d758b-f73d-4cc6-9dba-448fbd3cfcf9','七言 六','呂巖','唐','唐诗','tang','','[]','水府尋鉛合火鉛，黑紅紅黑又玄玄。',64,'全唐诗/poet.tang.47000.json','["水府尋鉛合火鉛，黑紅紅黑又玄玄。", "氣中生氣肌膚換，精裏含精性命專。", "藥返便爲真道士，丹還本是聖胎仙。", "出神入定虛華語，徒費功夫萬萬年。"]'),
('b38ea6a3-972a-42d7-9779-ec796f801d7b','七言 七','呂巖','唐','唐诗','tang','','[]','九鼎烹煎九轉砂，區分時節更無差。',64,'全唐诗/poet.tang.47000.json','["九鼎烹煎九轉砂，區分時節更無差。", "精神氣血歸三要，南北東西共一家。", "天地變通飛白雪，陰陽和合產金花。", "終期鳳詔空中降，跨虎騎龍謁紫霞。"]'),
('aa8fd792-7d79-4d64-8c14-66487034e27d','七言 八','呂巖','唐','唐诗','tang','','[]','憑君子後午前看，一脈天津在脊端。',64,'全唐诗/poet.tang.47000.json','["憑君子後午前看，一脈天津在脊端。", "金闕內藏玄谷子，玉池中坐太和官。", "只將至妙三周火，鍊出通靈九轉丹。", "直指幾多求道者，行藏莫離虎龍灘。"]'),
('1045aa88-ba54-47af-b0ad-c59965a06f63','七言 九','呂巖','唐','唐诗','tang','','[]','返本還元道氣平，虛非形質轉分明。',64,'全唐诗/poet.tang.47000.json','["返本還元道氣平，虛非形質轉分明。", "水中白雪微微結，火裏金蓮漸漸生。", "聖汞論時非有體，真鉛窮看亦無名。", "吾今爲報修行者，莫向燒金問至精。"]'),
('5df11e1f-3c83-4028-8320-ec52714e06df','七言 十','呂巖','唐','唐诗','tang','','[]','安排鼎竈煉玄根，進退須明卯酉門。',64,'全唐诗/poet.tang.47000.json','["安排鼎竈煉玄根，進退須明卯酉門。", "繞電奔雲飛日月，驅龍走虎出乾坤。", "一丸因與紅顏駐，九轉能燒白髮痕。", "此道幽微知者少，茫茫塵世與誰論。"]'),
('7788d525-c5b0-4845-bfab-c1adae510838','七言 十一','呂巖','唐','唐诗','tang','','[]','醍醐一盞詩一篇，暮醉朝吟不記年。',64,'全唐诗/poet.tang.47000.json','["醍醐一盞詩一篇，暮醉朝吟不記年。", "乾馬屢來遊九地，坤牛時駕出三天。", "白龜窟裏夫妻會，青鳳巢中子母圓。", "提挈靈童山上望，重重疊疊是金錢。"]'),
('5d717ab9-0e1f-43d2-a924-91dc6c2b5246','七言 十二','呂巖','唐','唐诗','tang','','[]','認得東西木與金，自然爐鼎虎龍吟。',64,'全唐诗/poet.tang.47000.json','["認得東西木與金，自然爐鼎虎龍吟。", "但隨天地明消息，方識陰陽有信音。", "左掌南辰攀鶴羽，右擎北極剖龜心。", "神仙親口留斯旨，何用區區向外尋。"]'),
('bb5c8185-192f-43eb-bc81-74e9021cbf11','七言 十三','呂巖','唐','唐诗','tang','','[]','一本天機深更深，徒言萬劫與千金。',64,'全唐诗/poet.tang.47000.json','["一本天機深更深，徒言萬劫與千金。", "三冬大熱玄中火，六月霜寒表外陰。", "金爲浮來方見性，木因沈後始知心。", "五行顛倒堪消息，返本還元在己尋。"]'),
('985dcca2-790b-4390-b6d6-240ab7c52c75','七言 十四','呂巖','唐','唐诗','tang','','[]','虎將龍軍氣宇雄，佩符持甲去悤悤。',64,'全唐诗/poet.tang.47000.json','["虎將龍軍氣宇雄，佩符持甲去悤悤。", "鋪排劒戟奔如電，羅列旌旗疾似風。", "活捉三尸焚鬼窟，生禽六賊破魔宮。", "河清海晏乾坤淨，世世安居道德中。"]'),
('f1ec6fff-a3d8-4478-aae6-47f64fdfb083','七言 十五','呂巖','唐','唐诗','tang','','[]','我家勤種我家田，內有靈苗活萬年。',64,'全唐诗/poet.tang.47000.json','["我家勤種我家田，內有靈苗活萬年。", "花似黃金苞不大，子如白玉顆皆圓。", "栽培全賴中宮土，灌溉須憑上谷泉。", "直候九年功滿日，和根拔入大羅天。"]'),
('8109d68c-f4fa-4690-95b5-9b95aacbc23a','七言 十六','呂巖','唐','唐诗','tang','','[]','尋常學道說黃芽，萬水千山覓轉差。',64,'全唐诗/poet.tang.47000.json','["尋常學道說黃芽，萬水千山覓轉差。", "有畛有園難下種，無根無脚自開花。", "九三鼎內烹如酪，六一爐中結似霞。", "不日成丹應換骨，飛升遙指玉皇家。"]'),
('ffe6263e-2684-492b-97a5-1ab69c67c55f','七言 十七','呂巖','唐','唐诗','tang','','[]','四六關頭路坦平，行人到此不須驚。',64,'全唐诗/poet.tang.47000.json','["四六關頭路坦平，行人到此不須驚。", "從教犢駕轟轟轉，儘使羊車軋軋鳴。", "渡海經河稀阻滯，上天入地絕欹傾。", "功成直入長生殿，袖出神珠徹夜明。"]'),
('e6215009-3911-4727-9ac8-f00d4856d675','七言 十八','呂巖','唐','唐诗','tang','','[]','九六相交道氣和，河車晝夜迸金波。',64,'全唐诗/poet.tang.47000.json','["九六相交道氣和，河車晝夜迸金波。", "呼時一一關頭轉，吸處重重脈上摩。", "電激離門光海嶽，雷轟震戶動婆娑。", "思量此道真長遠，學者多迷溺愛河。"]'),
('74b8935a-322a-43c5-b466-493313a3f19d','七言 十九','呂巖','唐','唐诗','tang','','[]','金丹不是小金丹，陰鼎陽爐裏面安。',64,'全唐诗/poet.tang.47000.json','["金丹不是小金丹，陰鼎陽爐裏面安。", "盡道東山尋汞易，豈知西海覓鉛難。", "玄珠窟裏行非遠，赤水灘頭去便端。", "認得靈竿真的路，何勞禮月步星壇。"]'),
('7878efc4-ced8-451d-8e87-00e3ab7a4688','七言 二十','呂巖','唐','唐诗','tang','','[]','古今機要甚分明，自是衆生力量輕。',64,'全唐诗/poet.tang.47000.json','["古今機要甚分明，自是衆生力量輕。", "盡向有中尋有質，誰能無裏見無形。", "真鉛聖汞徒虛費，玉室金關不解扃。", "本色丹瓢推倒後，却吞丸藥待延齡。"]'),
('1e8c126f-098d-4d67-92cd-79d4d3a47e30','七言 二十一','呂巖','唐','唐诗','tang','','[]','浮名浮利兩何堪，迴首歸山味轉甘。',64,'全唐诗/poet.tang.47000.json','["浮名浮利兩何堪，迴首歸山味轉甘。", "舉世算無心可契，誰人更與道相參。", "寸猶未到甘談尺，一尚難明強說三。", "經卷葫蘆幷拄杖，依前擔入舊江南。"]'),
('2887f0ee-033e-45a1-8f89-0bdb03e94873','七言 二十二','呂巖','唐','唐诗','tang','','[]','本來無作亦無行，行着之時是妄情。',64,'全唐诗/poet.tang.47000.json','["本來無作亦無行，行着之時是妄情。", "老氏語中猶未決，瞿曇言下更難明。", "靈竿有節通天去，至藥無根得地生。", "今日與君無恡惜，功成只此是蓬瀛。"]'),
('f44dffb0-d36b-4982-89ec-1795f126cbe2','七言 二十三','呂巖','唐','唐诗','tang','','[]','解將火種種刀圭，火種刀圭世豈知。',64,'全唐诗/poet.tang.47000.json','["解將火種種刀圭，火種刀圭世豈知。", "山上長男騎白馬，水邊少女牧烏龜。", "無中出有還丹象，陰裏生陽大道基。", "顛倒五行憑匠手，不逢匠手莫施爲。"]'),
('37e6155f-679f-4b60-bf32-cb693d1b209c','七言 二十四','呂巖','唐','唐诗','tang','','[]','三千餘法論修行，第一燒丹路最親。',64,'全唐诗/poet.tang.47000.json','["三千餘法論修行，第一燒丹路最親。", "須是坎男端的物，取他離女自然珍。", "烹成不死砂中汞，結出長生水裏銀。", "九轉九還功若就，定將衰老返長春。"]'),
('e6d10dbd-7e3b-4b8b-b837-8acb894621fa','七言 二十五','呂巖','唐','唐诗','tang','','[]','欲種長生不死根，再營陰魄及陽魂。',64,'全唐诗/poet.tang.47000.json','["欲種長生不死根，再營陰魄及陽魂。", "先教玄母歸離戶，後遣空王鎮坎門。", "虎到甲邊風浩浩，龍居庚內水溫溫。", "迷途爭與輕輕泄，此理須憑達者論。"]'),
('94847d21-1614-452b-a015-df7331d753ef','七言 二十六','呂巖','唐','唐诗','tang','','[]','閉目存神玉戶觀，時來火候遞相傳。',64,'全唐诗/poet.tang.47000.json','["閉目存神玉戶觀，時來火候遞相傳。", "雲飛海面龍吞汞，風擊巖巔虎伏鉛。", "一旦煉成身內寶，等閑探得道中玄。", "刀圭餌了丹書降，跳出塵籠上九天。"]'),
('1e7993aa-1bd3-4c81-aeea-e9e5da6c8136','七言 二十七','呂巖','唐','唐诗','tang','','[]','千日功夫不暫閑，河車搬載上崑山。',64,'全唐诗/poet.tang.47000.json','["千日功夫不暫閑，河車搬載上崑山。", "虎抽白汞安爐裏，龍發紅鉛向鼎間。", "仙府記名丹已熟，陰司除籍命應還。", "彩雲捧足歸何處，直入三清謝聖顏。"]'),
('9f7eb727-3246-44e1-bad3-55727da3e95e','七言 二十八','呂巖','唐','唐诗','tang','','[]','解匹真陰與正陽，三年功滿結成霜。',64,'全唐诗/poet.tang.47000.json','["解匹真陰與正陽，三年功滿結成霜。", "神龜出入庚辛位，丹鳳翺翔甲乙方。", "九鼎先輝雙瑞氣，三元中換五毫光。", "塵中若有同機者，共住煙霄不死鄉。"]'),
('d5c0b4e2-28fc-495d-9c8a-d9c0f58b60a9','七言 二十九','呂巖','唐','唐诗','tang','','[]','修生一路就中難，迷者徒將萬卷看。',64,'全唐诗/poet.tang.47000.json','["修生一路就中難，迷者徒將萬卷看。", "水火均平方是藥，陰陽差互不成丹。", "守雌勿失雄方住，在黑無虧白自乾。", "認得此般真妙訣，何憂風雨妒衰殘。"]'),
('c7b6d6d2-1b43-4d2d-ab8e-3ffd17f79f97','七言 三十','呂巖','唐','唐诗','tang','','[]','纔吞一粒便安然，十二重樓九曲連。',64,'全唐诗/poet.tang.47000.json','["纔吞一粒便安然，十二重樓九曲連。", "庚虎循環餐絳雪，甲龍夭喬迸靈泉。", "三三上應三千日，九九中延九萬年。", "須得有緣方可授，未曾輕泄與人傳。"]'),
('30a57326-a31b-470b-a2b9-f08e776897c6','七言 三十一','呂巖','唐','唐诗','tang','','[]','誰知神水玉華池，中有長生性命基。',64,'全唐诗/poet.tang.47000.json','["誰知神水玉華池，中有長生性命基。", "運用須憑龍與虎，抽添全藉坎兼離。", "晨昏點盡黃金粉，頃刻修成玉石脂。", "齋戒餌之千日後，等閑輕舉上雲梯。"]'),
('849ef78f-6548-4a94-bae7-cde2121e9179','七言 三十二','呂巖','唐','唐诗','tang','','[]','九天雲淨鶴飛輕，銜簡翩翩別太清。',64,'全唐诗/poet.tang.47000.json','["九天雲淨鶴飛輕，銜簡翩翩別太清。", "身外紅塵隨意換，爐中白石立時成。", "九苞鳳向空中舞，五色雲從足下生。", "回首便歸天上去，願將甘雨救焦氓。"]'),
('66bf5f14-1a22-45e4-b794-c097c33a225c','七言 三十三','呂巖','唐','唐诗','tang','','[]','嬰兒迤邐降瑤階，手握玄珠直下來。',64,'全唐诗/poet.tang.47000.json','["嬰兒迤邐降瑤階，手握玄珠直下來。", "半夜紫雲披素質，幾回赤氣掩桃顋。", "微微笑處機關轉，拂拂行時戶牖開。", "此是吾家真一子，庸愚誰敢等閑猜。"]'),
('cf5341b9-3739-4834-a0e9-e61ecc3632fc','七言 三十四','呂巖','唐','唐诗','tang','','[]','水得天符下玉都，三千日裏積功夫。',64,'全唐诗/poet.tang.47000.json','["水得天符下玉都，三千日裏積功夫。", "禱祈天地開金鼎，收拾陰陽鎖玉壺。", "便覺凡軀能變化，深知妙道不虛圖。", "時來試問塵中叟，這箇玄機世有無。"]'),
('44a13f67-7dbf-44fa-b92f-f38b2e5c43ae','七言 三十五','呂巖','唐','唐诗','tang','','[]','誰識寰中達者人，生平解法水中銀。',64,'全唐诗/poet.tang.47000.json','["誰識寰中達者人，生平解法水中銀。", "一條拄杖撐天地，三尺昆吾斬鬼神。", "大醉醉來眠月洞，高吟吟去傲紅塵。", "自從悟裏終身後，贏得蓬壺永劫春。"]'),
('a42fe551-cfb6-44e6-bf9b-2f9a816202c2','七言 三十六','呂巖','唐','唐诗','tang','','[]','紅爐迸濺煉金英，一點靈珠透室明。',64,'全唐诗/poet.tang.47000.json','["紅爐迸濺煉金英，一點靈珠透室明。", "擺動乾坤知道力，逃移生死見功程。", "逍遙四海留蹤跡，歸去三清立姓名。", "直上五雲雲路穩，紫鸞朱鳳自來迎。"]'),
('7fcb9346-ceb3-4f45-b1b9-47f6dc8246fa','七言 三十七','呂巖','唐','唐诗','tang','','[]','時人若要學長生，先是樞機晝夜行。',64,'全唐诗/poet.tang.47000.json','["時人若要學長生，先是樞機晝夜行。", "恍惚中間專志氣，虛無裏面固元精。", "龍交虎戰三周畢，兔走烏飛九轉成。", "煉出一爐神聖藥，五雲歸去路分明。"]'),
('171e02c6-af22-4eff-8db5-e0332d998365','七言 三十八','呂巖','唐','唐诗','tang','','[]','亦無得失亦無言，動即施功靜即眠。',64,'全唐诗/poet.tang.47000.json','["亦無得失亦無言，動即施功靜即眠。", "驅遣赤牛耕宇宙，分張玉粒種山川。", "栽培不憚勞千日，服食須知活萬年。", "今日示君君好信，教君見世作神仙。"]'),
('6fae0c8e-dff1-4a37-976a-ec14f4b1a591','七言 三十九','呂巖','唐','唐诗','tang','','[]','不須兩兩與三三，秖在崑崙第一巖。',64,'全唐诗/poet.tang.47000.json','["不須兩兩與三三，秖在崑崙第一巖。", "逢潤自然情易伏，遇炎常恐性難降。", "有時直入三元戶，無事還歸九曲江。", "世上有人燒得住，壽齊天地更無雙。"]'),
('09198206-c93e-4bee-8d95-eceebb9593bb','七言 四十','呂巖','唐','唐诗','tang','','[]','本末無非在玉都，亦曾陸地作凡夫。',64,'全唐诗/poet.tang.47000.json','["本末無非在玉都，亦曾陸地作凡夫。", "吞金食氣先從有，悟理歸真便入無。", "水火自然成既濟，陰陽和合自相符。", "爐中煉出延年藥，溟渤從教變復枯。"]'),
('5bbf524c-5151-487c-a235-4c6ed455bf66','七言 四十一','呂巖','唐','唐诗','tang','','[]','無名無利任優游，遇酒逢歌且唱酬。',64,'全唐诗/poet.tang.47000.json','["無名無利任優游，遇酒逢歌且唱酬。", "數載未曾經聖闕，千年唯只在仙州。", "尋常水火三回進，真箇夫妻一處收。", "藥就功成身羽化，更拋塵坌出凡流。"]'),
('8eed8f68-baf3-4c63-b727-6bb2f581cc8e','七言 四十二','呂巖','唐','唐诗','tang','','[]','杳杳冥冥莫問涯，雕蟲篆刻道之華。',64,'全唐诗/poet.tang.47000.json','["杳杳冥冥莫問涯，雕蟲篆刻道之華。", "守中絕學方知奧，抱一無言始見佳。", "自有物如黃菊蘂，更無色似碧桃花。", "休將心地虛勞用，煮鐵燒金轉轉差。"]'),
('55565fb7-5edc-49eb-b826-c4d572a14e74','七言 四十三','呂巖','唐','唐诗','tang','','[]','還丹功滿未朝天，且向人間度有緣。',64,'全唐诗/poet.tang.47000.json','["還丹功滿未朝天，且向人間度有緣。", "拄杖兩頭擔日月，葫蘆一箇隱山川。", "詩吟自得閑中句，酒飲多遺醉後錢。", "若問我修何妙法，不離身內汞和鉛。"]'),
('852da615-3172-4929-892b-5cd0c3380c31','七言 四十四','呂巖','唐','唐诗','tang','','[]','半紅半黑道中玄，水養真金火養鉛。',64,'全唐诗/poet.tang.47000.json','["半紅半黑道中玄，水養真金火養鉛。", "解接往年三寸氣，還將運動一周天。", "烹煎盡在陰陽力，進退須憑日月權。", "只此功成三島外，穩乘鸞鳳謁諸仙。"]'),
('e9e563c2-c1e6-43e0-99c4-d4f8e37aa37b','七言 四十五','呂巖','唐','唐诗','tang','','[]','返本還元已到乾，能升能降號飛仙。',64,'全唐诗/poet.tang.47000.json','["返本還元已到乾，能升能降號飛仙。", "一陽生是興功日，九轉周爲得道年。", "煉藥但尋金裏水，安爐先立地中天。", "此中便是還丹理，不遇奇人誓莫傳。"]'),
('975d3849-0609-44f8-a29f-c6b9c7f7d5a1','七言 四十六','呂巖','唐','唐诗','tang','','[]','飛龍九五已升天，次第還當赤帝權。',64,'全唐诗/poet.tang.47000.json','["飛龍九五已升天，次第還當赤帝權。", "喜遇汞珠凝正午，幸逢鉛母結重玄。", "狂猨自伏何須煉，野馬親調不着鞭。", "煉就一丸天上藥，頓然心地永剛堅。"]'),
('250cebc9-a723-4018-b4be-fd42e133efa9','七言 四十七','呂巖','唐','唐诗','tang','','[]','舉世何人悟我家，我家別是一榮華。',64,'全唐诗/poet.tang.47000.json','["舉世何人悟我家，我家別是一榮華。", "盈箱貯積登仙錄，滿室收藏伏火砂。", "頓飲長生天上酒，常栽不死洞中花。", "凡流若問吾生計，遍地紛紛五彩霞。"]'),
('84004c43-3d31-4688-a6da-b6dd15a637b2','七言 四十八','呂巖','唐','唐诗','tang','','[]','津能充渴氣充糧，家住三清玉帝鄉。',64,'全唐诗/poet.tang.47000.json','["津能充渴氣充糧，家住三清玉帝鄉。", "金鼎煉來多外白，玉虛烹處徹中黃。", "始知青帝離宮住，方信金精水府藏。", "流俗要求玄妙理，參同契有兩三行。"]'),
('361c5ff1-87aa-465f-b4db-9217daf98380','七言 四十九','呂巖','唐','唐诗','tang','','[]','紫詔隨鸞下玉京，元君相命會三清。',64,'全唐诗/poet.tang.47000.json','["紫詔隨鸞下玉京，元君相命會三清。", "便將金鼎丹砂餌，時拂霞衣駕鶴行。", "天上雙童持珮引，月中嬌女執幡迎。", "此時功滿參真後，始信仙都有姓名。"]'),
('34451fa3-e895-4785-8b56-03843c1b3bf2','七言 五十','呂巖','唐','唐诗','tang','','[]','修修修得到乾乾，方號人間一醉仙。',64,'全唐诗/poet.tang.47000.json','["修修修得到乾乾，方號人間一醉仙。", "世上光陰催短景，洞中花木任長年。", "形飛峭壁非凡骨，神在玄宮別有天。", "唯願先生頻一顧，更玄玄外問玄玄。"]'),
('75b78105-5b2b-491e-90ab-c582e418c060','七言 一','呂巖','唐','唐诗','tang','','[]','金丹一粒定長生，須得真鉛煉甲庚。',64,'全唐诗/poet.tang.47000.json','["金丹一粒定長生，須得真鉛煉甲庚。", "火取南方赤鳳髓，水求北海黑龜精。", "鼎追四季中央合，藥遣三元八卦行。", "齋戒興功成九轉，定應入口鬼神驚。"]'),
('53c422aa-60cf-4e6c-b0a6-215819287752','七言 二','呂巖','唐','唐诗','tang','','[]','功滿來來際會難，又聞東去上仙壇。',64,'全唐诗/poet.tang.47000.json','["功滿來來際會難，又聞東去上仙壇。", "杖頭春色一壺酒，頂上雲攢五嶽冠。", "飲酒龜兒人不識，燒山符子鬼難看。", "先生去後身須老，乞與貧儒換骨丹。"]'),
('30df7a37-f0e3-4aff-b0c1-7c597353bbc4','七言 三','呂巖','唐','唐诗','tang','','[]','碧潭深處一真人，貌似桃花體似銀。',64,'全唐诗/poet.tang.47000.json','["碧潭深處一真人，貌似桃花體似銀。", "鬢髮未斑緣有術，紅顏不老爲通神。", "蓬萊要去如今去，架上黃衣化作雲。", "任彼桑田變滄海，一丸丹藥定千春。"]'),
('eb604590-292d-4f18-b410-ac7e4a59faaa','七言 四','呂巖','唐','唐诗','tang','','[]','爐養丹砂鬢不斑，假將名利住人間。',64,'全唐诗/poet.tang.47000.json','["爐養丹砂鬢不斑，假將名利住人間。", "已逢志士傳神藥，又喜同流動笑顏。", "老子道經分付得，少微星許共相攀。", "幸蒙上士甘撈摝，處世輸君一箇閑。"]'),
('7fcf0f86-c05f-436c-af0d-5244a0718c29','七言 五','呂巖','唐','唐诗','tang','','[]','誰解長生似我哉，煉成真氣在三台。',64,'全唐诗/poet.tang.47000.json','["誰解長生似我哉，煉成真氣在三台。", "盡知白日昇天去，剛逐紅塵下世來。", "黑虎行時傾雨露，赤龍耕處產瓊瑰。", "只吞一粒金丹藥，飛入青霄更不回。"]'),
('2ad99d88-cd3c-45eb-a142-f1cad0d3abe4','七言 六','呂巖','唐','唐诗','tang','','[]','亂雲堆裏表星都，認得深藏大丈夫。',64,'全唐诗/poet.tang.47000.json','["亂雲堆裏表星都，認得深藏大丈夫。", "綠酒醉眠閑日月，白蘋風定釣江湖。", "長將氣度隨天道，不把言詞問世徒。", "山水路遙人不到，茅君消息近知無。"]'),
('090618be-ceee-488b-9d88-35e74112b482','七言 七','呂巖','唐','唐诗','tang','','[]','鶴爲車駕酒爲糧，爲戀長生不死鄉。',64,'全唐诗/poet.tang.47000.json','["鶴爲車駕酒爲糧，爲戀長生不死鄉。", "地脉尚能縮得短，人年豈不展教長。", "星辰往往壺中見，日月時時衲裏藏。", "若欲時流親得見，朝朝不離水銀行。"]'),
('693a6c14-336f-440e-beae-c2c41c72bbc8','七言 八','呂巖','唐','唐诗','tang','','[]','靈芝無種亦無根，解飲能餐自返魂。',64,'全唐诗/poet.tang.47000.json','["靈芝無種亦無根，解飲能餐自返魂。", "但得煙霞供歲月，任他烏兔走乾坤。", "嬰兒只戀陽中母，姹女須朝頂上尊。", "一得不回千古內，更無塚墓示兒孫。"]'),
('04e192b0-074d-449f-af11-cd0bf3c26c2c','七言 九','呂巖','唐','唐诗','tang','','[]','世上何人會此言，休將名利挂心田。',64,'全唐诗/poet.tang.47000.json','["世上何人會此言，休將名利挂心田。", "等閑倒盡十分酒，遇興高吟一百篇。", "物外煙霞爲伴侶，壺中日月任嬋娟。", "他時功滿歸何處，直駕雲車入洞天。"]'),
('34ac05e3-fe5b-4505-895a-3c9681d74a00','七言 十','呂巖','唐','唐诗','tang','','[]','玄門帝子坐中央，得算明長感玉皇。',64,'全唐诗/poet.tang.47000.json','["玄門帝子坐中央，得算明長感玉皇。", "枕上山河和雨露，笛中日月混瀟湘。", "坎男會遇逢金女，離女交騰嫁木郎。", "真箇夫妻齊守志，立教牽惹在陰陽。"]'),
('5738735e-c6ed-4818-b7ea-935a3e688988','七言 十一','呂巖','唐','唐诗','tang','','[]','遙指高峰笑一聲，紅霞紫霧面前生。',64,'全唐诗/poet.tang.47000.json','["遙指高峰笑一聲，紅霞紫霧面前生。", "每於廛市無人識，長到山中有鶴行。", "時弄玉蟾驅鬼魅，夜煎金鼎煮瓊英。", "他時若赴蓬萊洞，知我仙家有姓名。"]'),
('d2bbee1e-1acd-4655-a30d-a027f8304349','七言 十二','呂巖','唐','唐诗','tang','','[]','堪笑時人問我家，杖擔雲物惹煙霞。',64,'全唐诗/poet.tang.47000.json','["堪笑時人問我家，杖擔雲物惹煙霞。", "眉藏火電非他說，手種金蓮不自誇。", "三尺焦桐爲活計，一壺美酒是生涯。", "騎龍遠出遊三島，夜久無人翫月華。"]'),
('d56dc9b8-3c26-4a30-8d81-f087050c3fa2','七言 十三','呂巖','唐','唐诗','tang','','[]','九曲江邊坐臥看，一條長路入天端。',64,'全唐诗/poet.tang.47000.json','["九曲江邊坐臥看，一條長路入天端。", "慶雲捧擁朝丹闕，瑞氣裴回起白煙。", "鉛汞此時爲至藥，坎離今日結神丹。", "功能濟命長無老，只在人心不是難。"]'),
('4e0e6d77-03b8-486a-ba3b-9a59548f80bf','七言 十四','呂巖','唐','唐诗','tang','','[]','玄門玄理又玄玄，不死根元在汞鉛。',64,'全唐诗/poet.tang.47000.json','["玄門玄理又玄玄，不死根元在汞鉛。", "知是一般真箇術，調和六一也同天。", "玉京山上羊兒鬧，金水河中石虎眠。", "妙要能生覺本體，勤心到處自如然。"]'),
('d3240f5e-a6f2-437a-8b76-5d65dd9915dc','七言 十五','呂巖','唐','唐诗','tang','','[]','公卿雖貴不曾酬，說著仙鄉便去遊。',64,'全唐诗/poet.tang.47000.json','["公卿雖貴不曾酬，說著仙鄉便去遊。", "爲討石肝逢蜃海，因尋甜雪過瀛州。", "山川醉後壺中放，神鬼閑來匣裏收。", "據見目前無箇識，不如杯酒混凡流。"]'),
('75a3ad1e-1882-41c1-a190-397fa37e28fc','七言 十六','呂巖','唐','唐诗','tang','','[]','曾邀相訪到仙家，忽上崑崙宴月華。',64,'全唐诗/poet.tang.47000.json','["曾邀相訪到仙家，忽上崑崙宴月華。", "玉女控攏蒼獬豸，山童提挈白蝦蟇。", "時斟海內千年酒，慣摘壺中四序花。", "今在人寰人不識，看看揮袖入煙霞。"]'),
('c2d903fd-1ab9-4a78-b480-9ecd4050c148','七言 十七','呂巖','唐','唐诗','tang','','[]','火種丹田金自生，重重樓閣自分明。',64,'全唐诗/poet.tang.47000.json','["火種丹田金自生，重重樓閣自分明。", "三千功行百旬見，萬里蓬萊一日程。", "羽化自應無鬼錄，玉都長是有仙名。", "今朝得赴瑤池會，九節幢幡洞裏迎。"]'),
('e26288a6-9c90-4c03-95a8-f12583554854','七言 十八','呂巖','唐','唐诗','tang','','[]','因看崔公入藥鏡，令人心地轉分明。',64,'全唐诗/poet.tang.47000.json','["因看崔公入藥鏡，令人心地轉分明。", "陽龍言向離宮出，陰虎還於坎位生。", "二物會時爲道本，五方行盡得丹名。", "修真道士如知此，定跨赤龍歸玉清。"]'),
('0de46be4-2704-4015-9fe7-62dbc78b5569','七言 十九','呂巖','唐','唐诗','tang','','[]','浮生不實爲輕忽，衲服深藏奇異骨。',64,'全唐诗/poet.tang.47000.json','["浮生不實爲輕忽，衲服深藏奇異骨。", "非是塵中不染塵，焉得物外通無物。", "共語難兮情兀兀，獨自行時輕拂拂。", "一點刀圭五彩生，飛丹走入神仙窟。"]'),
('39e11215-787b-4a4c-b25b-29ff7ecb8eb4','七言 二十','呂巖','唐','唐诗','tang','','[]','莫怪愛吟天上詩，蓋緣吟得世間稀。',64,'全唐诗/poet.tang.47000.json','["莫怪愛吟天上詩，蓋緣吟得世間稀。", "慣餐玉帝宮中飯，曾著蓬萊洞裏衣。", "馬踏日輪紅露捲，鳳銜月角擘雲飛。", "何時再控青絲轡，又掉金鞭入紫微。"]'),
('feae9d70-d81d-4bb7-9f5f-47c4a88b993b','七言 二十一','呂巖','唐','唐诗','tang','','[]','黃芽白雪兩飛金，行即高歌醉即吟。',64,'全唐诗/poet.tang.47000.json','["黃芽白雪兩飛金，行即高歌醉即吟。", "日月暗扶君甲子，乾坤自與我知音。", "精靈滅跡三清劍，風雨騰空一弄琴。", "的當南遊歸甚處，莫交鶴去上天尋。"]'),
('888938ce-d63c-4a7b-a06c-b97aac81b194','七言 二十二','呂巖','唐','唐诗','tang','','[]','雲鬢雙明骨更輕，自言尋鶴到蓬瀛。',64,'全唐诗/poet.tang.47000.json','["雲鬢雙明骨更輕，自言尋鶴到蓬瀛。", "日論藥草皆知味，問著神仙自得名。", "簪冷夜龍穿碧洞，枕寒晨虎臥銀城。", "來春又擬攜筇去，爲憶軒轅海上行。"]'),
('94566261-dd84-4388-a853-dc69df876a15','七言 二十三','呂巖','唐','唐诗','tang','','[]','龍精龜眼兩相和，丈六男兒不奈何。',64,'全唐诗/poet.tang.47000.json','["龍精龜眼兩相和，丈六男兒不奈何。", "九盞水中煎赤子，一輪火內養黃婆。", "月圓自覺離天網，功滿方知出地羅。", "半醉好吞龍鳳髓，勸君休更認彌陀。"]'),
('53f97c14-ebf7-4345-bf3e-0d7170bccc1a','七言 二十四','呂巖','唐','唐诗','tang','','[]','強居此境絕知音，野景雖多不合吟。',64,'全唐诗/poet.tang.47000.json','["強居此境絕知音，野景雖多不合吟。", "詩句若喧卿相口，姓名還動帝王心。", "道袍薜帶應慵挂，隱帽皮冠尚懶簪。", "除此更無餘箇事，一壺村酒一張琴。"]'),
('cb1d05d7-59be-4335-9d24-2406998b7f5e','七言 二十五','呂巖','唐','唐诗','tang','','[]','華陽山裏多芝田，華陽山叟復延年。',64,'全唐诗/poet.tang.47000.json','["華陽山裏多芝田，華陽山叟復延年。", "青松巖畔攀高幹，白雲堆裏飲飛泉。", "不寒不熱神蕩蕩，東來西去氣綿綿。", "三千功滿好歸去，休與時人說洞天。"]'),
('34f8a6c4-42ae-4212-a5aa-6a8196005b63','七言 二十六','呂巖','唐','唐诗','tang','','[]','天生不散自然心，成敗從來古與今。',64,'全唐诗/poet.tang.47000.json','["天生不散自然心，成敗從來古與今。", "得路應知能出世，迷途終是任埋沈。", "身邊至藥堪攻煉，物外丹砂且細尋。", "咫尺洞房仙景在，莫隨波浪沒光陰。"]'),
('cad77054-667e-4c16-96f6-a871bf6917ed','七言 二十七','呂巖','唐','唐诗','tang','','[]','自隱玄都不記春，幾回滄海變成塵。',64,'全唐诗/poet.tang.47000.json','["自隱玄都不記春，幾回滄海變成塵。", "玉京殿裏朝元始，金闕宮中拜老君。", "悶即駕乘千歲鶴，閑來高臥九重雲。", "我今學得長生法，未肯輕傳與世人。"]'),
('4f6a47c7-bfde-4491-a162-262015dc36d7','七言 二十八','呂巖','唐','唐诗','tang','','[]','北帝南辰掌內觀，潛通造化暗相傳。',64,'全唐诗/poet.tang.47000.json','["北帝南辰掌內觀，潛通造化暗相傳。", "金槌袖裏居元宅，玉戶星宮降上玄。", "舉世盡皆尋此道，誰人空裏得玄關。", "明明道在堪消息，日月灘頭去又還。"]'),
('47925956-2a65-48ea-88ef-c3fab4f687d4','七言 二十九','呂巖','唐','唐诗','tang','','[]','日影元中合自然，奔雷走電入中原。',64,'全唐诗/poet.tang.47000.json','["日影元中合自然，奔雷走電入中原。", "長驅赤馬居東殿，大啓朱門泛碧泉。", "怒拔昆吾歌聖化，喜陪孤月賀新年。", "方知此是生生物，得在仁人始受傳。"]'),
('5eff325c-3287-42c6-b1db-d20378f5d0ea','七言 三十','呂巖','唐','唐诗','tang','','[]','六龍齊駕得昇乾，須覺潛通造化權。',64,'全唐诗/poet.tang.47000.json','["六龍齊駕得昇乾，須覺潛通造化權。", "真道每吟秋月澹，至言長運碧波寒。", "晝乘白虎遊三島，夜頂金冠立古壇。", "一載已成千歲藥，誰人將袖染塵寰。"]'),
('775780da-f62e-4597-9904-45870207a2b1','七言 三十一','呂巖','唐','唐诗','tang','','[]','五岳灘頭景象新，仁人方達杳冥身。',64,'全唐诗/poet.tang.47000.json','["五岳灘頭景象新，仁人方達杳冥身。", "天綱運轉三元淨，地脈通來萬物生。", "自曉谷神通此道，誰將理性欲修真。", "明明說向中黃路，霹靂聲中自得神。"]'),
('0a53d12a-1020-4abf-851c-45a676b7912f','七言 三十二','呂巖','唐','唐诗','tang','','[]','欲陪仙侶得身輕，飛過蓬萊徹上清。',64,'全唐诗/poet.tang.47000.json','["欲陪仙侶得身輕，飛過蓬萊徹上清。", "朱頂鶴來雲外接，紫鱗魚向海中迎。", "姮娥月桂花先吐，王母仙桃子漸成。", "下瞰日輪天欲曉，定知人世久長生。"]'),
('13ba0c55-c67a-4a9c-989b-782bc8c0265a','七言 三十三','呂巖','唐','唐诗','tang','','[]','四海皆忙幾箇閑，時人口內說塵緣。',64,'全唐诗/poet.tang.47000.json','["四海皆忙幾箇閑，時人口內說塵緣。", "知君有道來山上，何似無名住世間。", "十二樓臺藏秘訣，五千言內隱玄關。", "方知鼎貯神仙藥，乞取刀圭一粒看。"]'),
('695b7657-e964-4392-9849-0955d1d235a0','七言 三十四','呂巖','唐','唐诗','tang','','[]','割斷繁華掉却榮，便從初得是長生。',64,'全唐诗/poet.tang.47000.json','["割斷繁華掉却榮，便從初得是長生。", "曾於錦水爲蟬蛻，又向蓬萊別姓名。", "三住住來無否泰，一塵塵在世人情。", "不知功滿歸何處，直跨虬龍上玉京。"]'),
('2dfb5f4b-ae7c-403b-ae06-26cbe3ca6ea4','七言 三十五','呂巖','唐','唐诗','tang','','[]','當年詩價滿皇都，掉臂西歸是丈夫。',64,'全唐诗/poet.tang.47000.json','["當年詩價滿皇都，掉臂西歸是丈夫。", "萬頃白雲獨自有，一枝丹桂阿誰無。", "閑尋渭曲漁翁引，醉上蓮峰道士扶。", "他日與君重際會，竹溪茅舍夜相呼。"]'),
('935b0ad4-205f-4a4f-a7ed-6adcf5aa9ddd','七言 三十六','呂巖','唐','唐诗','tang','','[]','金鎚灼灼舞天階，獨自騎龍去又來。',64,'全唐诗/poet.tang.47000.json','["金鎚灼灼舞天階，獨自騎龍去又來。", "高臥白雲觀日窟，閑眠秋月擘天開。", "離花片片乾坤產，坎蘂翻翻造化栽。", "晚醉九巖回首望，北邙山下骨皚皚。"]'),
('23e1a280-20c9-42fd-9b09-559f4842f2c7','七言 三十七','呂巖','唐','唐诗','tang','','[]','結交常與道情深，日日隨他出又沈。',64,'全唐诗/poet.tang.47000.json','["結交常與道情深，日日隨他出又沈。", "若要自通雲外鶴，直須勤煉水中金。", "丹成只恐乾坤窄，餌了寧憂疾患侵。", "未去瑤臺猶混世，不妨杯酒喜閑吟。"]'),
('346c75a6-feae-4679-b6e7-5137568c074e','七言 三十八','呂巖','唐','唐诗','tang','','[]','因攜琴劍下煙蘿，何幸今朝喜暫過。',64,'全唐诗/poet.tang.47000.json','["因攜琴劍下煙蘿，何幸今朝喜暫過。", "貌相本來猶自可，針醫偏更効無多。", "仙經已讀三千卷，古法曾持十二科。", "些小道功如不信，金堦捨手試看麽。"]'),
('840c9e5c-285c-4f2f-8819-55d1ff28fca1','七言 三十九','呂巖','唐','唐诗','tang','','[]','傾側華陽醉再三，騎[龍]遇晚下南巖。',66,'全唐诗/poet.tang.47000.json','["傾側華陽醉再三，騎[龍]遇晚下南巖。", "眉因拍劍留星電，衣爲眠雲惹碧嵐。", "金液變來成雨露，玉都歸去老松杉。", "曾將鐵鏡照神鬼，霹靂搜尋火滿潭。"]'),
('4ee5be2c-2069-4cf3-bcc1-3d087798f721','七言 四十','呂巖','唐','唐诗','tang','','[]','鐵鏡烹金火滿空，碧潭龍臥夕陽中。',64,'全唐诗/poet.tang.47000.json','["鐵鏡烹金火滿空，碧潭龍臥夕陽中。", "麒麟意合乾坤地，獬豸機關日月東。", "三尺劍橫雙水岸，五丁冠頂百神宮。", "閑鋪羽服居仙窟，自著金蓮造化功。"]'),
('cbb2ae88-c39b-49bd-9cee-23734e5fa7a2','七言 四十一','呂巖','唐','唐诗','tang','','[]','隨緣信業任浮沈，似水如雲一片心。',64,'全唐诗/poet.tang.47000.json','["隨緣信業任浮沈，似水如雲一片心。", "兩卷道經三尺劍，一條藜杖七弦琴。", "壺中有藥逢人施，腹內新詩遇客吟。", "一嚼永添千載壽，一丸丹點一斤金。"]'),
('40a6e270-49cb-4274-b56f-5d0f91410a09','七言 四十二','呂巖','唐','唐诗','tang','','[]','琴劍酒碁龍鶴虎，逍遙落托永無憂。',64,'全唐诗/poet.tang.47000.json','["琴劍酒碁龍鶴虎，逍遙落托永無憂。", "閑騎白鹿遊三島，悶駕青牛看十洲。", "碧洞遠觀明月上，青山高隱綵雲流。", "時人若要還如此，名利浮華即便休。"]'),
('827b37f1-2001-45a8-9c16-7676b3e77d8f','七言 四十三','呂巖','唐','唐诗','tang','','[]','紫極宮中我自知，親磨神劍劍還飛。',64,'全唐诗/poet.tang.47000.json','["紫極宮中我自知，親磨神劍劍還飛。", "先差玉子開南殿，後遣青龍入紫微。", "九鼎黃芽棲瑞鳳，一軀仙骨養靈芝。", "蓬萊不是凡人處，只怕愚人泄世機。"]'),
('bba2f35f-46aa-424e-8920-2054664c3fa0','七言 四十四','呂巖','唐','唐诗','tang','','[]','向身方始出埃塵，造化功夫只在人。',64,'全唐诗/poet.tang.47000.json','["向身方始出埃塵，造化功夫只在人。", "早使亢龍拋地網，豈知白虎出天真。", "綿綿有路誰留我，默默忘言自合神。", "擊劍夜深歸甚處，披星帶月折麒麟。"]'),
('6f76aa2e-94f9-4973-9322-086103d820d6','七言 四十五','呂巖','唐','唐诗','tang','','[]','春盡閑閑過落花，一回舞劍一吁嗟。',64,'全唐诗/poet.tang.47000.json','["春盡閑閑過落花，一回舞劍一吁嗟。", "常憂白日光陰促，每恨青天道路賒。", "本志不求名與利，元心只慕水兼霞。", "世間萬種浮沈事，達理誰能似我家。"]'),
('900e758e-18e6-416a-b333-256d87c6ba48','七言 四十六','呂巖','唐','唐诗','tang','','[]','日爲和解月呼丹，華夏諸侯肉眼看。',64,'全唐诗/poet.tang.47000.json','["日爲和解月呼丹，華夏諸侯肉眼看。", "仁義異如胡越異，世情難似泰衡難。", "八仙煉後鍾神異，四海磨成照膽寒。", "笑指不平千萬萬，騎龍撫劍九重關。"]'),
('8dc62ca2-1f57-4203-941a-ed872bc8fe96','七言 四十七','呂巖','唐','唐诗','tang','','[]','別來洛汭六東風，醉眼吟情慵不慵。',64,'全唐诗/poet.tang.47000.json','["別來洛汭六東風，醉眼吟情慵不慵。", "擺撼乾坤金劍吼，烹煎日月玉爐紅。", "杖搖楚甸三千里，鶴翥秦煙幾萬重。", "爲報晉成仙子道，再期春色會稽峰。"]'),
('93ee7b7c-1d19-43e9-8d8e-5693880a8357','七言 四十八','呂巖','唐','唐诗','tang','','[]','髮頭滴血眼如鐶，吐氣雲生怒世間。',64,'全唐诗/poet.tang.47000.json','["髮頭滴血眼如鐶，吐氣雲生怒世間。", "爭耐不平千古事，須期一訣蕩兇頑。", "蛟龍斬處翻滄海，暴虎除時拔遠山。", "爲滅世情兼負義，劍光腥染點痕斑。"]'),
('6b2dd721-41eb-438f-8bd9-82b6093e4f39','七言 四十九','呂巖','唐','唐诗','tang','','[]','雨雪霏霏天已暮，金鍾滿勸撫焦桐。',64,'全唐诗/poet.tang.47000.json','["雨雪霏霏天已暮，金鍾滿勸撫焦桐。", "詩吟席上未移刻，劍舞筵前疾似風。", "何事行杯當午夜，忽然怒目便騰空。", "不知誰是虧忠孝，攜箇人頭入坐中。"]'),
('4abbaeef-6949-40c6-aafe-ff4a1eba0acb','七言 五十','呂巖','唐','唐诗','tang','','[]','未煉還丹且煉心，丹成方覺道元深。',64,'全唐诗/poet.tang.47000.json','["未煉還丹且煉心，丹成方覺道元深。", "每留客有錢酤酒，誰信君無藥點金。", "洞裏風雷歸掌握，壺中日月在胸襟。", "神仙事業人難會，養性長生自意吟。"]'),
('a4667adf-b79e-48d0-b7f4-bbbeba682a68','七言 五十一','呂巖','唐','唐诗','tang','','[]','鐵牛耕地種金錢，刻石時童把貫穿。',64,'全唐诗/poet.tang.47000.json','["鐵牛耕地種金錢，刻石時童把貫穿。", "一粒粟中藏世界，二升鐺內煮山川。", "白頭老子眉垂地，碧眼胡兒手指天。", "若向此中玄會得，此玄玄外更無玄。"]'),
('e73fbc5a-9488-463b-a38f-7dd6960eac8d','七言 五十二','呂巖','唐','唐诗','tang','','[]','箕星昴宿下長天，凡景寧教不愕然。',64,'全唐诗/poet.tang.47000.json','["箕星昴宿下長天，凡景寧教不愕然。", "龍出水來鱗甲就，鶴沖天氣羽毛全。", "塵中教化千人眼，世上人知爾雅篇。", "自是凡流福命薄，忍教微妙略輕傳。"]'),
('0dae3e32-3b0f-43a4-a1cc-337db465ac18','七言 五十三','呂巖','唐','唐诗','tang','','[]','閑來掉臂入天門，拂袂徐徐撮綵雲。',64,'全唐诗/poet.tang.47000.json','["閑來掉臂入天門，拂袂徐徐撮綵雲。", "無語下窺黃谷子，破顏平揖紫霞君。", "擬登瑤殿參金母，回訪瀛洲看日輪。", "恰值嫦娥排宴會，瑤漿新熟味氤氳。"]'),
('50516b0c-630d-480d-a178-4b24826628d0','七言 五十四','呂巖','唐','唐诗','tang','','[]','曾隨劉阮醉桃源，未省人間欠酒錢。',64,'全唐诗/poet.tang.47000.json','["曾隨劉阮醉桃源，未省人間欠酒錢。", "一領布裘權且當，九天回日却歸還。", "鳳茸襖子非爲貴，狐白裘裳欲比難。", "只此世間無價寶，不憑火裏試燒看。"]'),
('c5d34cf1-9811-4a27-bfba-89da080dc3d0','七言 五十五','呂巖','唐','唐诗','tang','','[]','因思往事却成憨，曾讀仙經第十三。',64,'全唐诗/poet.tang.47000.json','["因思往事却成憨，曾讀仙經第十三。", "武氏死時應室女，陳王沒後是童男。", "兩輪日月從他載，九箇山河一擔擔。", "盡日無人話消息，一壺春酒且醺酣。"]'),
('18a6e6fc-9b1b-4eb8-8d7c-9115e4c27c71','七言 五十六','呂巖','唐','唐诗','tang','','[]','垂袖騰騰傲世塵，葫蘆攜却數遊巡。',64,'全唐诗/poet.tang.47000.json','["垂袖騰騰傲世塵，葫蘆攜却數遊巡。", "利名身外終非道，龍虎門前辨取真。", "一覺夢魂朝紫府，數年蹤跡隱埃塵。", "華陰市內纔相見，不是尋常賣藥人。"]'),
('2aba50c4-315a-4928-8eaa-5f8aed25e79c','七言 五十七','呂巖','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','萬卷仙經三尺琴，劉安聞說是知音。',64,'全唐诗/poet.tang.47000.json','["萬卷仙經三尺琴，劉安聞說是知音。", "杖頭春色一壺酒，爐內丹砂萬點金。", "悶裏醉眠三路口，閑來遊釣洞庭心。", "相逢相遇人誰識，只恐沖天沒處尋。"]'),
('b0b0c36a-8e7a-4fb2-9d73-25eaca6d9c5f','七言 五十八','呂巖','唐','唐诗','tang','','[]','曾戰蚩尤玉座前，六龍高駕振鳴鑾。',64,'全唐诗/poet.tang.47000.json','["曾戰蚩尤玉座前，六龍高駕振鳴鑾。", "如來車後隨金鼓，黃帝旂傍戴鐵冠。", "醉捋黑鬚三島黯，怒抽霜劍十洲寒。", "軒轅世代橫行後，直隱深巖久覓難。"]'),
('2d1d802c-5440-46bc-8c55-e7c8f241d449','七言 五十九','呂巖','唐','唐诗','tang','','[]','頭角蒼浪聲似鐘，貌如冰雪骨如松。',64,'全唐诗/poet.tang.47000.json','["頭角蒼浪聲似鐘，貌如冰雪骨如松。", "匣中寶劍時頻吼，袖裏金鎚逞露風。", "會飲酒時爲伴侶，能行詩句便參同。", "來年定赴蓬萊會，騎箇生獰九色龍。"]'),
('b61eab38-e516-4c43-bbf9-4e5234309ebb','七言 六十','呂巖','唐','唐诗','tang','','[]','神仙暮入黃金闕，將相門關白玉京。',64,'全唐诗/poet.tang.47000.json','["神仙暮入黃金闕，將相門關白玉京。", "可是洞中無好景，爲憐天下有衆生。", "心琴際會閑隨鶴，匣劍時磨待斷鯨。", "進退兩楹俱未應，憑君與我指前程。"]'),
('310b6023-ff08-4fb1-9eec-79c8a8b1ff10','七言 六十一','呂巖','唐','唐诗','tang','','[]','九鼎烹煎一味砂，自然火候放童花。',64,'全唐诗/poet.tang.47000.json','["九鼎烹煎一味砂，自然火候放童花。", "星辰照出青蓮顆，日月能藏白馬牙。", "七返返成生碧霧，九還還就吐紅霞。", "有人奪得玄珠餌，三島途中路不賒。"]'),
('0c4ae8eb-218f-48fd-a6ad-8510d43d91e4','七言 六十二','呂巖','唐','唐诗','tang','','[]','天生一物變三才，交感陰陽結聖胎。',64,'全唐诗/poet.tang.47000.json','["天生一物變三才，交感陰陽結聖胎。", "龍虎順行陰鬼去，龜蛇逆往火龍來。", "嬰兒日喫黃婆髓，姹女時餐白玉杯。", "功滿自然居物外，人間寒署任輪回。"]'),
('8d030a2b-2ecb-418e-8694-104132fd4215','七言 六十三','呂巖','唐','唐诗','tang','','[]','星辰聚會入離鄉，日月盈虧助藥王。',64,'全唐诗/poet.tang.47000.json','["星辰聚會入離鄉，日月盈虧助藥王。", "三候火燒金鼎寶，五符水煉玉壺漿。", "乾坤反覆龍收霧，卯酉相吞虎放光。", "入室用機擒捉取，一丸丹點體純陽。"]'),
('8058a9a3-bbbb-4154-8387-c51a621ef895','真人行巴陵市太守怒其不避使案吏具其罪真人曰須酒醒耳頃忽失之但留詩曰','呂巖','唐','唐诗','tang','','[]','暫別蓬萊海上遊，偶逢太守問根由。',64,'全唐诗/poet.tang.47000.json','["暫別蓬萊海上遊，偶逢太守問根由。", "身居北斗星杓下，劍挂南宮月角頭。", "道我醉來真箇醉，不知愁是怎生愁。", "相逢何事不相認，却駕白雲歸去休。"]'),
('6cacf356-a783-4bf6-b22f-7de4923aa03b','仙樂侑席','呂巖','唐','唐诗','tang','','[]','曾經天上三千劫，又在人間五百年。',64,'全唐诗/poet.tang.47000.json','["曾經天上三千劫，又在人間五百年。", "腰下劍鋒橫紫電，爐中丹焰起蒼煙。", "纔騎白鹿過蒼海，復跨青牛入洞天。", "小技等閑聊戲爾，無人知我是真仙。"]'),
('55d97bbc-9489-4822-b1de-b423ff62191b','題桐柏山黃先生庵門','呂巖','唐','唐诗','tang','','[]','吾有玄中極玄語，周遊八極無處吐。',294,'全唐诗/poet.tang.47000.json','["吾有玄中極玄語，周遊八極無處吐。", "雲軿飄泛到凝陽，一見君兮在玄浦。", "知君本是孤雲客，擬話希夷生恍惚。", "無爲大道本根源，要君親見求真物。", "其中有一分三五，本自無名號丹母。", "寒泉瀝瀝氣綿綿，上透崑崙還紫府。", "浮沈升降入中宮，四象五行齊見土。", "驅青龍，擒白虎，起祥風兮下甘露。", "鉛凝真汞結丹砂，一派火輪真爲主。", "既修真，須堅確，能轉乾坤泛海岳。", "運行天地莫能知，變化鬼神應不覺。", "千朝煉就紫金身，乃致全神歸返朴。", "黃秀才，黃秀才，既修真，須且早，人間萬事何時了。", "貪名貪利愛金多，爲他財色身衰老。", "我今勸子心悲切，君自思兮生猛烈。", "莫教大限到身來，又是隨流入生滅。", "留此片言，用表其意。", "他日相逢，必與汝決。", "莫退初心，善愛善愛。"]'),
('6337d58a-291c-4be1-a36a-8318341871ef','五言 一','呂巖','唐','唐诗','tang','','[]','悟了長生理，秋蓮處處開。',48,'全唐诗/poet.tang.47000.json','["悟了長生理，秋蓮處處開。", "金童登錦帳，玉女下香階。", "虎嘯天魂住，龍吟地魄來。", "有人明此道，立使返嬰孩。"]'),
('a668c670-aef9-49c6-876d-f957b0ec9341','五言 二','呂巖','唐','唐诗','tang','','[]','姹女住南方，身邊產太陽。',48,'全唐诗/poet.tang.47000.json','["姹女住南方，身邊產太陽。", "蟾宮烹玉液，坎戶煉瓊漿。", "過去神仙餌，今來到我嘗。", "一杯延萬紀，物外任翺翔。"]'),
('76af9e23-544c-4d7c-87d2-ef3d3b852268','五言 三','呂巖','唐','唐诗','tang','','[]','頓悟黃芽理，陰陽稟自然。',50,'全唐诗/poet.tang.47000.json','["頓悟黃芽理，陰陽稟自然。", "乾坤爐裏煉，日月鼎中煎。", "木產長生汞，金[烹]續命鉛。", "世人明此道，立便返童顏。"]'),
('ed0fd4ad-a7aa-4042-a99b-cdf128d472c0','五言 四','呂巖','唐','唐诗','tang','','[]','宇宙產黃芽，經爐煅作砂。',48,'全唐诗/poet.tang.47000.json','["宇宙產黃芽，經爐煅作砂。", "陰陽烹五彩，水火煉三花。", "鼎內龍降虎，壺中龜遣蛇。", "功成歸物外，自在樂煙霞。"]'),
('df3ad5ee-0a96-4a0e-90f4-e42745132837','五言 五','呂巖','唐','唐诗','tang','','[]','要覓長生路，除非認本元。',48,'全唐诗/poet.tang.47000.json','["要覓長生路，除非認本元。", "都來一味藥，剛道數千般。", "丹鼎烹成汞，爐中煉就鉛。", "依時服一粒，白日上冲天。"]'),
('d9bcea21-8fa9-4261-a7ea-9e7682a48596','五言 六','呂巖','唐','唐诗','tang','','[]','姹女住瑤臺，仙花滿地開。',48,'全唐诗/poet.tang.47000.json','["姹女住瑤臺，仙花滿地開。", "金苗從此出，玉蘂自天來。", "鳳舞長生曲，鸞歌續命杯。", "有人明此道，海變已千回。"]'),
('150477b6-37c2-4294-bbe3-c5e3fdecd178','五言 七','呂巖','唐','唐诗','tang','','[]','古往諸仙子，根元占甲庚。',48,'全唐诗/poet.tang.47000.json','["古往諸仙子，根元占甲庚。", "水中聞虎嘯，火裏見龍行。", "進退窮三候，相吞用八紘。", "沖天功行滿，寒暑不能爭。"]'),
('5320b510-0dcb-472e-aee5-bb0ea94d68c7','五言 八','呂巖','唐','唐诗','tang','','[]','我悟長生理，太陽伏太陰。',48,'全唐诗/poet.tang.47000.json','["我悟長生理，太陽伏太陰。", "離宮生白玉，坎戶產黃金。", "要主君臣義，須存子母心。", "九重神室內，虎嘯與龍吟。"]'),
('a7439510-f25d-4cfe-8fb1-43ca04fd0fe4','五言 九','呂巖','唐','唐诗','tang','','[]','靈丹產太虛，九轉入重爐。',48,'全唐诗/poet.tang.47000.json','["靈丹產太虛，九轉入重爐。", "浴就紅蓮顆，燒成白玉珠。", "水中鉛一兩，火內汞三銖。", "喫了瑤臺寶，升天任海枯。"]'),
('b67d7ab8-475f-464c-af96-f7b9b0f18a49','五言 十','呂巖','唐','唐诗','tang','','[]','姹女住離宮，身邊產雌雄。',48,'全唐诗/poet.tang.47000.json','["姹女住離宮，身邊產雌雄。", "爐中七返畢，鼎內九還終。", "悟了魚投水，迷因鳥在籠。", "耄年服一粒，立地變沖童。"]'),
('4b8438f8-6955-4d12-b06f-d31ad8537cf0','五言 十一','呂巖','唐','唐诗','tang','','[]','盜得乾坤祖，陰陽是本宗。',48,'全唐诗/poet.tang.47000.json','["盜得乾坤祖，陰陽是本宗。", "天魂生白虎，地魄產青龍。", "運寶泥丸在，搬精入上宮。", "有人明此法，萬載貌如童。"]'),
('bfc79d6b-9ad1-4e55-a117-43810b46a1de','五言 十二','呂巖','唐','唐诗','tang','','[]','要覓金丹理，根元不易逢。',48,'全唐诗/poet.tang.47000.json','["要覓金丹理，根元不易逢。", "三才七返足，四象九還終。", "浴就微微白，燒成漸漸紅。", "一丸延萬紀，物外去沖沖。"]'),
('9e56e1b9-4222-411e-bbc3-4c12b3bf8dc3','五言 十三','呂巖','唐','唐诗','tang','','[]','箇箇覓長生，根元不易尋。',48,'全唐诗/poet.tang.47000.json','["箇箇覓長生，根元不易尋。", "要貪天上寶，須去世間琛。", "煉就水中火，燒成陽內陰。", "祖師親有語，一味水中金。"]'),
('d9373786-9726-41ca-a73b-a9b1df3be4a8','五言 十四','呂巖','唐','唐诗','tang','','[]','萬物皆生土，如人得本元。',48,'全唐诗/poet.tang.47000.json','["萬物皆生土，如人得本元。", "青龍精是汞，白虎水爲鉛。", "悟者子投母，迷應地是天。", "將來物外客，箇箇補丹田。"]'),
('ff1110f3-f23c-48c7-85f0-b279de71221d','五言 十五','呂巖','唐','唐诗','tang','','[]','二十四神清，三千功行成。',48,'全唐诗/poet.tang.47000.json','["二十四神清，三千功行成。", "寒雲連地轉，聖日滿天明。", "玉子偏宜種，金田豈在耕。", "此中真妙理，誰道不長生。"]'),
('aa7e87b2-8322-4727-99b6-f203f7cb0b62','五言 十六','呂巖','唐','唐诗','tang','','[]','妙妙妙中妙，玄玄玄更玄。',48,'全唐诗/poet.tang.47000.json','["妙妙妙中妙，玄玄玄更玄。", "動言俱演道，語默盡神仙。", "在掌如珠異，當空似月圓。", "他時功滿後，直入大羅天。"]'),
('85ee1814-a6d0-42eb-b548-db1535244e45','絕句 一','呂巖','唐','唐诗','tang','','[]','捉得金晶固命基，日魂東畔月華西。',32,'全唐诗/poet.tang.47000.json','["捉得金晶固命基，日魂東畔月華西。", "於中煉就長生藥，服了還同天地齊。"]'),
('e15a7226-df6b-48d2-934c-0ea53d3f350f','絕句 二','呂巖','唐','唐诗','tang','','[]','莫怪瑤池消息稀，只緣塵事隔天機。',32,'全唐诗/poet.tang.47000.json','["莫怪瑤池消息稀，只緣塵事隔天機。", "若人尋得水中火，有一黃童上太微。"]'),
('3311951b-217e-4a51-a7db-a32b64d38ce6','絕句 三','呂巖','唐','唐诗','tang','','[]','混元海底隱生倫，內有黃童玉帝名。',32,'全唐诗/poet.tang.47000.json','["混元海底隱生倫，內有黃童玉帝名。", "白虎神符潛姹女，靈元鎮在七元君。"]'),
('fd62fd1d-c17c-4deb-a0b7-9815ba54f783','絕句 四','呂巖','唐','唐诗','tang','','[]','三畝丹田無種種，種時須藉赤龍耕。',32,'全唐诗/poet.tang.47000.json','["三畝丹田無種種，種時須藉赤龍耕。", "曾將此種教人種，不解鉛池道不生。"]'),
('59b1a941-50c9-4ec9-b131-8417e7e8b8ed','絕句 五','呂巖','唐','唐诗','tang','','[]','閃灼虎龍神劒飛，好憑身事莫相違。',32,'全唐诗/poet.tang.47000.json','["閃灼虎龍神劒飛，好憑身事莫相違。", "傳時須在乾坤力，便透三清入紫微。"]'),
('4fed18c2-a9db-4815-b2b7-76c12da0c635','絕句 六','呂巖','唐','唐诗','tang','','[]','不用梯媒向外求，還丹只在體中收。',32,'全唐诗/poet.tang.47000.json','["不用梯媒向外求，還丹只在體中收。", "莫言大道人難得，自是功夫不到頭。"]'),
('5b9f02a6-1481-4f0e-a0ba-fd49d3da2e92','絕句 七','呂巖','唐','唐诗','tang','','[]','飲酒須教一百杯，東浮西泛自梯媒。',32,'全唐诗/poet.tang.47000.json','["飲酒須教一百杯，東浮西泛自梯媒。", "日精自與月華合，有箇明珠走上來。"]'),
('9a183514-1707-4fd9-87f3-be780ced9ab1','絕句 八','呂巖','唐','唐诗','tang','','[]','不負三光不負人，不欺神道不欺貧。',32,'全唐诗/poet.tang.47000.json','["不負三光不負人，不欺神道不欺貧。", "有人問我修行法，只種心田養此身。"]'),
('cef72683-a09a-41a0-8cec-743064f15f64','絕句 九','呂巖','唐','唐诗','tang','','[]','時人若擬去瀛洲，先過巍巍十八樓。',32,'全唐诗/poet.tang.47000.json','["時人若擬去瀛洲，先過巍巍十八樓。", "自有電雷聲震動，一池金水向東流。"]'),
('7bb5db12-c4bf-4ac1-b7ba-d97ad82134d0','絕句 十','呂巖','唐','唐诗','tang','','[]','瓶子如金玉子黃，上升下降續神光。',32,'全唐诗/poet.tang.47000.json','["瓶子如金玉子黃，上升下降續神光。", "三元一會經年淨，這箇天中日月長。"]'),
