('8ef413fc-5ba1-4fa5-a427-379bb1f54a31','贈江州太平觀道士','呂巖','唐','唐诗','tang','','[]','落魄薛高士，年高無白髭。',48,'全唐诗/poet.tang.47000.json','["落魄薛高士，年高無白髭。", "雲中閑臥石，山裏冷尋碑。", "誇我飲大酒，嫌人說小詩。", "不知甚麽漢，一任輩流嗤。"]'),
('c63701c9-bfb0-49e3-baeb-c960b12aff1d','宋朝張天覺爲相之日有繿縷道人及門求施公不知禮敬因戲問道人有何仙術荅以能揑土爲香公請試爲之須臾煙罷道人不見但留詩于案上云','呂巖','唐','唐诗','tang','','[]','捏土爲香事有因，世間宜假不宜真。',32,'全唐诗/poet.tang.47000.json','["捏土爲香事有因，世間宜假不宜真。", "皇朝宰相張天覺，天下雲遊呂洞賓。"]'),
('9ccddb57-f0b6-4e05-925b-49003dfa2a3d','贈陳處士','呂巖','唐','唐诗','tang','','[]','青霄一路少人行，休話興亡事不成。',64,'全唐诗/poet.tang.47000.json','["青霄一路少人行，休話興亡事不成。", "金榜因何無姓字，玉都必是有仙名。", "雲歸入海龍千尺，雲滿長空鶴一聲。", "深謝宋朝明聖主，解書丹詔詔先生。"]'),
('1a083efa-e037-4d6a-8569-b7e676fc371c','哭陳先生','呂巖','唐','唐诗','tang','','[]','天網恢恢萬象疎，一身親到華山區。',64,'全唐诗/poet.tang.47000.json','["天網恢恢萬象疎，一身親到華山區。", "寒雲去後留殘月，春雪來時問太虛。", "六洞真人歸紫府，千年鸞鶴老蒼梧。", "自從遺却先生後，南北東西少丈夫。"]'),
('1d3817a0-07fd-4e7c-8308-047ab579eabd','化江南簡寂觀道士侯用晦磨劒','呂巖','唐','唐诗','tang','','[]','欲整鋒鋩取憚勞，凌晨開匣玉龍嗥。',64,'全唐诗/poet.tang.47000.json','["欲整鋒鋩取憚勞，凌晨開匣玉龍嗥。", "手中氣概冰三尺，石上精神虵一條。", "姦血默隨流水盡，凶豪今逐漬痕消。", "削平浮世不平事，與爾相將上九霄。"]'),
('bbfbc747-acf1-4e1b-b5e8-aef58ef199bc','熙寧元年八月十九日過湖州東林沈山用石榴皮寫絕句於壁自號回山人','呂巖','唐','唐诗','tang','','[]','西鄰已富憂不足，東老雖貧樂有餘。',32,'全唐诗/poet.tang.47000.json','["西鄰已富憂不足，東老雖貧樂有餘。", "白酒釀來緣好客，黃金散盡爲收書。"]'),
('10812bf0-3ddb-4b55-a1fd-187aee311bb2','大雲寺茶詩','呂巖','唐','唐诗','tang','','[]','玉蘂一鎗稱絕品，僧家造法極功夫。',64,'全唐诗/poet.tang.47000.json','["玉蘂一鎗稱絕品，僧家造法極功夫。", "兔毛甌淺香雲白，蝦眼湯翻細浪俱。", "斷送睡魔離几席，增添清氣入肌膚。", "幽叢自落溪巖外，不肯移根入上都。"]'),
('3cfccc63-31e4-448f-9adb-e5ef04dd11f9','別詩二首 一','呂巖','唐','唐诗','tang','','[]','無心獨坐轉黃庭，不逐時流入利名。',64,'全唐诗/poet.tang.47000.json','["無心獨坐轉黃庭，不逐時流入利名。", "救老只存真一氣，修生長遣百神靈。", "朝朝煉液歸瓊壠，夜夜朝元養玉英。", "莫笑老人貧裏樂，十年功滿上三清。"]'),
('df314794-aec3-4778-99ae-6a0463d55340','別詩二首 二','呂巖','唐','唐诗','tang','','[]','時人受氣稟陰陽，均體乾坤壽命長。',64,'全唐诗/poet.tang.47000.json','["時人受氣稟陰陽，均體乾坤壽命長。", "爲重本宗能壽永，因輕元祖遂淪亡。", "三宮自有迴流法，萬物那無運用方。", "咫尺崑崙山上玉，幾人知是藥中王。"]'),
('a6dcac8c-b132-49f8-8758-cadb269d0223','贈羅浮道士','呂巖','唐','唐诗','tang','','[]','羅浮道士誰同流，草衣木食輕王侯。',64,'全唐诗/poet.tang.47000.json','["羅浮道士誰同流，草衣木食輕王侯。", "世間甲子管不得，壺裏乾坤只自由。", "數着殘棊江月曉，一聲長嘯海山秋。", "飲餘回首話歸路，遙指白雲天際頭。"]'),
('ce6ec907-4bb3-4266-b3bf-02569ffd7ddf','宿州天慶觀殿門留贈符離道士','呂巖','唐','唐诗','tang','','[]','秋景蕭條葉亂飛，庭松影裏坐移時。',32,'全唐诗/poet.tang.47000.json','["秋景蕭條葉亂飛，庭松影裏坐移時。", "雲迷鶴駕何方去，仙洞朝元失我期。"]'),
('b3535553-31b0-4b12-983e-db5e50119e97','題黃鶴樓石照','呂巖','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','黃鶴樓前吹笛時，白蘋紅蓼滿江湄。',32,'全唐诗/poet.tang.47000.json','["黃鶴樓前吹笛時，白蘋紅蓼滿江湄。", "衷情欲訴誰能會，惟有清風明月知。"]'),
('4ee45e7e-378e-486b-9535-a9f77bffd102','荅僧見','呂巖','唐','唐诗','tang','','[]','三千里外無家客，七百年來雲水身。',64,'全唐诗/poet.tang.47000.json','["三千里外無家客，七百年來雲水身。", "行滿蓬萊爲別館，道成瓦礫盡黃金。", "待賓榼裏常存酒，化藥爐中別有春。", "積德求師何患少，由來天地不私親。"]'),
('a02f1433-c766-4c72-9738-f1c3179d9b15','與潭州智度寺慧覺詩','呂巖','唐','唐诗','tang','','[]','達者推心兼濟物，聖賢傳法不離真。',32,'全唐诗/poet.tang.47000.json','["達者推心兼濟物，聖賢傳法不離真。", "請師開說西來意，七祖如今未有人。"]'),
('cf44ceff-9ce2-4708-b4e7-e66feb5cec58','參黃龍機悟後呈偈','呂巖','唐','唐诗','tang','','[]','棄却瓢囊摵碎琴，如今不戀□中金。',32,'全唐诗/poet.tang.47000.json','["棄却瓢囊摵碎琴，如今不戀□中金。", "自從一見黃龍後，始覺從前錯用心。"]'),
('f3377218-e870-4b6a-adf4-cf6425587ae1','題僧房絕句','呂巖','唐','唐诗','tang','','[]','唐朝進士，今日神仙。',20,'全唐诗/poet.tang.47000.json','["唐朝進士，今日神仙。", "足躡紫霧，却返洞天。"]'),
('a2297fa0-4fbe-4e21-a467-01a86b851f9e','賜齊州李希遇詩','呂巖','唐','唐诗','tang','','[]','少飲欺心酒，休貪不義財。',24,'全唐诗/poet.tang.47000.json','["少飲欺心酒，休貪不義財。", "福因慈善得，禍向巧姦來。"]'),
('2aed390e-cec4-4ecf-96ad-37adcb6e8abf','六言','呂巖','唐','唐诗','tang','','[]','春暖羣花半開，逍遙石上徘徊。',56,'全唐诗/poet.tang.47000.json','["春暖羣花半開，逍遙石上徘徊。", "獨攜玉律丹訣，閑踏青莎碧苔。", "古洞眠來九載，流霞飲幾千杯。", "逢人莫話他事，笑指白雲去來。"]'),
('07909e25-206d-4c7a-b76a-7f052ce2b2f5','明胎息','呂巖','唐','唐诗','tang','','[]','密室靜存神，陰陽重一斤。',48,'全唐诗/poet.tang.47000.json','["密室靜存神，陰陽重一斤。", "煉成離女液，嚥盡坎男津。", "漸變逍遙體，超然自在身。", "更休功業滿，旌鶴引朝真。"]'),
('a25f3128-9834-4dc9-9a7f-ebe9568a8881','警世','呂巖','唐','唐诗','tang','','[]','二八佳人體似酥，腰間仗劒斬凡夫。',32,'全唐诗/poet.tang.47000.json','["二八佳人體似酥，腰間仗劒斬凡夫。", "雖然不見人頭落，暗裏教君骨髓枯。"]'),
('96e2c63c-8f70-4e1d-9ed9-e6786f67492e','通道','呂巖','唐','唐诗','tang','','[]','通道復通玄，名留四海傳。',48,'全唐诗/poet.tang.47000.json','["通道復通玄，名留四海傳。", "交親一拄杖，活計兩空拳。", "要果逡巡種，思茶逐旋煎。", "豈知來混世，不久却回天。"]'),
('24818449-e5a9-41ad-b7d4-81ab80629745','爲賈師雄發明古鐵鏡','呂巖','唐','唐诗','tang','','[]','手內青虵凌白日，洞中仙果豔長春。',32,'全唐诗/poet.tang.47000.json','["手內青虵凌白日，洞中仙果豔長春。", "須知物外煙霞客，不是塵中磨鏡人。"]'),
('fad2e3b8-c17a-43dd-976b-fac54e398e90','題全州道士蔣暉壁','呂巖','唐','唐诗','tang','','[]','醉舞高歌海上山，天瓢承露結金丹。',32,'全唐诗/poet.tang.47000.json','["醉舞高歌海上山，天瓢承露結金丹。", "夜深鶴透秋空碧，萬里西風一劒寒。"]'),
('b6cc0491-846c-4fde-ba61-524cd6323a44','謁石守道','呂巖','唐','唐诗','tang','','[]','高心休擬鳳池遊，朱紱銀章寵已優。',32,'全唐诗/poet.tang.47000.json','["高心休擬鳳池遊，朱紱銀章寵已優。", "欲待禍來名欲滅，林泉養法預爲謀。"]'),
('15953941-0641-4b4e-9c0e-bdfcdc4efa51','題廣陵妓屏二首 一','呂巖','唐','唐诗','tang','','[]','嫫母西施共此身，可憐老少隔千春。',32,'全唐诗/poet.tang.47000.json','["嫫母西施共此身，可憐老少隔千春。", "他年鶴髮雞皮媼，今日玉顏花貌人。"]'),
('4a97b707-c0b6-4d49-96a5-ac2495c033d4','題廣陵妓屏二首 二','呂巖','唐','唐诗','tang','','[]','花開花落兩悲歡，花與人還事一般。',32,'全唐诗/poet.tang.47000.json','["花開花落兩悲歡，花與人還事一般。", "開在枝間妨客折，落來地上請誰看。"]'),
('f0bffd4b-fc60-4b81-a87e-6f78b072d594','題東都妓館壁','呂巖','唐','唐诗','tang','','[]','一吸鸞笙裂太清，綠衣童子步虛聲。',32,'全唐诗/poet.tang.47000.json','["一吸鸞笙裂太清，綠衣童子步虛聲。", "玉樓喚醒千年夢，碧桃枝上金雞鳴。"]'),
('97fdbb63-2d58-48ba-b7b9-4ca8c2c93e3c','崔中舉進士遊岳陽遇真人錄沁園春詞詰其姓名薦之李守排戶而入惟見留詩于壁','呂巖','唐','唐诗','tang','','[]','腹內嬰兒養已成，且居廛市暫娛情。',32,'全唐诗/poet.tang.47000.json','["腹內嬰兒養已成，且居廛市暫娛情。", "無端措大剛饒舌，却入白雲深處行。"]'),
('b48ff3ef-b33b-4c90-9587-a5a03f05ca66','題詩紫極宮','呂巖','唐','唐诗','tang','','[]','宮門一閑入，臨水憑欄立。',24,'全唐诗/poet.tang.47000.json','["宮門一閑入，臨水憑欄立。", "無人知我來，朱頂鶴聲急。"]'),
('7e008712-a49b-4447-9c6b-881523f48470','閑題','呂巖','唐','唐诗','tang','','[]','獨自行來獨自坐，無限世人不識我。',32,'全唐诗/poet.tang.47000.json','["獨自行來獨自坐，無限世人不識我。", "惟有城南老樹精，分明知道神仙過。"]'),
('c84ec2fa-cf4b-4d49-90da-21884df659bd','山隱','呂巖','唐','唐诗','tang','','[]','松枯石老水縈迴，箇裏難教俗客來。',32,'全唐诗/poet.tang.47000.json','["松枯石老水縈迴，箇裏難教俗客來。", "擡眼試看山外景，紛紛風急障黃埃。"]'),
('1ff9af08-5d70-4331-a818-d51aba1a781d','絕句 一','呂巖','唐','唐诗','tang','','[]','息精息氣養精神，精養丹田氣養身。',32,'全唐诗/poet.tang.47000.json','["息精息氣養精神，精養丹田氣養身。", "有人學得這般術，便是長生不死人。"]'),
('d73647d3-09be-4bea-b7c8-72f741d550dd','絕句 二','呂巖','唐','唐诗','tang','','[]','斗笠爲帆扇作舟，五湖四海任遨遊。',32,'全唐诗/poet.tang.47000.json','["斗笠爲帆扇作舟，五湖四海任遨遊。", "大千沙界須臾至，石爛松枯經幾秋。"]'),
('406a277d-9657-47f7-a85b-7e52dd93ba5a','絕句 三','呂巖','唐','唐诗','tang','','[]','或爲道士或爲僧，混俗和光別有能。',32,'全唐诗/poet.tang.47000.json','["或爲道士或爲僧，混俗和光別有能。", "苦海翻成天上路，毘盧常照百千燈。"]'),
('5fa6ab28-af29-4b8c-9a40-82c73c0923a8','勸世','呂巖','唐','唐诗','tang','','[]','一毫之善，與人方便。',70,'全唐诗/poet.tang.47000.json','["一毫之善，與人方便。", "一毫之惡，勸君莫作。", "衣食隨緣，自然快樂。", "筭是甚命，問什麽卜。", "欺人是禍，饒人是福。", "天眼昭昭，報應甚速。", "諦聽吾言，神欽鬼伏。"]'),
('f52d0c04-d75f-4f0c-bd6b-eb67876e816e','𡏟頭坯歌','呂巖','唐','唐诗','tang','','[]','𡏟頭坯，隨雨破，秪是未曾經水火。',387,'全唐诗/poet.tang.47000.json','["𡏟頭坯，隨雨破，秪是未曾經水火。", "若經水火燒成磚，留向世間住萬年。", "稜角堅完不復壞，扣之聲韻堪磨鐫。", "凡水火，尚成功，堅完萬物誰能同。", "修行路上多少人，窮年煉養費精神。", "不道未曾經水火，無常一旦臨君身。", "既不悟，終不悔，死了猶來借精髓。", "主持正念大艱辛，一失人身爲異類。", "君不見洛陽富鄭公，說與金丹如盲聾。", "執迷不悟修真理，焉知潛合造化功。", "又不見九江張尚書，服藥失明神氣枯。", "不知還丹本無質，翻餌金石何太愚。", "又不見三衢趙樞密，參禪作鬼終不識。", "修完外體在何邊，辯捷語言終不實。", "𡏟頭坯，隨雨破，便似修行這幾箇。", "大丈夫，超覺性，了盡空門不爲證。", "伏羲傳道至于今，窮理盡性至於命。", "了命如何是本元，先認坎離幷四正。", "坎離即是真常家，見者超凡須入聖。", "坎是虎，離是龍，二體本來同一宮。", "龍吞虎啗居其中，離合浮沈初復終。", "剝而復，否而泰，進退往來定交會。", "弦而望，明而晦，消長盈虛相匹配。", "神仙深入水晶宮，時飲醍醐清更醲。"]'),
('aa8f930a-65ca-4044-ad7d-a75fc9c09bf5','贈劉方處士','呂巖','唐','唐诗','tang','','[]','六國愁看沉與浮，攜琴長歗出神州。',384,'全唐诗/poet.tang.47000.json','["六國愁看沉與浮，攜琴長歗出神州。", "擬向煙霞煮白石，偶來城市見丹丘。", "受得金華出世術，期於紫府駕雲遊。", "年來摘得黃巖翠，琪樹參差連地肺。", "露飄香隴玉苗滋，月上碧峰丹鶴唳。", "洞天消息春正深，仙路往還俗難繼。", "忽因乘興下白雲，與君邂逅於塵世。", "塵世相逢開口希，共論太古同流志。", "瑤琴寶瑟與君彈，瓊漿玉液勸我醉。", "醉中亦話興亡事，云道總無珪組累。", "浮世短景倏成空，石火電光看即逝。", "韶年淑質曾非固，花面玉顏還作土。", "芳樽但繼曉復昏，樂事不窮今與古。", "何如識箇玄玄道，道在杳冥須細考。", "壺中一粒化奇物，物外千年功力奧。", "但能制得水中華，水火翻成金丹竈。", "丹就人間不久居，自有碧霄元命誥。", "玄洲暘谷悉可居，地壽天齡永相保。", "鸞車鶴駕逐雲飛，迢迢瑤池應易到。", "耳聞爭戰還傾覆，眼見妍華成枯槁。", "唐家舊國盡荒蕪，漢室諸侯空白草。", "蜉蝣世界實足悲，槿花性命莫遲遲。", "珠璣溢屋非爲福，羅綺滿箱徒自危。", "志士戒貪昔所重，達人忘欲寧自期。"]'),
('fd41be01-a579-49be-89cb-6e21b69bc4cb','寄白龍洞劉道人','呂巖','唐','唐诗','tang','','[]','玉走金飛兩曜忙，始聞花發又秋霜。',384,'全唐诗/poet.tang.47000.json','["玉走金飛兩曜忙，始聞花發又秋霜。", "徒誇籛壽千年歲，也是雲中一電光。", "一電光，何太疾，百年都來三萬日。", "其間寒暑互煎熬，不覺童顏暗中失。", "縱有兒孫滿眼前，却成恩愛轉牽纏。", "及乎精竭身枯朽，誰解教伊暫駐顏。", "延年之道既無計，不免將身歸逝水。", "但看古往聖賢人，幾箇解留身在世。", "身在世，也有方，只爲時人誤度量。", "競向山中尋草藥，伏鉛制汞點丹陽。", "點丹陽，事迥別，須向坎中求赤血。", "取來離位制陰精，配合調和有時節。", "時節正，用媒人，金翁姹女結親姻。", "金翁偏愛騎白虎，姹女常駕赤龍身。", "虎來靜坐秋江裏，龍向潭中奮身起。", "兩獸相逢戰一場，波浪奔騰如鼎沸。", "黃婆丁老助威靈，撼動乾坤走神鬼。", "須臾戰罷雲氣收，種箇玄珠在泥底。", "從此根芽漸長成，隨時灌溉抱真精。", "十月脫胎吞入口，忽覺凡身已有靈。", "此箇事，世間稀，不是等閑人得知。", "宿世若無仙骨分，容易如何得遇之。", "金液丹，宜便煉，大都光景急如箭。", "要取魚，須結筌，何不收心煉取鉛？"]'),
('cf23be31-cf66-4eab-9d99-c2083b6074bd','贈喬二郎','呂巖','唐','唐诗','tang','','[]','與君相見皇都裏，陶陶動便經年醉。',208,'全唐诗/poet.tang.47000.json','["與君相見皇都裏，陶陶動便經年醉。", "醉中往往愛藏真，亦不爲他名與利。", "勸君休戀浮華榮，直須奔走煙霞程。", "煙霞欲去如何去，先須肘後飛金晶。", "金晶飛到上宮裏，上宮下宮通光明。", "當時玉汞涓涓生，奔歸元海如雷聲。", "從此夫妻相際會，歡娛踴躍情無外。", "水火都來兩半間，卦候翻成地天泰。", "一浮一沈陽煉陰，陰盡方知此理深。", "到底根元是何物，分明只是水中金。", "喬公喬公急下手，莫逐烏飛兼兔走。", "何如脩煉作真人，塵世浮生終不久。", "人道長生沒得來，自古至今有有有。"]'),
('d2dd1c88-68a7-4054-bd14-edafb3798407','鄂渚悟道歌','呂巖','唐','唐诗','tang','','[]','縱橫天際爲閑客，時遇季秋重陽節。',304,'全唐诗/poet.tang.47000.json','["縱橫天際爲閑客，時遇季秋重陽節。", "陰雲一布徧長空，膏澤連綿滋萬物。", "因雨泥滑門不出，忽聞鄰舍語丹術。", "試問鄰公可相傳，一言許肯更無難。", "數篇奇怪文入手，一夜挑燈讀不了。", "曉來日早纔看畢，不覺自醉如恍惚。", "恍惚之中見有物，狀如日輪明突屼。", "自言便是丹砂精，宜向鼎中烹凡質。", "凡質本來不化真，化真須得真中物。", "不用鉛，不用汞，還丹須向爐中種。", "玄中之玄號真鉛，及至用鉛還不用。", "或名龍，或名虎，或號嬰兒幷姹女。", "丹砂一粒名千般，一中有一爲丹母。", "火莫燃，水莫凍，修之煉之須珍重。", "直待虎歗折顛峰，驪龍奪得玄珠弄。", "龍吞玄寶忽昇飛，飛龍被我捉來騎。", "一翥上朝歸碧落，碧落廣闊無東西。", "無曉無夜無年月，無寒無暑無四時。", "自從修到無爲地，始覺奇之又怪之。"]'),
('a87142ad-8126-4f60-9f10-31346bceddd3','又記','呂巖','唐','唐诗','tang','','[]','數載樂幽幽，欲逃寒暑逼。',276,'全唐诗/poet.tang.47000.json','["數載樂幽幽，欲逃寒暑逼。", "不求名與利，猶恐身心役。", "苦志慕黃庭，慇懃求道跡。", "陰功暗心修，善行長日積。", "世路果逢師，時人皆不識。", "我師機行密，懷量性孤僻。", "解把五行移，能將四象易。", "傳余造化門，始悟希夷則。", "服取兩般真，從頭路端的。", "烹煎日月壺，不離乾坤側。", "至道眼前觀，得之元咫尺。", "真空空不空，真色色非色。", "推倒玉葫蘆，迸出黃金液。", "緊把赤龍頭，猛將驪珠吸。", "吞歸臟腑中，奪得神仙力。", "妙號一黍珠，延年千萬億。", "同途聽我吟，與道相親益。", "未曉真黃芽，徒勞遊紫陌。", "把住赤烏魂，突出銀蟾魄。", "未省此中玄，常流容易測。", "三天應有路，九地終無厄。", "守道且藏愚，忘機要混迹。", "羣生莫相輕，已是蓬萊客。"]'),
('1076a8a8-676e-46e7-a4bf-bc54597a6b17','秘訣歌','呂巖','唐','唐诗','tang','','[]','求之不見，來即不見。',119,'全唐诗/poet.tang.47000.json','["求之不見，來即不見。", "不見不見，君之素面。", "火裏曾飛，水中亦見。", "道路非遙，身心不戀。", "又不知有返陰之龜，回陽之鴈。", "遇即遇真人，達即達其神。", "一萬二千甲子，這一壺流霞長春。", "流霞流霞，本性一家。", "飢餐日精，渴飲月華。", "將甲子丁丑之歲，與君決破東門之大瓜。"]'),
('74099436-d234-4a4c-8b4e-f841ba404834','勉牛生夏侯生','呂巖','唐','唐诗','tang','','[]','二秀才，二秀才兮非秀才，非秀才兮是仙才。',195,'全唐诗/poet.tang.47000.json','["二秀才，二秀才兮非秀才，非秀才兮是仙才。", "中華國裏親遭遇，仰面觀天笑眼開。", "鶴形兮龜骨，龍吟兮虎顏。", "我有至言相勸勉，願君兮勿猜勿猜。", "但煦日吹月，嚥雨呵雷。", "火寄冥宮，水濟丹臺。", "金木交而土歸位，鉛汞分而丹露胎。", "赤血換而白乳流，透九竅兮動百骸。", "然然卷，然然舒，哀哀咍咍。", "孩兒喘而不死，腹空虛兮長齋。", "酬名利兮狂歌醉舞，酬富貴兮麻裰莎鞋。", "甲子問時休記，看桑田變作黃埃。", "青山白雲好居住，勸君歸去來兮歸去來。"]'),
('b9503043-cc56-4eb9-acff-38e7ab244219','題四明金鵝寺壁','呂巖','唐','唐诗','tang','','[]','方丈有門出不鑰，見箇山童露雙脚。',96,'全唐诗/poet.tang.47000.json','["方丈有門出不鑰，見箇山童露雙脚。", "問伊方丈何寂寥，道是虛空也不著。", "聞此語，何欣欣，主翁豈是尋常人。", "我來謁見不得見，謁心耿耿生埃塵。", "歸去也，波浩渺，路入蓬萊山杳杳。", "相思一上石樓時，雪晴海闊千峰曉。"]'),
('47e454df-52ed-40a5-b0e6-a60519605ada','谷神歌','呂巖','唐','唐诗','tang','','[]','我有一腹空谷虛，言之道有又還無。',334,'全唐诗/poet.tang.47000.json','["我有一腹空谷虛，言之道有又還無。", "言之無兮不可捨，言之有兮不可居。", "谷兮谷兮太玄妙，神兮神兮真大道。", "保之守之不死名，修之煉之仙人號。", "神得一以靈，谷得一以盈。", "若人能守一，只此是長生。", "本不遠離，身還不見。", "煉之功若成，自然凡骨變。", "谷神不死玄牝門，出入綿綿道若存。", "修煉還須夜半子，河車般載上崑崙。", "龍又吟，虎又歗，風雲際會黃婆叫。", "火中姹女正含嬌，回觀水底嬰兒俏。", "嬰兒姹女見黃婆，兒女相逢兩意和。", "金殿玉堂門十二，金翁木母正來過。", "重門過後牢關鎖，點檢斗牛先下火。", "進火消陰始一陽，千歲仙桃初結果。", "曲江東岸金烏飛，西岸清光玉兔輝。", "烏兔走歸峰頂上，爐中姹女脫青衣。", "脫却青衣露素體，嬰兒領入重幃裏。", "十月情濃產一男，說道長生永不死。", "勸君煉，勸君修，谷神不死此中求。", "此中悟取玄微處，與君白日登瀛洲。"]'),
('5a83d27e-3b6b-486c-938c-5524b9feb210','修身訣','呂巖','唐','唐诗','tang','','[]','人命急如線，上下來往速如箭。',76,'全唐诗/poet.tang.47000.json','["人命急如線，上下來往速如箭。", "認得是元神，子後午前須至煉。", "隨意出，隨意入，天地三才人得一。", "既得一，勿遺失，失了永求無一物。", "堪歎荒郊塚墓中，自古滅亡不知屈。"]'),
('df16656e-76ed-4489-b152-ba12a11e560c','長短句','呂巖','唐','唐诗','tang','','[]','落魄且落魄，夜宿鄉村，朝遊城郭。',64,'全唐诗/poet.tang.47000.json','["落魄且落魄，夜宿鄉村，朝遊城郭。", "閑來無事玩青山，因來街市貨丹藥。", "賣得錢，不算度，酤美酒，自斟酌。", "醉後吟哦動鬼神，任意日頭向西落。"]'),
('e404fba9-8b04-4b8d-9caf-325368542176','直指大丹歌','呂巖','唐','唐诗','tang','','[]','三清宮殿隱崑巔，日月光浮起紫煙。',128,'全唐诗/poet.tang.47000.json','["三清宮殿隱崑巔，日月光浮起紫煙。", "池沼泓泓翻玉液，樓臺疊疊運靈泉。", "青龍乘火鉛爲汞，白虎騰波汞作鉛。", "欲得坎男求匹偶，須憑離女結因緣。", "黃婆設盡千般計，金鼎開成一朵蓮。", "列女擎烏當左畔，將軍戴兔鎮西邊。", "黑龜却伏紅爐下，朱雀還棲華閣前。", "然後澄神窺見影，三周功就駕雲軿。"]'),
('5efc3567-b3a9-49ee-940d-dd52aab171ac','漁父詞一十八首 入定','呂巖','唐','唐诗','tang','','[]','閉目藏真神思凝，杳冥中裏見吾宗。',32,'全唐诗/poet.tang.47000.json','["閉目藏真神思凝，杳冥中裏見吾宗。", "無邊畔，迥朦朧，玄景觀來覺盡空。"]'),
('b6eca962-dd06-464f-bec6-061b9c2ceaab','漁父詞一十八首 初九','呂巖','唐','唐诗','tang','','[]','大道從來屬自然，空堂寂坐守機關。',32,'全唐诗/poet.tang.47000.json','["大道從來屬自然，空堂寂坐守機關。", "三田寶，鎮長存，赤帝分明坐廣寒。"]'),
('9c736477-969b-4410-b4bb-db3e85a99a88','漁父詞一十八首 玄用','呂巖','唐','唐诗','tang','','[]','日月交加曉夜奔，崑崙頂上定乾坤。',32,'全唐诗/poet.tang.47000.json','["日月交加曉夜奔，崑崙頂上定乾坤。", "真鏡裏，實堪論，靉靉紅霞曉寂門。"]'),
('a96f42a7-0a9e-4192-a934-39b0407eaa3b','漁父詞一十八首 神効','呂巖','唐','唐诗','tang','','[]','恍惚擒來得自然，偷他造化在其間。',32,'全唐诗/poet.tang.47000.json','["恍惚擒來得自然，偷他造化在其間。", "神鼎內，火烹煎，盡歷陰陽結作丹。"]'),
('f15628e2-507c-4a38-8f7a-5f3b4920cd4a','漁父詞一十八首 沐浴','呂巖','唐','唐诗','tang','','[]','卯酉門中作用時，赤龍時蘸玉清池。',32,'全唐诗/poet.tang.47000.json','["卯酉門中作用時，赤龍時蘸玉清池。", "雲薄薄，雨微微，看取妖容露雪肌。"]'),
('b13aea1b-3495-4bfa-a664-c662601a2884','漁父詞一十八首 延壽','呂巖','唐','唐诗','tang','','[]','子午常餐日月精，玄關門戶啓還扃。',32,'全唐诗/poet.tang.47000.json','["子午常餐日月精，玄關門戶啓還扃。", "長如此，過平生，且把陰陽子細烹。"]'),
('c2145939-0bea-43b1-8b54-5321f04f53d6','漁父詞一十八首 瑞鼎','呂巖','唐','唐诗','tang','','[]','會合都從戊巳家，金鉛水汞莫須誇。',32,'全唐诗/poet.tang.47000.json','["會合都從戊巳家，金鉛水汞莫須誇。", "只此物，結丹砂，反覆陰陽色轉華。"]'),
('f217a9f4-3305-4bc0-9e9d-cfc24d6c7535','漁父詞一十八首 活得','呂巖','唐','唐诗','tang','','[]','位立三才屬五行，陰陽合處便相生。',32,'全唐诗/poet.tang.47000.json','["位立三才屬五行，陰陽合處便相生。", "龍飛踴，虎狌獰，吐箇神珠各戰爭。"]'),
('151c0b94-0ed6-4fb0-bec8-4265385d5df4','漁父詞一十八首 燦爛','呂巖','唐','唐诗','tang','','[]','四象分明八卦周，乾坤男女論綢繆。',32,'全唐诗/poet.tang.47000.json','["四象分明八卦周，乾坤男女論綢繆。", "交會處，更嬌羞，轉覺情深玉體柔。"]'),
('06d13a0c-b850-4e6f-ad75-fcb990e49db9','漁父詞一十八首 鍊質','呂巖','唐','唐诗','tang','','[]','運本還元於此尋，周流金鼎虎龍吟。',32,'全唐诗/poet.tang.47000.json','["運本還元於此尋，周流金鼎虎龍吟。", "身不老，俗難侵，貌返童顏骨變金。"]'),
('84fcbf10-8f56-44b1-8735-1055fdab6a45','漁父詞一十八首 神異','呂巖','唐','唐诗','tang','','[]','還返初成立變童，瑞蓮開處色輝紅。',32,'全唐诗/poet.tang.47000.json','["還返初成立變童，瑞蓮開處色輝紅。", "金鼎內，迥朦朧，換骨添筋處處通。"]'),
('cdfca188-646d-4d0f-8689-d1d25735da77','漁父詞一十八首 知路','呂巖','唐','唐诗','tang','','[]','那箇仙經述此方，參同大易顯陰陽。',32,'全唐诗/poet.tang.47000.json','["那箇仙經述此方，參同大易顯陰陽。", "須窮取，莫顛狂，會者名高道自昌。"]'),
('2824a01b-48a4-4802-a83c-2e95dd658545','漁父詞一十八首 朝帝','呂巖','唐','唐诗','tang','','[]','九轉功成數盡乾，開爐撥鼎見金丹。',32,'全唐诗/poet.tang.47000.json','["九轉功成數盡乾，開爐撥鼎見金丹。", "餐餌了，別塵寰，足躡青雲突上天。"]'),
('d06af775-14c8-4ae2-b36e-7edd4a7e2e99','漁父詞一十八首 方契理','呂巖','唐','唐诗','tang','','[]','舉世人生何所依，不求自己更求誰。',32,'全唐诗/poet.tang.47000.json','["舉世人生何所依，不求自己更求誰。", "絕嗜慾，斷貪癡，莫把神明暗裏欺。"]'),
('f17a2a6e-ab55-48e8-8eb1-5ad69cc4adda','漁父詞一十八首 自無憂','呂巖','唐','唐诗','tang','','[]','學道初從此處修，斷除貪愛別嬌柔。',32,'全唐诗/poet.tang.47000.json','["學道初從此處修，斷除貪愛別嬌柔。", "長守靜，處深幽，服氣餐霞飽即休。"]'),
('c9103ca1-d1e8-4180-9bf2-42bcf2a044b7','漁父詞一十八首 作甚物','呂巖','唐','唐诗','tang','','[]','貪貴貪榮逐利名，追遊醉後戀歡情。',32,'全唐诗/poet.tang.47000.json','["貪貴貪榮逐利名，追遊醉後戀歡情。", "年不永，代君驚，一報身終那裏生。"]'),
('01415e00-b0bf-4abb-865a-0737f6d8253e','漁父詞一十八首 疾瞥地','呂巖','唐','唐诗','tang','','[]','萬劫千生得箇人，須知先世種來因。',32,'全唐诗/poet.tang.47000.json','["萬劫千生得箇人，須知先世種來因。", "速覺悟，出迷津，莫使輪迴受苦辛。"]'),
('bf6f9139-a6ca-4125-80d5-a539e710c5f8','漁父詞一十八首 常自在','呂巖','唐','唐诗','tang','','[]','閉目尋真真自歸，玄珠一顆出輝輝。',32,'全唐诗/poet.tang.47000.json','["閉目尋真真自歸，玄珠一顆出輝輝。", "終日翫，莫拋離，免使閻王遣使追。"]'),
('107374f2-b31c-4465-9771-ab27c350ebbc','口占','呂巖','唐','唐诗','tang','','[]','非神亦非仙，非術亦非幻。',48,'全唐诗/poet.tang.47000.json','["非神亦非仙，非術亦非幻。", "天地有終窮，桑田幾遷變。", "身固非我有，財亦何足戀。", "曷不從吾遊，騎鯨騰汗漫。"]'),
('d5f5fe31-5618-4684-952e-d11dc835a94d','敲爻歌','呂巖','唐','唐诗','tang','','[]','漢終唐國飄蓬客，所以敲爻不可測。',384,'全唐诗/poet.tang.47000.json','["漢終唐國飄蓬客，所以敲爻不可測。", "縱橫逆順沒遮欄，靜則無爲動是色。", "也飲酒，也食肉，守定胭花斷淫慾。", "行歌唱詠胭粉詞，持戒酒肉常充腹。", "色是藥，酒是祿，酒色之中無拘束。", "只因花酒悞長生，飲酒帶花神鬼哭。", "不破戒，不犯淫，破戒真如性即沈。", "犯淫壞失長生寶，得者須由道力人。", "道力人，真散漢，酒是良朋花是伴。", "花街柳巷覓真人，真人只在花街翫。", "摘花戴飲長生酒，景裏無爲道自昌。", "一任羣迷多笑怪，仙花仙酒是仙鄉。", "到此鄉，非常客，姹女嬰兒生喜樂。", "洞中常採四時花，時花結就長生藥。", "長生藥，採花心，花蘂層層豔麗春。", "時人不達花中理，一訣天機直萬金。", "謝天地，感虛空，得遇仙師是祖宗。", "附耳低言玄妙旨，提上蓬萊第一峰。", "第一峰，是仙物，惟產金花生恍惚。", "口口相傳不記文，須得靈根骨髓堅。", "堅骨髓，煉靈根，片片桃花洞裏春。", "七七白虎雙雙養，八八青龍總一斤。", "真父母，送元宮，木母金公性本溫。", "十二宮中蟾魄現，時時地魄降天魂。"]'),
('3fa9a412-f929-4b90-b539-ed7b915316b0','三字訣','呂巖','唐','唐诗','tang','','[]','這箇道，非常道。',184,'全唐诗/poet.tang.47000.json','["這箇道，非常道。", "性命根，生死竅。", "說著醜，行着妙。", "人人憎，箇箇笑。", "大關鍵，在顛倒。", "莫厭穢，莫計較。", "得他來，立見効。", "地天泰，爲朕兆。", "口對口，竅對竅。", "吞入腹，自知道。", "藥苗新，先天兆。", "審眉間，行逆道。", "滓質物，自繼紹。", "二者餘，方絕妙。", "要行持，令人叫。", "氣要堅，神莫耗。", "若不行，空老耄。", "認得真，老還少。", "不知音，莫語要。", "此兒法，合大道。", "精氣神，不老藥。", "靜裏全，明中報。", "乘鳳鸞，聽天詔。"]'),
('c3eff3b2-57f9-4d08-bc14-4607508083c0','百字碑','呂巖','唐','唐诗','tang','','[]','養氣忘言守，降心爲不爲。',120,'全唐诗/poet.tang.47000.json','["養氣忘言守，降心爲不爲。", "動靜知宗祖，無事更尋誰。", "真常須應物，應物要不迷。", "不迷性自住，性住氣自回。", "氣回丹自結，壺中配坎離。", "陰陽生返復，普化一聲雷。", "白雲朝頂上，甘露灑須彌。", "自飲長生酒，逍遙誰得知。", "坐聽無弦曲，明通造化機。", "都來二十句，端的上天梯。"]'),
('3afa4d47-2cb3-4bb2-a184-ce2006703663','句','呂巖','唐','唐诗','tang','','[]','莫道神仙無學處，古今多少上昇人。',16,'全唐诗/poet.tang.47000.json','["莫道神仙無學處，古今多少上昇人。"]'),
('1ffe443f-f1de-4969-9518-6eebd13b1344','四言詩','孫思邈','唐','唐诗','tang','','[]','取金之精，合石之液。',190,'全唐诗/poet.tang.47000.json','["取金之精，合石之液。", "列爲夫婦，結爲魂魄。", "一體混沌，兩精感激。", "河車覆載，鼎候無忒。", "洪鑪烈火，烘燄翕赫。", "煙未及黔，燄不假碧。", "如畜扶桑，若藏霹靂。", "姹女氣索，嬰兒聲寂。", "透出兩儀，麗於四極。", "壁立幾多，馬馳一驛。", "宛其死矣，適然從革。", "惡黜善遷，情回性易。", "紫色內達，赤芒外射。", "熠若火生，乍疑血滴。", "號曰中環，退藏於密。", "霧散五內，川流百脉。", "骨變金植，顏駐玉澤。", "陽德乃敷，陰功□積。", "南宮度名，北斗落籍。"]'),
('5002b25f-e00e-4fa1-bcd1-9436b6db5381','留詩 一','葉法善','唐','唐诗','tang','','[]','昔在禹餘天，還依太上家。',48,'全唐诗/poet.tang.47000.json','["昔在禹餘天，還依太上家。", "忝以掌仙錄，去來乘煙霞。", "暫下宛利城，渺然思金華。", "自此非久住，雲上登香車。"]'),
('ab93604f-f6a2-41a6-9e00-c83ad4155e26','留詩 二','葉法善','唐','唐诗','tang','','[]','適向人間世，時復濟蒼生。',48,'全唐诗/poet.tang.47000.json','["適向人間世，時復濟蒼生。", "度人初行滿，輔國亦功成。", "但念清微樂，誰忻下界榮。", "門人好住此，翛然雲上征。"]'),
('ef6858d5-204f-4875-8d42-55cab0fd33c9','留詩 三','葉法善','唐','唐诗','tang','','[]','退仙時此地，去俗久爲榮。',48,'全唐诗/poet.tang.47000.json','["退仙時此地，去俗久爲榮。", "今日登雲天，歸真遊上清。", "泥丸空示世，騰舉不爲名。", "爲報學仙者，知余朝玉京。"]'),
('6d66d362-9b84-4205-9a92-3f6bfcde3652','題登真洞','張果','唐','唐诗','tang','','[]','修成金骨鍊歸真，洞鎖遺蹤不計春。',64,'全唐诗/poet.tang.47000.json','["修成金骨鍊歸真，洞鎖遺蹤不計春。", "野草謾隨青嶺秀，閑花長對白雲新。", "風搖翠篠敲寒玉，水激丹砂走素鱗。", "自是神仙多變異，肯教踪跡掩紅塵。"]'),
('9226587f-a96d-47bc-9f9c-ae25a980b1b0','負薪行','許宣平','唐','唐诗','tang','','[]','負薪朝出賣，沽酒日西歸。',28,'全唐诗/poet.tang.47000.json','["負薪朝出賣，沽酒日西歸。", "路人莫問歸何處，穿入白雲行翠微。"]'),
('06b2a680-a0ea-4b8f-854f-ac41947e560b','庵壁題詩','許宣平','唐','唐诗','tang','','[]','隱居三十載，石室南山巔。',48,'全唐诗/poet.tang.47000.json','["隱居三十載，石室南山巔。", "靜夜翫明月，清朝飲碧泉。", "樵人歌壠上，谷鳥戲巖前。", "樂矣不知老，都忘甲子年。"]'),
('b8e8f06c-6d43-4d1d-b073-cdb8214cb35d','見李白詩又吟','許宣平','唐','唐诗','tang','','[]','一池荷葉衣無盡，兩畝黃精食有餘。',32,'全唐诗/poet.tang.47000.json','["一池荷葉衣無盡，兩畝黃精食有餘。", "又被人來尋討著，移庵不免更深居。"]'),
('d9a6e032-6de3-44dc-b16c-b7d38d821080','題壁','成真人','唐','唐诗','tang','','[]','蜀路南行，燕師北至。',24,'全唐诗/poet.tang.47000.json','["蜀路南行，燕師北至。", "本擬白日昇天，且看黑龍飲渭。"]'),
('3e03f381-62b5-48de-99aa-572d9629291f','對趙潁歌','朱子真','唐','唐诗','tang','','[]','人間幾日變桑田，誰識神仙洞裏天。',32,'全唐诗/poet.tang.47000.json','["人間幾日變桑田，誰識神仙洞裏天。", "短促共知有□異，且須歡醉在生前。"]'),
('fd774aec-85c1-4488-8fd4-9ae3257a32e6','兜玄國懷歸詩','申歡','唐','唐诗','tang','','[]','風軟景和煦，異香馥林塘。',24,'全唐诗/poet.tang.47000.json','["風軟景和煦，異香馥林塘。", "登高一長望，信美非吾鄉。"]'),
('1420e11e-7cfa-4092-a930-014a636b0f06','題壁','李遐周','唐','唐诗','tang','','[]','燕市人皆去，函關馬不歸。',24,'全唐诗/poet.tang.47000.json','["燕市人皆去，函關馬不歸。", "若逢山下鬼，環上繫羅衣。"]'),
('3e121ad9-27e9-4ad3-b2ac-6d674c5bb356','遺簡詩 一','趙惠宗','唐','唐诗','tang','','[]','生我於虛，置我於無。',50,'全唐诗/poet.tang.47000.json','["生我於虛，置我於無。", "至精爲神，元氣爲軀。", "散陽爲明，合陰爲符。", "形爲灰土，神爲仙居。", "衆垢將畢，萬事永除。"]'),
('eef9f438-750b-43ae-811a-6b67176e5d51','遺簡詩 二','趙惠宗','唐','唐诗','tang','','[]','吾駕時馬，日月爲衛。',50,'全唐诗/poet.tang.47000.json','["吾駕時馬，日月爲衛。", "洞耀九霄，上謁天帝。", "明明我衆，及我門人。", "僞道養形，真道養神。", "懋哉懋哉，餘無所陳。"]'),
('37c064ff-2294-421d-83dd-4e4655dfca6a','遇蓮葉二客詩','欒清','唐','唐诗','tang','','[]','得飲攄公酒，復登攄公舟。',24,'全唐诗/poet.tang.47000.json','["得飲攄公酒，復登攄公舟。", "便得神體清，超遙曠無憂。"]'),
('c4ff7fd7-7a17-4456-9f2a-7aed1bc35ad5','蓮葉二客詩 一','欒清','唐','唐诗','tang','','[]','行時雲作伴，坐即酒爲侶。',36,'全唐诗/poet.tang.47000.json','["行時雲作伴，坐即酒爲侶。", "腹以元化充，衣將雲霞補。", "紂虐與堯仁，可惜皆朽腐。"]'),
('6d6b778f-3db6-4e59-92eb-72a3e25af15e','蓮葉二客詩 二','欒清','唐','唐诗','tang','','[]','檝櫂無所假，超然信萍查。',36,'全唐诗/poet.tang.47000.json','["檝櫂無所假，超然信萍查。", "朝浮旭日輝，夕蔭清月華。", "營營功業人，朽骨成泥沙。"]'),
('e9694be4-7005-4bd1-9c46-b84c6674d617','言志','韓湘','唐','唐诗','tang','','[]','青山雲水窟，此地是吾家。',84,'全唐诗/poet.tang.47000.json','["青山雲水窟，此地是吾家。", "後夜流瓊液，凌晨咀綘霞。", "琴彈碧玉調，鍊煉白硃砂。", "寶鼎存金虎，元田養白鴉。", "一瓢藏世界，三尺斬妖邪。", "解造逡巡酒，能開頃刻花。", "有人能學我，同去看仙葩。"]'),
('67279752-e2cc-476e-ac21-982b676df73e','荅從叔愈','韓湘','唐','唐诗','tang','','[]','舉世都爲名利醉，伊予獨向道中醒。',32,'全唐诗/poet.tang.47000.json','["舉世都爲名利醉，伊予獨向道中醒。", "他時定是飛昇去，衝破秋空一點青。"]'),
('0ba7295a-ca56-4e31-adc0-b0cab16f8e9b','題院詩','侯道華','唐','唐诗','tang','','[]','帖裏大還丹，多年色不移。',72,'全唐诗/poet.tang.47000.json','["帖裏大還丹，多年色不移。", "前宵盜喫却，今日碧空飛。", "慙媿深珍重，珍重鄧天師。", "他年煉得藥，留著與內芝。", "吾師知此術，速煉莫爲遲。", "三清專相待，大羅的有期。"]'),
('6130942b-218b-4584-a334-049c2950f64b','贈樊夫人詩','裴航','唐','唐诗','tang','','[]','向爲胡越猶懷想，況遇天仙隔錦屏。',32,'全唐诗/poet.tang.47000.json','["向爲胡越猶懷想，況遇天仙隔錦屏。", "儻若玉京朝會去，願隨鸞鶴入青冥。"]'),
('a2d8d73a-2b9f-444c-8c67-d803f262e04e','樊夫人荅裴航','裴航','唐','唐诗','tang','','[]','一飲瓊漿百感生，玄霜擣盡見雲英。',32,'全唐诗/poet.tang.47000.json','["一飲瓊漿百感生，玄霜擣盡見雲英。", "藍橋便是神仙窟，何必崎嶇上玉清。"]'),
('b9a7b498-a5e4-495e-a8d9-34e64ecd9a09','題長安酒肆壁三絕句 一','鍾離權','唐','唐诗','tang','','[]','坐臥常攜酒一壺，不教雙眼識皇都。',32,'全唐诗/poet.tang.47000.json','["坐臥常攜酒一壺，不教雙眼識皇都。", "乾坤許大無名姓，疎散人中一丈夫。"]'),
('2685b5a6-273d-4d98-ac61-d8a17a4ff331','題長安酒肆壁三絕句 二','鍾離權','唐','唐诗','tang','','[]','得道高僧不易逢，幾時歸去願相從。',32,'全唐诗/poet.tang.47000.json','["得道高僧不易逢，幾時歸去願相從。", "自言住處連滄海，別是蓬萊第一峯。"]'),
('7de51a0d-3b6c-46ec-b032-b85de06e27f8','題長安酒肆壁三絕句 三','鍾離權','唐','唐诗','tang','','[]','莫厭追歡笑語頻，尋思離亂好傷神。',32,'全唐诗/poet.tang.47000.json','["莫厭追歡笑語頻，尋思離亂好傷神。", "閑來屈指從頭數，得見清平有幾人。"]'),
('d0e43db3-3677-4065-80af-2ff7b563df6b','贈呂洞賓','鍾離權','唐','唐诗','tang','','[]','知君幸有英靈骨，所以教君心恍惚。',238,'全唐诗/poet.tang.47000.json','["知君幸有英靈骨，所以教君心恍惚。", "含元殿上水晶宮，分明指出神仙窟。", "大丈夫，遇真訣，須要執持心猛烈。", "五行匹配自刀圭，執取龜蛇顛倒訣。", "三尸神，須打徹，進退天機明六甲。", "知此三要萬神歸，來駕火龍離九闕。", "九九道至成真日，三界四府朝元節。", "氣翱翔兮神烜赫，蓬萊便是吾家宅。", "羣仙會飲天樂喧，雙童引入昇玄客。", "道心不退故傳君，立誓約言親灑血。", "逢人兮莫亂說，遇友兮不須訣。", "莫怪頻發此言辭，輕慢必有陰司折。", "執手相別意如何，今日爲君重作歌。", "說盡千般玄妙理，未必君心信也麽。", "子後分明說與汝，保惜吾言上大羅。"]'),
('b77783c9-fc25-49f0-af73-3c89891edaea','登杭州秦望山','馬湘','唐','唐诗','tang','','[]','太乙初分何處尋，空留曆數變人心。',64,'全唐诗/poet.tang.47000.json','["太乙初分何處尋，空留曆數變人心。", "九天日月移朝暮，萬里山川換古今。", "風動水光吞遠嶠，雨添嵐氣沒高林。", "秦皇謾作驅山計，滄海茫茫轉更深。"]'),
('8f88b6f4-aabc-4198-9c66-a22ba210b374','題龍興觀壁','馬湘','唐','唐诗','tang','','[]','世有無窮事，生知遂百春。',24,'全唐诗/poet.tang.47000.json','["世有無窮事，生知遂百春。", "問程方外路，宜是上清人。"]'),
('e36ed1fb-1d31-4f9f-858f-fd003ab9fb5f','又詩一首','馬湘','唐','唐诗','tang','','[]','昔日曾隨魏伯陽，無端醉臥紫金牀。',32,'全唐诗/poet.tang.47000.json','["昔日曾隨魏伯陽，無端醉臥紫金牀。", "東君謂我多情賴，罰向人間作酒狂。"]'),
('dc9f7620-35b9-4737-b3c9-87db3f0c2860','又詩二首 一','馬湘','唐','唐诗','tang','','[]','省悟前非一息間，更拋閑事棄塵寰。',64,'全唐诗/poet.tang.47000.json','["省悟前非一息間，更拋閑事棄塵寰。", "徒誇美酒如瓊液，休戀嬌娥似玉顏。", "含笑謾教情面厚，多愁還使鬢毛斑。", "雲中幸有堪歸路，無限青山是我山。"]'),
('b0c05631-ea67-4273-ba77-c77f78e60eed','又詩二首 二','馬湘','唐','唐诗','tang','','[]','何用燒丹學駐顏，鬧非城市靜非山。',32,'全唐诗/poet.tang.47000.json','["何用燒丹學駐顏，鬧非城市靜非山。", "時人若覓長生藥，對景無心是大還。"]'),
('ba0902eb-22cb-4639-b618-a5a83c4d8567','題壁','張辭','唐','唐诗','tang','','[]','爭那金烏何，頭上飛不住。',48,'全唐诗/poet.tang.47000.json','["爭那金烏何，頭上飛不住。", "紅爐漫燒藥，玉顏安可駐。", "今年花發枝，明年葉落樹。", "不如且飲酒，莫管流年度。"]'),
('2469960f-96e9-4ade-8e94-bcb666d30843','上鹽城令述德詩','張辭','唐','唐诗','tang','','[]','門風常有蕙蘭馨，鼎族家傳霸國名。',64,'全唐诗/poet.tang.47000.json','["門風常有蕙蘭馨，鼎族家傳霸國名。", "容貌靜懸秋月彩，文章高振海濤聲。", "訟堂無事調琴軫，郡閣何妨醉玉觥。", "今日東漸橋下水，一條從此鎮常清。"]'),
('91c8d669-ff49-4b68-9104-1406c1ff9e02','謝令學道詩','張辭','唐','唐诗','tang','','[]','何用梯媒向外求，長生只合內中修。',32,'全唐诗/poet.tang.47000.json','["何用梯媒向外求，長生只合內中修。", "莫言大道人難得，自是行心不到頭。"]'),
('12c16ee6-926f-4146-8d53-108011c822e0','別令詩','張辭','唐','唐诗','tang','','[]','張辭張辭自不會，天下經書在腹內。',32,'全唐诗/poet.tang.47000.json','["張辭張辭自不會，天下經書在腹內。", "身即騰騰處世間，心即逍遙出天外。"]'),
('701b58d5-3979-4156-b90b-73dbe335718e','贈吳生','陸禹臣','唐','唐诗','tang','','[]','露下瑤簪濕，雲生石室寒。',24,'全唐诗/poet.tang.47000.json','["露下瑤簪濕，雲生石室寒。", "星壇鸞鶴舞，丹竈虎龍蟠。"]'),
('e24ae6f4-b533-4057-a1f4-06b01bd1c8b6','丈人山詩','李真','唐','唐诗','tang','','[]','春凍曉韉露重，夜寒幽枕雲生。',28,'全唐诗/poet.tang.47000.json','["春凍曉韉露重，夜寒幽枕雲生。", "豈是與山無素，丈人著帽相迎。"]'),
('151dddf6-9644-48e4-9970-e3bdc0b29293','醉歌','殷七七','唐','唐诗','tang','','[]','琴彈碧玉調，藥鍊白硃砂。',24,'全唐诗/poet.tang.47000.json','["琴彈碧玉調，藥鍊白硃砂。", "解醞頃刻酒，能開非時花。"]'),
('ae09fd4b-5a05-4f49-8baa-92b272ba133a','陽春曲','殷七七','唐','唐诗','tang','','[]','愁見唱陽春，令人離腸結。',24,'全唐诗/poet.tang.47000.json','["愁見唱陽春，令人離腸結。", "郎去未歸家，柳自飄香雪。"]'),
('74692b7f-e682-449f-bd73-51a04358018f','寄杜光庭','張令問','唐','唐诗','tang','','[]','試問朝中爲宰相，何如林下作神仙。',32,'全唐诗/poet.tang.47000.json','["試問朝中爲宰相，何如林下作神仙。", "一壺美酒一爐藥，飽聽松風清晝眠。"]'),
('49c4e70b-35d7-45c8-8977-9fdbce83f51f','上昇歌','吳涵虛','唐','唐诗','tang','','[]','玉皇有詔登仙職，龍吐雲兮鳳著力。',64,'全唐诗/poet.tang.47000.json','["玉皇有詔登仙職，龍吐雲兮鳳著力。", "眼前驀地見樓臺，異草奇花不可識。", "我向大羅觀世界，世界即如指掌大。", "當時不爲上昇忙，一時提向瀛洲賣。"]'),
('22dc0b13-2b20-49aa-bd3b-4a3eab8282a0','荅常學士','李夢符','唐','唐诗','tang','','[]','罷修儒業罷修真，養拙藏愚春復春。',64,'全唐诗/poet.tang.47000.json','["罷修儒業罷修真，養拙藏愚春復春。", "到老不疎林裏鹿，平生難見日邊人。", "洞桃深處千林錦，巖雪鋪時萬草新。", "深謝名賢遠相訪，求聞難博鳳爲鄰。"]'),
('08bc5154-ff91-4308-9b25-134908d248d4','漁父引二首 一','李夢符','唐','唐诗','tang','','[]','林寺鐘聲度遠灘，半輪殘月落山前。',32,'全唐诗/poet.tang.47000.json','["林寺鐘聲度遠灘，半輪殘月落山前。", "徐徐撥櫂却歸灣，浪疊朝霞錦繡翻。"]'),
('9feb4c7d-1c88-44ab-8666-3cd1060909fa','漁父引二首 二','李夢符','唐','唐诗','tang','','[]','漁弟漁兄喜到來，波官賽却坐江隈。',32,'全唐诗/poet.tang.47000.json','["漁弟漁兄喜到來，波官賽却坐江隈。", "椰榆杓子木瘤杯，爛煮鱸魚滿案堆。"]'),
('911e1eb6-40c9-45f9-825c-abf101e0a5de','察考取狀荅','李夢符','唐','唐诗','tang','','[]','插花飲酒何妨事，樵唱漁歌不礙時。',16,'全唐诗/poet.tang.47000.json','["插花飲酒何妨事，樵唱漁歌不礙時。"]'),
('f3fa47cf-53a2-4ebd-b366-acfe05c8557d','荅高安宰','沈廷瑞','唐','唐诗','tang','','[]','何須問我道成時，紫府清都自有期。',32,'全唐诗/poet.tang.47000.json','["何須問我道成時，紫府清都自有期。", "手握藥苗人不識，體含金骨俗爭知。"]'),
('59daa901-97e9-402c-88d1-e872aecdf66a','贈僧昭瑩','沈廷瑞','唐','唐诗','tang','','[]','南北東西路，人生會不無。',48,'全唐诗/poet.tang.47000.json','["南北東西路，人生會不無。", "早曾依閣皂，又却上玄都。", "雲片隨天闊，泉聲落石孤。", "何期早相遇，樂共煮菖蒲。"]'),
('19c256fd-7ab9-46ee-9820-d2130d4f1a90','寄袁州陳智周','沈廷瑞','唐','唐诗','tang','','[]','名山相別後，別後會難期。',48,'全唐诗/poet.tang.47000.json','["名山相別後，別後會難期。", "金鼎銷紅日，丹田老紫芝。", "訪君雖有路，懷我豈無詩。", "休羨繁華事，百年能幾時。"]'),
('38023806-187f-4330-ab5e-c855138f78cc','壟穴遺詩','沈廷瑞','唐','唐诗','tang','','[]','虛勞營殯玉山前，殯後那知已脫蟬。',64,'全唐诗/poet.tang.47000.json','["虛勞營殯玉山前，殯後那知已脫蟬。", "應是元神歸洞府，更無遺魄在黃泉。", "靈臺已得修真訣，塵世空留悟道篇。", "堪歎浮生今古事，北邙山下草芊芊。"]'),
('13265525-1365-43f6-805d-2a9ca38051e5','大言詩','譚峭','唐','唐诗','tang','','["\u957f\u6c5f"]','線作長江扇作天，靸鞵拋向海東邊。',32,'全唐诗/poet.tang.47000.json','["線作長江扇作天，靸鞵拋向海東邊。", "蓬萊信道無多路，只在譚生拄杖前。"]'),
('89ab7f2b-ca9d-4dd1-8dd8-868ed3b897f7','大言詩','譚峭','唐','唐诗','tang','','["\u957f\u6c5f"]','線大長江扇大天，屐鞋抛在海東邉。',32,'全唐诗/poet.tang.47000.json','["線大長江扇大天，屐鞋抛在海東邉。", "世間多少閒蟲豸，盡在郯生柱杖前。"]'),
('f178f79d-49d0-4718-ab4b-0766bebff106','句','譚峭','唐','唐诗','tang','','[]','雲外星霜如走電，世間娛樂似拋磚。',16,'全唐诗/poet.tang.47000.json','["雲外星霜如走電，世間娛樂似拋磚。"]'),
('c3187489-b4b9-463e-90cd-6a1a6b886bb6','望江南詞詠鼓','伊用昌','唐','唐诗','tang','','[]','江南鼓，梭肚兩頭欒。',32,'全唐诗/poet.tang.47000.json','["江南鼓，梭肚兩頭欒。", "釘著不知侵骨髓，打來只是沒心肝，空腹被人謾。"]'),
('11384e72-8496-49fb-9e75-bb9b7e5f75ae','題茶陵縣門','伊用昌','唐','唐诗','tang','','[]','茶陵一道好長街，兩畔栽柳不栽槐。',32,'全唐诗/poet.tang.47000.json','["茶陵一道好長街，兩畔栽柳不栽槐。", "夜後不聞更漏鼓，只聽鎚芒織草鞋。"]'),
('770a3699-aaaf-4d82-9365-ea98a7e11eb4','題酒樓壁','伊用昌','唐','唐诗','tang','','[]','此生生在此生先，何事從玄不復玄。',32,'全唐诗/poet.tang.47000.json','["此生生在此生先，何事從玄不復玄。", "已在淮南雞犬後，而今便到玉皇前。"]'),
('82428546-4568-4fc9-a9d2-904138ce7b1e','題遊帷觀真君殿後','伊用昌','唐','唐诗','tang','','[]','日日祥雲瑞氣連，儂家應作大神仙。',64,'全唐诗/poet.tang.47000.json','["日日祥雲瑞氣連，儂家應作大神仙。", "筆頭灑起風雷力，劒下驅馳造化權。", "更與戎夷添禮樂，永教胡虜絕烽煙。", "列仙功業只如此，直上三清第一天。"]'),
('757347e0-66d3-4dca-aec4-27375416c9e0','留題閣皂觀','伊用昌','唐','唐诗','tang','','[]','花洞門前吠似雷，險聲流斷俗塵埃。',64,'全唐诗/poet.tang.47000.json','["花洞門前吠似雷，險聲流斷俗塵埃。", "雨噴山脚毒龍起，月照松梢孤鶴回。", "蘿幕秋高添碧翠，畫簾時捲到樓臺。", "兩壇詩客何年去，去後門關更不開。"]'),
('5311947c-cc06-45fa-a3b9-6903b6ba3196','湖南闖齋吟','伊用昌','唐','唐诗','tang','','[]','誰人能識白元君，上士由來盡見聞。',64,'全唐诗/poet.tang.47000.json','["誰人能識白元君，上士由來盡見聞。", "避世早空南火宅，植田高種北山雲。", "雞能抱卵心常聽，蟬到成形殼自分。", "學取大羅些子術，免教松下作孤墳。"]'),
('029cd8ac-1e4f-49b9-a96f-44f386cef74b','游溧陽霞泉寺限白字','許堅','唐','唐诗','tang','','[]','近枕吳溪與越峰，前朝恩賜雲泉額。',64,'全唐诗/poet.tang.47000.json','["近枕吳溪與越峰，前朝恩賜雲泉額。", "竹林晴見鴈塔高，石室曾棲幾禪伯。", "荒碑字沒莓苔深，古池香泛荷花白。", "客有經年別故林，落日啼猨情脉脉。"]'),
('4f01eac0-5610-492a-96fc-92724fefeb05','幽棲觀','許堅','唐','唐诗','tang','','[]','仙翁上昇去，丹井寄晴壑。',48,'全唐诗/poet.tang.47000.json','["仙翁上昇去，丹井寄晴壑。", "山色接天台，湖光照寥廓。", "玉洞絕無人，老檜猶棲鶴。", "我欲掣青蛇，他時沖碧落。"]'),
('e344500b-6f32-40d0-a033-8ec28957d131','題茅山觀','許堅','唐','唐诗','tang','','[]','嘗恨清風千載鬱，洞天今得恣遊遨。',64,'全唐诗/poet.tang.47000.json','["嘗恨清風千載鬱，洞天今得恣遊遨。", "松楸一色古壇靜，鸞鶴不來青漢高。", "茅氏井寒丹已化，玄宗碑斷夢仍勞。", "分明有箇長生路，休向紅塵歎二毛。"]'),
('adb75de9-d138-49e1-b555-aa47f02d6c93','題扇','許堅','唐','唐诗','tang','','[]','哦吟但寫胸中妙，飲酒能忘身後名。',32,'全唐诗/poet.tang.47000.json','["哦吟但寫胸中妙，飲酒能忘身後名。", "但願長閑有詩酒，一溪風月共清明。"]'),
('d9ab3503-da82-4e82-8f94-eaff0d5c5748','上徐舍人鉉','許堅','唐','唐诗','tang','','[]','幾宵煙月鎖樓臺，欲寄侯門薦禰才。',32,'全唐诗/poet.tang.47000.json','["幾宵煙月鎖樓臺，欲寄侯門薦禰才。", "滿面塵埃人不識，謾隨流水出山來。"]'),
('8acf6436-7fa8-4831-b6a4-643280964e1f','句','許堅','唐','唐诗','tang','','[]','道既學不得，仙從何處來？臥久似慵伸雪項，立遲猶未整霜衣。',28,'全唐诗/poet.tang.47000.json','["道既學不得，仙從何處來？臥久似慵伸雪項，立遲猶未整霜衣。"]'),
('54ee1fb5-a686-4bc9-bf8d-831e5753a700','醉吟','許碏','唐','唐诗','tang','','[]','閬苑花前是醉鄉，踏翻王母九霞觴。',32,'全唐诗/poet.tang.47000.json','["閬苑花前是醉鄉，踏翻王母九霞觴。", "羣仙拍手嫌輕薄，謫向人間作酒狂。"]'),
('2d45e348-8d73-492c-9bb5-f861401edfc3','題南嶽招仙觀壁上','許碏','唐','唐诗','tang','','["\u8861\u5c71"]','洪鑪烹鍛人性命，器用不同分皆定。',112,'全唐诗/poet.tang.47000.json','["洪鑪烹鍛人性命，器用不同分皆定。", "妖精鬼魅鬬神通，只自干邪不干正。", "黃口小兒初學行，唯知日月東西生。", "還爲萬靈威聖力，移月在南日在北。", "玉爲玉兮石是石，蘊棄深泥終不易。", "鄧通餓死嚴陵貧，帝王豈是無人力。", "丈夫未達莫相侵，攀龍附鳳捐精神。"]'),
('5af4e1b7-02c6-44e2-b16e-08300d1adbbe','武陵春色','張白','唐','唐诗','tang','','[]','武陵春色好，十二酒家樓。',48,'全唐诗/poet.tang.47000.json','["武陵春色好，十二酒家樓。", "大醉方回首，逢人不舉頭。", "是非都不采，名利混然休。", "戴箇星冠子，浮沈逐世流。"]'),
('f5f95c75-54d3-4704-9de9-dba4496547f4','贈酒店崔氏','張白','唐','唐诗','tang','','[]','武陵城裏崔家酒，地上應無天上有。',32,'全唐诗/poet.tang.47000.json','["武陵城裏崔家酒，地上應無天上有。", "南遊道士飲一斗，臥向白雲深洞口。"]'),
('c7498f96-bf20-487e-8848-e869dcedc134','哭陸先生','張白','唐','唐诗','tang','','[]','六親慟哭還復蘇，我笑先生淚箇無。',32,'全唐诗/poet.tang.47000.json','["六親慟哭還復蘇，我笑先生淚箇無。", "脫履定歸天上去，空墳留入武陵圖。"]'),
('d7428746-e5a0-4882-8a85-b76b89f1c015','市中狂吟','段穀','唐','唐诗','tang','','[]','一間茅屋，尚自修治。',46,'全唐诗/poet.tang.47000.json','["一間茅屋，尚自修治。", "任狂風吹，連簷破碎。", "枓栱斜欹，看著倒也。", "牆壁作散土一堆，主人翁永不來歸。"]'),
('cf1aab6d-94f2-469f-8748-f42fba97aea9','詩','趙自然','唐','唐诗','tang','','[]','常欲棲山島，閑眠玉洞寒。',24,'全唐诗/poet.tang.47000.json','["常欲棲山島，閑眠玉洞寒。", "丹哥時引舞，來去跨雲鸞。"]'),
('fbb6044a-62c2-43ca-b244-76bee822f232','大丹詩四首 一','李浩','唐','唐诗','tang','','[]','混沌未分我獨存，包含四象立乾坤。',32,'全唐诗/poet.tang.47000.json','["混沌未分我獨存，包含四象立乾坤。", "還丹須向此中覓，得此方爲至妙門。"]'),
('755328d6-8ae0-495e-ae31-0377b3f8f6fc','大丹詩四首 二','李浩','唐','唐诗','tang','','[]','煮石烹金煉太元，神仙不肯等閑傳。',32,'全唐诗/poet.tang.47000.json','["煮石烹金煉太元，神仙不肯等閑傳。", "人能認得其中理，奪盡乾坤造化權。"]'),
('07b1b651-8200-4b28-b666-edfe638460cb','大丹詩四首 三','李浩','唐','唐诗','tang','','[]','百首荒辭義亦深，因傳同道決疑心。',32,'全唐诗/poet.tang.47000.json','["百首荒辭義亦深，因傳同道決疑心。", "華池本是真神水，神水元來是白金。"]'),
('ae12a93d-7147-4aa8-a375-1dad3b24a46c','大丹詩四首 四','李浩','唐','唐诗','tang','','[]','取將白金爲鼎器，鼎成潛伏汞來侵。',32,'全唐诗/poet.tang.47000.json','["取將白金爲鼎器，鼎成潛伏汞來侵。", "汞入金鼎終年盡，產出靈砂似太陰。"]'),
('c01c75d6-9182-4429-8e42-1ab52d7e45a5','自吟','徐釣者','唐','唐诗','tang','','[]','曾見秦皇架石橋，海神忙迫漲驚潮。',32,'全唐诗/poet.tang.47000.json','["曾見秦皇架石橋，海神忙迫漲驚潮。", "蓬萊隔海雖難到，直上三清却不遙。"]'),
('d8b3c234-7cd9-4ab4-a001-4d57fa62c592','踏歌','藍采和','唐','唐诗','tang','','[]','踏歌踏歌藍采和，世界能幾何。',74,'全唐诗/poet.tang.47000.json','["踏歌踏歌藍采和，世界能幾何。", "紅顏三春樹，流年一擲梭。", "古人混混去不返，今人紛紛來更多。", "朝騎鸞鳳到碧落，暮見桑田生白波。", "長景明暉在空際，金銀宮闕高嵯峨。"]'),
('7bbe42bc-0412-46ec-b8e1-a58ae1f4d95e','同沈恭子遊虎丘寺有作','清遠道士','唐','唐诗','tang','','[]','我本長殷周，遭罹歷秦漢。',144,'全唐诗/poet.tang.47000.json','["我本長殷周，遭罹歷秦漢。", "四瀆與五嶽，名山盡幽竄。", "及此寰區中，始有近峰翫。", "近峰何鬱鬱，平湖渺瀰漫。", "吟俯川之陰，步上山之岸。", "山川共澄澈，光彩交凌亂。", "白雲蓊欲歸，青松忽消半。", "客去川島靜，人來山鳥散。", "谷深中見日，崖幽曉非旦。", "聞子盛遊遨，風流足詞翰。", "嘉茲好松石，一言常累嘆。", "勿謂余鬼神，忻君共幽贊。"]'),
('5e11e9ac-3f88-4891-903f-1fa15b16e46f','遊春臺詩 一','春臺仙','唐','唐诗','tang','','[]','玉幢亘碧虛，此乃真人居。',24,'全唐诗/poet.tang.47000.json','["玉幢亘碧虛，此乃真人居。", "裴回仍未進，邪省猶難除。"]'),
('bc2a766e-12b5-48b0-a013-cb7b703e87a6','遊春臺詩 二','春臺仙','唐','唐诗','tang','','[]','日落煙水黯，驪珠色豈昏。',24,'全唐诗/poet.tang.47000.json','["日落煙水黯，驪珠色豈昏。", "寒光射萬里，霜縞遍千門。"]'),
('1c5ac119-58ff-4416-85f7-3e5cc6d77e46','遊春臺詩 三','春臺仙','唐','唐诗','tang','','[]','玉魄東方開，嫦娥逐影來。',24,'全唐诗/poet.tang.47000.json','["玉魄東方開，嫦娥逐影來。", "洗心兼滌目，怳若遊春臺。"]'),
('64069405-dd7d-4745-b1c1-9cef66185a84','遊春臺詩 四','春臺仙','唐','唐诗','tang','','[]','清波滔碧天，烏藏黯黮連。',24,'全唐诗/poet.tang.47000.json','["清波滔碧天，烏藏黯黮連。", "二儀不辨處，忽吐清光圓。"]'),
('b3405e8f-7046-4d8c-adb6-00179a11d247','遊春臺詩 五','春臺仙','唐','唐诗','tang','','[]','烏沈海西岸，蟾吐天東頭。',12,'全唐诗/poet.tang.47000.json','["烏沈海西岸，蟾吐天東頭。"]'),
('e095f4c2-a53c-44b8-a3ec-32dc4091e0c0','遊春臺詩 六','春臺仙','唐','唐诗','tang','','[]','鳳凰三十六，碧天高太清。',28,'全唐诗/poet.tang.47000.json','["鳳凰三十六，碧天高太清。", "元君夫人蹋雲語，冷風颯颯吹鵝笙。"]'),
('a13f9d44-c003-4e31-9b8c-754bac6316ca','醉吟','酒肆布衣','唐','唐诗','tang','','[]','陽春時節天氣和，萬物芳盛人如何。',64,'全唐诗/poet.tang.47000.json','["陽春時節天氣和，萬物芳盛人如何。", "素秋時節天地肅，榮秀叢林立衰促。", "有同人世當少年，壯心儀貌皆儼然。", "一旦形羸又髮白，舊遊空使淚連連。"]'),
('8bd6bf69-f889-404e-81cd-0ffeafc12703','又吟','酒肆布衣','唐','唐诗','tang','','[]','有形皆朽孰不知，休吟春景與秋時。',32,'全唐诗/poet.tang.47000.json','["有形皆朽孰不知，休吟春景與秋時。", "爭如且醉長安酒，榮華零悴總奚爲。"]'),
('1351909f-b4e7-40ce-a690-1d1d197c1799','嫁女詩 一','嵩嶽諸仙','唐','唐诗','tang','','[]','勸君酒，爲君悲且吟。',26,'全唐诗/poet.tang.47000.json','["勸君酒，爲君悲且吟。", "自從頻見市朝改，無復瑤池宴樂心。"]'),
('fa8ff655-ce5a-4aaf-8020-eb6b25a5031e','嫁女詩 二','嵩嶽諸仙','唐','唐诗','tang','','[]','奉君酒，休嘆市朝非。',26,'全唐诗/poet.tang.47000.json','["奉君酒，休嘆市朝非。", "早知無復瑤池興，悔駕驊騮草草歸。"]'),
('cf5cc0be-253a-4c2c-b2e3-bb4547ce3707','嫁女詩 三','嵩嶽諸仙','唐','唐诗','tang','','[]','八馬迴乘汗漫風，猶思往事憩昭宮。',64,'全唐诗/poet.tang.47000.json','["八馬迴乘汗漫風，猶思往事憩昭宮。", "宴移玄圃情方洽，樂奏鈞天曲未終。", "斜漢露凝殘月冷，流霞杯泛曙光紅。", "崑崙回首不知處，疑是酒酣魂夢中。"]'),
('063483cc-84e5-4744-8ee7-ece291ccee2e','嫁女詩 四','嵩嶽諸仙','唐','唐诗','tang','','[]','一曲笙歌瑤水濱，曾留逸足駐征輪。',64,'全唐诗/poet.tang.47000.json','["一曲笙歌瑤水濱，曾留逸足駐征輪。", "人間甲子週千歲，靈境杯觴初一巡。", "玉兔銀河終不夜，奇花好樹鎮長春。", "悄知碧海饒詞句，歌向俗流疑誤人。"]'),
('a4301493-2219-4e5a-ab4b-0272c4773196','嫁女詩 五','嵩嶽諸仙','唐','唐诗','tang','','[]','珠露金風下界秋，漢家陵樹冷脩脩。',32,'全唐诗/poet.tang.47000.json','["珠露金風下界秋，漢家陵樹冷脩脩。", "當時不得仙桃力，尋作浮塵飄隴頭。"]'),
('533fd12d-45c9-4a3a-a295-14ac997ddf7d','嫁女詩 六','嵩嶽諸仙','唐','唐诗','tang','','[]','五十餘年四海清，自親丹藥得長生。',32,'全唐诗/poet.tang.47000.json','["五十餘年四海清，自親丹藥得長生。", "若言盡是仙桃力，看取神仙簿上名。"]'),
('9f4d2800-7e04-4363-822c-68f231e6955a','嫁女詩 七','嵩嶽諸仙','唐','唐诗','tang','','[]','月照驪山露泣花，似悲先帝早昇遐。',32,'全唐诗/poet.tang.47000.json','["月照驪山露泣花，似悲先帝早昇遐。", "至今猶有長生鹿，時遶溫泉望翠華。"]'),
('450aa66d-85e8-4233-ae45-2b245b69ebcf','嫁女詩 八','嵩嶽諸仙','唐','唐诗','tang','','[]','幽薊煙塵別九重，貴妃湯殿罷歌鐘。',64,'全唐诗/poet.tang.47000.json','["幽薊煙塵別九重，貴妃湯殿罷歌鐘。", "中宵扈從無全杖，大駕蒼黃發六龍。", "妝匣尚留金翡翠，暖池猶浸玉芙蓉。", "荆榛一閉朝元路，唯有悲風吹晚松。"]'),
('38880671-e1c7-4c4a-a793-59c8a983b551','嫁女詩 九','嵩嶽諸仙','唐','唐诗','tang','','[]','上清神女，玉京仙郎。',40,'全唐诗/poet.tang.47000.json','["上清神女，玉京仙郎。", "樂此今夕，和鳴鳳凰。", "鳳凰和鳴，將翱將翔。", "與天齊休，慶流無央。"]'),
('52cb1bfd-de19-49dd-9e67-05bea3195c8d','嫁女詩 十','嵩嶽諸仙','唐','唐诗','tang','','[]','玉爲質兮花爲顏，蟬爲鬢兮雲爲鬟。',34,'全唐诗/poet.tang.47000.json','["玉爲質兮花爲顏，蟬爲鬢兮雲爲鬟。", "何勞傅粉兮施渥丹，早出娉婷兮縹緲間。"]'),
('ff86a73d-8b4f-4479-a406-b2448c64cfa1','嫁女詩 十一','嵩嶽諸仙','唐','唐诗','tang','','[]','水晶帳開銀燭明，風搖珠珮連雲清。',32,'全唐诗/poet.tang.47000.json','["水晶帳開銀燭明，風搖珠珮連雲清。", "休勻紅粉飾花態，早駕雙鸞朝玉京。"]'),
('49ac397c-37de-485d-8187-447f37a27200','嫁女詩 十二','嵩嶽諸仙','唐','唐诗','tang','','[]','三星在天銀河迴，人間曙色東方來。',32,'全唐诗/poet.tang.47000.json','["三星在天銀河迴，人間曙色東方來。", "玉苗瓊蕊亦宜夜，莫使一花衝曉開。"]'),
('b5618c22-4c31-4d2d-953f-0defc39fbb45','吟 一','芙蓉古丈夫　毛女','唐','唐诗','tang','','[]','餌柏身輕疊嶂間，是非無意到塵寰。',32,'全唐诗/poet.tang.47000.json','["餌柏身輕疊嶂間，是非無意到塵寰。", "冠裳暫備論浮世，一餉雲遊碧落間。"]'),
('3ae38509-509e-47a6-aabd-a7c8754cb5ac','吟 二','芙蓉古丈夫　毛女','唐','唐诗','tang','','[]','誰知古是與今非，閑躡青霞與翠微。',32,'全唐诗/poet.tang.47000.json','["誰知古是與今非，閑躡青霞與翠微。", "簫管秦樓應寂寂，彩雲空惹薜蘿衣。"]'),
('337c322e-6d63-449d-ad4e-06b51857913e','授炙轂子歌二首 一','希道','唐','唐诗','tang','','[]','木津天魂，金液地魄。',38,'全唐诗/poet.tang.47000.json','["木津天魂，金液地魄。", "坎離運行寬無成，金木有數秦晉合。", "近効宜六旬，遠期三載闊。"]'),
('cf4f6b0e-d404-4189-a02b-f1495a3b69e7','授炙轂子歌二首 二','希道','唐','唐诗','tang','','[]','魄微入魂牝牡結，陽呴陰滋神鬼滅。',32,'全唐诗/poet.tang.47000.json','["魄微入魂牝牡結，陽呴陰滋神鬼滅。", "千歌萬讚皆未決，古往今來拋日月。"]'),
('4f8c2bb6-8a4a-4be1-87cd-54807999f16f','李泌庭黑石詩','隱者','唐','唐诗','tang','','[]','神真鍊形年未足，化爲我子功相續。',32,'全唐诗/poet.tang.47000.json','["神真鍊形年未足，化爲我子功相續。", "丞相瘞之刻玄玉，仙路何長死何促。"]'),
('4baf8178-97f7-4e0c-be1c-025d5a6931a8','戲吟','廣陵道士','唐','唐诗','tang','','[]','無事到揚州，相攜上酒樓。',24,'全唐诗/poet.tang.47000.json','["無事到揚州，相攜上酒樓。", "藥囊爲贈別，千載更何求。"]'),
('eeb950ba-8c7b-4aad-926f-4a2a22fe4c13','授馬氏女詩','黃冠野夫','唐','唐诗','tang','','[]','女是寄生枝，男是冬青木。',48,'全唐诗/poet.tang.47000.json','["女是寄生枝，男是冬青木。", "冬青駕白鵝，寄生跨黃鹿。", "若遇寇相凌，穩便拋家族。", "早早上三清，莫候丹砂熟。"]'),
('18ef8ed5-8172-4253-9845-e5920076cb47','歌','蜀中酒閣道人','唐','唐诗','tang','','[]','尾閭不禁滄溟竭，九轉神丹都謾說。',32,'全唐诗/poet.tang.47000.json','["尾閭不禁滄溟竭，九轉神丹都謾說。", "惟有班龍頂上珠，能補玉堂關下穴。"]'),
('f43708d2-ea9b-4a67-b8aa-7229835c2036','吟','章江書生','唐','唐诗','tang','','[]','西去長沙東上船，思量此事已千年。',32,'全唐诗/poet.tang.47000.json','["西去長沙東上船，思量此事已千年。", "長春殿掩無人掃，滿眼梨花哭杜鵑。"]'),
('c1dddb66-ccc3-43b1-ac6a-ddd1b9001d20','示邊洞元','萼嶺書生','唐','唐诗','tang','','[]','邂逅相逢萼嶺邊，對傾浮蟻共談玄。',32,'全唐诗/poet.tang.47000.json','["邂逅相逢萼嶺邊，對傾浮蟻共談玄。", "擬將劒法親傳授，却爲迷人未有緣。"]'),
('61ed6d48-5c52-4ca3-b1ee-6fe17cd73101','示胡二郎歌','成都醉道士','唐','唐诗','tang','','[]','欲究丹砂理，幽玄無處尋。',184,'全唐诗/poet.tang.47000.json','["欲究丹砂理，幽玄無處尋。", "不離鉛與汞，無出水中金。", "金欲煉時須得水，水遇土兮終不起。", "但知火候不參差，自得還丹微妙旨。", "人世分明知有死，剛只留心戀朱紫。", "豈知光景片時間，將謂人生長似此。", "何不迴心師至道？免逐年光虛自老。", "臨樽只解醉醺酣，對鏡方知漸枯槁。", "二郎切切聽我語，仙鄉咫尺無寒暑。", "與君說盡只如斯，莫戀嬌奢不肯去。", "感君恩義言方苦，火急迴心求出路。", "吟成數句贈君辭，不覺便成今與古。"]'),
('ea5cd8f3-6231-4f39-9b20-ac738434e4e7','貽白永年詩','樵夫','唐','唐诗','tang','','[]','清秋無所事，乘露出遙天。',24,'全唐诗/poet.tang.47000.json','["清秋無所事，乘露出遙天。", "憑杖樵人語，相期白永年。"]'),
('776e7e9f-f5de-4ebf-ab98-20b301a94a74','留詩','李公佐僕','唐','唐诗','tang','','[]','我有衣中珠，不嫌衣上塵。',72,'全唐诗/poet.tang.47000.json','["我有衣中珠，不嫌衣上塵。", "我有長生理，不厭有生身。", "江南神仙窟，吾當混其真。", "不嫌市井諠，來救世間人。", "蘇子跡已往，顓蒙事可親。", "莫言東海變，天地有長春。"]'),
('2615c5d4-457d-42fc-816f-82bb85b0bbed','酒盡君莫沽','木客','唐','唐诗','tang','','[]','酒盡君莫沽，壺傾我當發。',24,'全唐诗/poet.tang.47000.json','["酒盡君莫沽，壺傾我當發。", "城市多囂塵，還山弄明月。"]'),
