('8c1545e3-905f-43de-858c-98374a6b76d9','宴柳毅詩 一','洞庭龍君','唐','唐诗','tang','','[]','大天蒼蒼兮大地茫茫，人各有志兮何可思量。',65,'全唐诗/poet.tang.47000.json','["大天蒼蒼兮大地茫茫，人各有志兮何可思量。", "狐神鼠聖兮薄社依牆，雷霆一發兮其孰敢當。", "荷貞人兮信義長，令骨肉兮還故鄉，永言慚愧兮何時忘。"]'),
('7d050685-8416-4e78-a6ac-096fe27fded1','宴柳毅詩 二','洞庭龍君','唐','唐诗','tang','','[]','上天配合兮生死有途，此不當婦兮彼不當夫。',65,'全唐诗/poet.tang.47000.json','["上天配合兮生死有途，此不當婦兮彼不當夫。", "腹心辛苦兮涇水之隅，風霜滿鬢兮雨雪羅襦。", "賴明公兮引素書，令肉骨兮家如初，永言珍重兮無時無。"]'),
('697772c3-7516-49b7-a8ef-a5312c2ae623','宴柳毅詩 三','洞庭龍君','唐','唐诗','tang','','[]','碧雲悠悠兮涇水東流，傷嗟美人兮雨泣花愁。',67,'全唐诗/poet.tang.47000.json','["碧雲悠悠兮涇水東流，傷嗟美人兮雨泣花愁。", "尺書遠達兮以解君憂，哀冤果雪兮還處其休。", "荷君和雅兮感甘羞，山家寂寞兮難久留，欲將辭去兮悲綢繆。"]'),
('965332d6-1602-4003-a7d8-d69eaff9e5f1','鑄鏡歌','龍護老人','唐','唐诗','tang','','[]','盤龍盤龍，隱於鏡中。',40,'全唐诗/poet.tang.47000.json','["盤龍盤龍，隱於鏡中。", "分野有象，變化無窮。", "興雲吐霧，行雨生風。", "上清仙子，來獻聖聰。"]'),
('056dfdd9-a76a-46e6-ab01-a96184e9e738','示韋泛祿命','冥吏','唐','唐诗','tang','','[]','前陽復後楊，後楊年年強，七月之節歸玄鄉。',20,'全唐诗/poet.tang.47000.json','["前陽復後楊，後楊年年強，七月之節歸玄鄉。"]'),
('82b57e62-f23e-498d-8c97-432593281217','贈僧','滕傳胤','唐','唐诗','tang','','[]','卓立不求名出家，長懷片志在青霞。',32,'全唐诗/poet.tang.47000.json','["卓立不求名出家，長懷片志在青霞。", "今日英雄氣衝蓋，誰能久坐寶蓮花。"]'),
('3a119d44-ab04-4a6a-abee-d8e05dd71c13','贈人','滕傳胤','唐','唐诗','tang','','[]','平生才不足，立身信有餘。',24,'全唐诗/poet.tang.47000.json','["平生才不足，立身信有餘。", "自歎無大故，君子莫相疎。"]'),
('b3ff9483-06a6-4aed-a300-34a8205c8bf6','鄭鋒宅神詩 一','滕傳胤','唐','唐诗','tang','','[]','浦口潮來初淼漫，蓮舟搖颺採花難。',32,'全唐诗/poet.tang.47000.json','["浦口潮來初淼漫，蓮舟搖颺採花難。", "春心不愜空歸去，會待潮回更折看。"]'),
('40eba435-4026-4127-b9c3-d9d5491689e2','鄭鋒宅神詩 二','滕傳胤','唐','唐诗','tang','','[]','忽然湖上片雲飛，不覺舟中雨濕衣。',32,'全唐诗/poet.tang.47000.json','["忽然湖上片雲飛，不覺舟中雨濕衣。", "折得蓮花渾忘却，空將荷葉蓋頭歸。"]'),
('7957fca4-d2bb-4cbf-98c6-0c54d1b96533','與鄭德璘奇遇詩 一','水府君','唐','唐诗','tang','','[]','物觸輕舟心自知，風恬煙靜月光微。',32,'全唐诗/poet.tang.47000.json','["物觸輕舟心自知，風恬煙靜月光微。", "夜深江上解愁思，拾得紅蕖香惹衣。"]'),
('e7f8d7f0-aa2b-40a6-9c64-ce4fdf23ce64','與鄭德璘奇遇詩 二','水府君','唐','唐诗','tang','','["\u957f\u6c5f"]','纖手垂鉤對水窗，紅蕖秋色豔長江。',32,'全唐诗/poet.tang.47000.json','["纖手垂鉤對水窗，紅蕖秋色豔長江。", "既能解珮投交甫，更有明珠乞一雙。"]'),
('c037d762-fb09-4928-9f9f-05dca5c10e38','與鄭德璘奇遇詩 三','水府君','唐','唐诗','tang','','[]','湖面狂風且莫吹，浪花初綻月光微。',32,'全唐诗/poet.tang.47000.json','["湖面狂風且莫吹，浪花初綻月光微。", "沈潛暗想橫波淚，得共鮫人相對垂。"]'),
('fc34854f-5433-4682-967e-204482515030','與鄭德璘奇遇詩 四','水府君','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭風軟荻花秋，新沒青娥細浪愁。',32,'全唐诗/poet.tang.47000.json','["洞庭風軟荻花秋，新沒青娥細浪愁。", "淚滴白蘋君不見，月明江上有輕鷗。"]'),
('b8830b52-1653-44d8-935e-3ef94afe5616','與鄭德璘奇遇詩 五','水府君','唐','唐诗','tang','','[]','昔日江頭菱芡人，蒙君數飲松醪春。',32,'全唐诗/poet.tang.47000.json','["昔日江頭菱芡人，蒙君數飲松醪春。", "活君家室以爲報，珍重長沙鄭德璘。"]'),
('8414dd83-1032-4cbb-acfa-8b8d67edc13e','笑巫詩','李序','唐','唐诗','tang','','[]','魍魎何曾見，頭旋即下神。',24,'全唐诗/poet.tang.47000.json','["魍魎何曾見，頭旋即下神。", "圖他衫子段，詐道大王嗔。"]'),
('443aef9a-d576-404a-b4b6-fc2fb7ff074a','霅溪夜宴詩 一','水神','唐','唐诗','tang','','[]','濁波揚揚兮凝曉霧，公無渡河兮公竟渡。',105,'全唐诗/poet.tang.47000.json','["濁波揚揚兮凝曉霧，公無渡河兮公竟渡。", "風號水激兮呼不聞，提衣看入兮中流去。", "浪排衣兮隨步沒，沈屍深入兮蛟螭窟。", "蛟螭盡醉兮君血乾，推出黃沙兮泛君骨。", "當時君死兮妾何適，遂就波瀾兮合魂魄。", "願持精衛銜石心，窮斷河源塞泉脉。"]'),
('bfe1fcc2-c0f2-4ef9-8d0e-bb66936b1741','霅溪夜宴詩 二','水神','唐','唐诗','tang','','[]','悲風淅淅兮波緜緜，蘆花萬里兮凝蒼煙。',109,'全唐诗/poet.tang.47000.json','["悲風淅淅兮波緜緜，蘆花萬里兮凝蒼煙。", "虬螭窟宅兮淵且玄，排波疊浪兮沈我天。", "所覆不全兮身寧全，溢眸恨血兮徒漣漣。", "誓將柔荑抉鋸牙之喙，空水府而藏其腥涎。", "青娥翠黛兮沈江壖，碧雲斜月兮空嬋娟。", "吞聲飲恨兮語無力，徒揚哀怨兮登歌筵。"]'),
('766e405b-c3d9-423e-81bd-aca8596462c1','霅溪夜宴詩 三','水神','唐','唐诗','tang','','[]','白露漙兮西風高，碧波萬里兮翻洪濤。',33,'全唐诗/poet.tang.47000.json','["白露漙兮西風高，碧波萬里兮翻洪濤。", "莫言天下至柔者，載舟覆舟皆我曹。"]'),
('9115c233-20ce-4533-b5ed-d1a33161a813','霅溪夜宴詩 四','水神','唐','唐诗','tang','','[]','君不見夜來渡口擁千艘，中載萬姓之脂膏。',87,'全唐诗/poet.tang.47000.json','["君不見夜來渡口擁千艘，中載萬姓之脂膏。", "當樓船泛泛於疊浪，恨珠貝又輕於鴻毛。", "又不見朝來津亭維一舠，中有一士青其袍。", "赴宰邑之良日，任波吼而風號。", "是知溺名溺利者，不免爲水府之腥臊。"]'),
('3ac380cb-d3c5-4039-87fc-0682da7a9dc7','霅溪夜宴詩 五','水神','唐','唐诗','tang','','[]','山勢縈迴水脉分，水光山色翠連雲。',32,'全唐诗/poet.tang.47000.json','["山勢縈迴水脉分，水光山色翠連雲。", "四時盡入詩人詠，役殺吳興柳使君。"]'),
('c8c5b310-a463-4e68-861c-8aae7e1d3726','霅溪夜宴詩 六','水神','唐','唐诗','tang','','[]','渺渺煙波接九疑，幾人經此泣江蘺。',32,'全唐诗/poet.tang.47000.json','["渺渺煙波接九疑，幾人經此泣江蘺。", "年年綠水青山色，不改重華南狩時。"]'),
('4e70c5f9-e934-413c-a3b1-ae9f91df6e87','霅溪夜宴詩 七','水神','唐','唐诗','tang','','[]','浪闊波澄秋氣涼，沈沈水殿夜初長。',64,'全唐诗/poet.tang.47000.json','["浪闊波澄秋氣涼，沈沈水殿夜初長。", "自憐休退五湖客，何幸追陪百谷王。", "香裊碧雲飄几席，觥飛白玉豔椒漿。", "酒酣獨泛扁舟去，笑入琴高不死鄉。"]'),
('ed06c39c-7949-4516-af8d-e2c14c51adaf','霅溪夜宴詩 八','水神','唐','唐诗','tang','','[]','珠光龍耀火燑燑，夜接朝雲宴渚宮。',64,'全唐诗/poet.tang.47000.json','["珠光龍耀火燑燑，夜接朝雲宴渚宮。", "鳳管清吹淒極浦，朱弦間奏冷秋空。", "論心幸遇同歸友，揣分慙無輔佐功。", "雲雨各飛真境後，不堪波上起悲風。"]'),
('509185c6-c881-45f1-890f-cc013387158d','霅溪夜宴詩 九','水神','唐','唐诗','tang','','[]','鳳鶱鶱以降瑞兮，患山雞之雜飛。',272,'全唐诗/poet.tang.47000.json','["鳳鶱鶱以降瑞兮，患山雞之雜飛。", "玉溫溫以呈器兮，因碔砆之爭輝。", "當侯門之四闢兮，墐嘉謨之重扉。", "既瑞器而無庸兮，宜昏暗之相微。", "徒刳石以爲舟兮，顧沿流而志違。", "將刻木而作羽兮，與超騰之理非。", "矜孑孑於空江兮，靡羣援之可依。", "血淋淋而滂流兮，顧江魚之腹而將歸。", "西風蕭蕭兮湘水悠悠，白芷芳歇兮江蘺秋。", "日晼晼兮川雲收，櫂四起兮悲風幽。", "羈魂汨沒兮我名永浮，碧波雖涸兮厥譽長流。", "向使甘言盛行於曩昔，豈今日居君王之座頭。", "是知貪名徇祿而隨世磨滅者，雖正寢之死乎無得與吾儔。", "當鼎足之嘉會兮，獲周旋於君侯。", "雕盤玉豆兮羅珍羞，金巵瓊斝兮方獻酬。", "敢寫心兮歌一曲，無誚余持杯以淹留。"]'),
('71b3782b-ad35-487d-bf76-69c5762a54d7','霅溪夜宴詩 十','水神','唐','唐诗','tang','','[]','行殿秋未晚，水宮風初涼。',168,'全唐诗/poet.tang.47000.json','["行殿秋未晚，水宮風初涼。", "誰言此中夜，得接朝宗行。", "靈鼉振鼕鼕，神龍耀煌煌。", "紅樓壓波起，翠幄連雲張。", "玉簫冷吟秋，瑤瑟清含商。", "賢臻江湖叟，貴列川瀆王。", "諒予衰俗人，無能振頹綱。", "分辭皆亂世，樂寐蛟螭鄉。", "棲遲幽島間，幾見波成桑。", "爾來盡流俗，難與傾壺觴。", "今日登華筵，稍覺神揚揚。", "方歡滄浪侶，遽恐白日光。", "海人瑞錦前，豈敢言文章。", "聊歌靈境會，此會誠難忘。"]'),
('eb9e7fbd-6435-4971-bdef-2b42415f7011','霅溪夜宴詩 十一','水神','唐','唐诗','tang','','[]','雪集大野兮血波洶洶，玄黃交戰兮吳無全隴。',157,'全唐诗/poet.tang.47000.json','["雪集大野兮血波洶洶，玄黃交戰兮吳無全隴。", "既霸業之將墜，宜嘉謨之不從。", "國步顛蹶兮吾道遘凶，處鴟夷之大困，入淵泉之九重。", "上帝愍余之非辜兮，俾大江鼓怒其冤蹤。", "所以鞭浪山而疾驅波岳，亦粗足展余拂鬱之心胸。", "當靈境之良宴兮，謬尊俎之相容。", "擊簫鼓兮撞歌鐘，吳謳越舞兮歡未極。", "遽軍城曉鼓之鼕鼕，願保上善之柔德，何行樂之地兮難相逢。"]'),
('77abf3f4-f065-4ba8-9bce-17f486ac7f72','爲劉洪作 一','輔國將軍','唐','唐诗','tang','','[]','烏烏在虛飛，玄駒遂野依。',24,'全唐诗/poet.tang.47000.json','["烏烏在虛飛，玄駒遂野依。", "名今編戶籍，翠過葉生稀。"]'),
('a8e3277e-8819-45cf-9266-4054a13253b5','爲劉洪作 二','輔國將軍','唐','唐诗','tang','','[]','箇樹枝條朽，三花五面啼。',21,'全唐诗/poet.tang.47000.json','["箇樹枝條朽，三花五面啼。", "移家朝度日，誰覺。"]'),
('38d9b6cf-8b79-4a29-92ca-c904ab71934d','語','太白山神','唐','唐诗','tang','','[]','三珠併一珠，驢馬沒人驅。',24,'全唐诗/poet.tang.47000.json','["三珠併一珠，驢馬沒人驅。", "歲月甲庚午，中興戊己土。"]'),
('c8f941d2-1358-4c09-933f-eb71c6357671','月夜吟','瀵水神','唐','唐诗','tang','','[]','夜月明皎皎，綠波空悠悠。',12,'全唐诗/poet.tang.47000.json','["夜月明皎皎，綠波空悠悠。"]'),
('141fdb68-9238-4009-ae59-d94bec621805','荅鄭生歌','湘中蛟女','唐','唐诗','tang','','[]','泝青山兮江之隅，拖湘波兮褭綠裾。',32,'全唐诗/poet.tang.47000.json','["泝青山兮江之隅，拖湘波兮褭綠裾。", "荷拳拳兮情未舒，匪同歸兮將焉如。"]'),
('f7826f39-117b-4bf5-9fce-436d18586bc2','風光詞','湘中蛟女','唐','唐诗','tang','','[]','隆佳秀兮昭盛時，播薰綠兮淑華歸。',104,'全唐诗/poet.tang.47000.json','["隆佳秀兮昭盛時，播薰綠兮淑華歸。", "故里荑與處萼兮，潛重房以飾姿。", "見雅態之韶華兮，蒙長靄以爲幃。", "醉融光兮渺渺瀰瀰，迷千里兮涵煙眉，晨陶陶兮暮熙熙。", "舞嫋娜之穠條兮，娉盈盈以披遲。", "酡遊顏兮倡蔓卉縠，流倩電兮石髮髓施。"]'),
('1f794197-d3b9-4aae-85ed-3541006e307a','鄭生詩','湘中蛟女','唐','唐诗','tang','','[]','情無垠兮水湯湯，懷佳期兮屬三湘。',16,'全唐诗/poet.tang.47000.json','["情無垠兮水湯湯，懷佳期兮屬三湘。"]'),
('7aafb29e-81e1-4b71-9d05-80410e0f40b4','感懷詩','龍女','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','海門連洞庭，每去三千里。',24,'全唐诗/poet.tang.47000.json','["海門連洞庭，每去三千里。", "十載一歸來，辛苦瀟湘水。"]'),
('8fbb2e17-e94c-4516-b541-e721cca3a118','寄張無頗 一','廣利王女','唐','唐诗','tang','','[]','羞解明璫尋漢渚，但憑春夢訪天涯。',32,'全唐诗/poet.tang.47000.json','["羞解明璫尋漢渚，但憑春夢訪天涯。", "紅樓日暮鶯飛去，愁殺深宮落砌花。"]'),
('8ced1bb5-7b43-4459-a8e0-f0d9d0014b56','寄張無頗 二','廣利王女','唐','唐诗','tang','','[]','燕語春泥墮錦筵，情愁無意整花鈿。',32,'全唐诗/poet.tang.47000.json','["燕語春泥墮錦筵，情愁無意整花鈿。", "寒閨欹枕不成夢，香炷金爐自褭煙。"]'),
('27d1ac0c-f49b-4d0b-94eb-ea6e79092fc1','與崔渥冥會雜詩 一','湘妃廟','唐','唐诗','tang','','[]','萬里同心別九重，定知涉歷此相逢。',32,'全唐诗/poet.tang.47000.json','["萬里同心別九重，定知涉歷此相逢。", "誰人翻向羣峰路，不得蒼梧徇玉容。"]'),
('3020d487-d5dc-4f3e-802d-e1f1ea003791','與崔渥冥會雜詩 二','湘妃廟','唐','唐诗','tang','','[]','春鳥交交引思濃，豈期塵跡拜仙宮。',32,'全唐诗/poet.tang.47000.json','["春鳥交交引思濃，豈期塵跡拜仙宮。", "鸞歌鳳舞飄珠翠，疑是陽臺一夢中。"]'),
('7cef843e-8225-4e51-87f8-2d709a782dd8','與崔渥冥會雜詩 三','湘妃廟','唐','唐诗','tang','','[]','鸞輿昔日出蒲關，一去蒼梧更不還。',32,'全唐诗/poet.tang.47000.json','["鸞輿昔日出蒲關，一去蒼梧更不還。", "若是不留千古恨，湘江何事竹猶斑。"]'),
