('5edef38a-44bd-4625-9191-a30da70dedee','天明聯句','商山三丈夫','唐','唐诗','tang','','[]','幽樹高高影，山花寂寂香。',24,'全唐诗/poet.tang.47000.json','["幽樹高高影，山花寂寂香。", "山天遙歷歷，山水急湯湯。"]'),
('7986ee98-e3b0-44c9-8581-d41a992cedf5','贈張珽','鄭適','唐','唐诗','tang','','[]','昔爲吟風嘯月人，今爲吟風嘯月身。',32,'全唐诗/poet.tang.47000.json','["昔爲吟風嘯月人，今爲吟風嘯月身。", "冢壞路邊吟嘯罷，安知今日又勞神。"]'),
('88856142-89df-46b7-ad0a-989e525b842e','西軒詩 一','甘露寺鬼','唐','唐诗','tang','','["\u957f\u6c5f"]','趙壹能爲賦，鄒陽解獻書。',24,'全唐诗/poet.tang.47000.json','["趙壹能爲賦，鄒陽解獻書。", "可惜西江水，不救轍中魚。"]'),
('1fd714d2-3ac2-415f-8c87-dcc6547900a7','西軒詩 二','甘露寺鬼','唐','唐诗','tang','','[]','偉哉橫海鱗，壯矣垂天翼。',24,'全唐诗/poet.tang.47000.json','["偉哉橫海鱗，壯矣垂天翼。", "一旦失風水，翻爲螻蟻食。"]'),
('8fa18000-095e-4941-bae2-038c38b62c5a','西軒詩 三','甘露寺鬼','唐','唐诗','tang','','[]','功遂侔昔人，保退無智力。',24,'全唐诗/poet.tang.47000.json','["功遂侔昔人，保退無智力。", "既涉太行險，茲路信難陟。"]'),
('4d9bd7d4-271f-4659-938a-d6923c46605b','西軒詩 四','甘露寺鬼','唐','唐诗','tang','','[]','握裏龍蛇紙上鸞，逡巡千幅不將難。',32,'全唐诗/poet.tang.47000.json','["握裏龍蛇紙上鸞，逡巡千幅不將難。", "顧雲已往羅隱耄，更有何人逞筆端。"]'),
('88635f9f-b292-4fc7-806f-b60c20c91c39','降巫詩','邵謁','唐','唐诗','tang','','[]','青山山下少年郎，失意當時別故鄉。',32,'全唐诗/poet.tang.47000.json','["青山山下少年郎，失意當時別故鄉。", "惆悵不堪回首望，隔谿遙見舊書堂。"]'),
('c40b1378-cdc5-45a5-9f41-166ad969b4e6','贈雷殿直。','石恪','唐','唐诗','tang','','[]','衡陽去此正三年，一路程途甚坦然。',64,'全唐诗/poet.tang.47000.json','["衡陽去此正三年，一路程途甚坦然。", "深邃門牆三楚外，清風池館五峰前。", "西邊市井來商客，東岸汀洲簇釣船。", "公退只應無別事，朱陵後洞看神仙。"]'),
('bf7c29b8-d79f-4e75-872c-40b09f03afb0','吟','富春沙際鬼','唐','唐诗','tang','','[]','陊江三十年，潮打形骸朽。',24,'全唐诗/poet.tang.47000.json','["陊江三十年，潮打形骸朽。", "家人都不知，何處奠杯酒。"]'),
('f9e3d31f-f10d-4607-a618-da73d3bf1d1c','又吟','富春沙際鬼','唐','唐诗','tang','','[]','莫問我姓名，向君言亦空。',24,'全唐诗/poet.tang.47000.json','["莫問我姓名，向君言亦空。", "潮生沙骨冷，魂魄悲秋風。"]'),
('5559e870-ae8a-4764-8446-4e573affb200','獻高駢','趙𤰳','唐','唐诗','tang','','[]','我昔勝君昔，君今勝我今。',24,'全唐诗/poet.tang.47000.json','["我昔勝君昔，君今勝我今。", "人生一世事，何用苦相侵。"]'),
('e42582fe-3280-400f-b1df-13fb6e3bd852','吟','九華山白衣','唐','唐诗','tang','','[]','澗水潺潺聲不絕，溪壠茫茫野花發。',32,'全唐诗/poet.tang.47000.json','["澗水潺潺聲不絕，溪壠茫茫野花發。", "自去自來人不知，歸時唯對空山月。"]'),
('8905d150-130a-43d1-a1af-5967477ee838','詩','田達誠借宅鬼','唐','唐诗','tang','','[]','天然與我一靈通，還與人間事不同。',32,'全唐诗/poet.tang.47000.json','["天然與我一靈通，還與人間事不同。", "要識吾家真姓字，天地南頭一段紅。"]'),
('ed549c13-ea5c-40f6-83e0-51fdaa7d0e4c','秋夜吟','長安中鬼','唐','唐诗','tang','','[]','六街鼓歇行人絕，九衢茫茫室有月。',32,'全唐诗/poet.tang.47000.json','["六街鼓歇行人絕，九衢茫茫室有月。", "九衢生人何勞勞，長安土盡槐根高。"]'),
('1a04c045-cd9e-4576-aaab-97841fc5bae9','題窗上詩','隔窗鬼','唐','唐诗','tang','','[]','何人窗下讀書聲，南斗闌干北斗橫。',32,'全唐诗/poet.tang.47000.json','["何人窗下讀書聲，南斗闌干北斗橫。", "千里思家歸不得，春風腸斷石頭城。"]'),
('f240f42f-4bf0-4463-8026-4bb19f4db3af','柱上詩','巴陵館鬼','唐','唐诗','tang','','[]','爺娘送我青楓根，不記青楓幾迴落。',32,'全唐诗/poet.tang.47000.json','["爺娘送我青楓根，不記青楓幾迴落。", "當時手刺衣上花，今日爲灰不堪著。"]'),
('8e5d220c-a1e9-4779-93a0-b9359d1fca2a','留別安鳳','徐侃','唐','唐诗','tang','','[]','君寄長安久，恥不還故鄉。',36,'全唐诗/poet.tang.47000.json','["君寄長安久，恥不還故鄉。", "我別長安去，切在慰高堂。", "不意與離恨，泉下亦難忘。"]'),
('15dc522d-0721-4e69-ab49-6e2ef357f9a3','安鳳贈別徐侃','徐侃','唐','唐诗','tang','','[]','一自離鄉國，十年在咸秦。',60,'全唐诗/poet.tang.47000.json','["一自離鄉國，十年在咸秦。", "泣盡卞和血，不逢一故人。", "今日舊友別，羞此漂泊身。", "離情吟詩處，麻衣掩淚頻。", "淚別各分袂，且及來年春。"]'),
('e773542f-8f35-4a99-9b96-8c7c9b118a2d','述懷 一','商山客死書生','唐','唐诗','tang','','[]','家住驛北路，百里無四鄰。',24,'全唐诗/poet.tang.47000.json','["家住驛北路，百里無四鄰。", "往來不相問，寂寂山家春。"]'),
('286527d0-f51f-4035-91e1-1216e23637d0','述懷 二','商山客死書生','唐','唐诗','tang','','[]','南岡夜蕭蕭，青松與白楊。',24,'全唐诗/poet.tang.47000.json','["南岡夜蕭蕭，青松與白楊。", "家人應有夢，遠客已無腸。"]'),
('87499b24-d37b-49eb-858f-0289be3a359a','述懷 三','商山客死書生','唐','唐诗','tang','','[]','白草寒露裏，亂山明月中。',24,'全唐诗/poet.tang.47000.json','["白草寒露裏，亂山明月中。", "是夕苦吟罷，寒燭與君同。"]'),
('249fa103-26ff-4a6b-b3e4-dc45e21ef435','續鄭郊吟','冢中人','唐','唐诗','tang','','[]','冢上兩竿竹，風吹常嫋嫋。',24,'全唐诗/poet.tang.47000.json','["冢上兩竿竹，風吹常嫋嫋。", "下有百年人，長眠不知曉。"]'),
('1bcfa1b4-12c5-4dbf-8619-efd97d123588','題壁 一','崇聖寺鬼','唐','唐诗','tang','','[]','禁煙佳節同遊此，正值酴醿夾岸香。',32,'全唐诗/poet.tang.47000.json','["禁煙佳節同遊此，正值酴醿夾岸香。", "緬首十年前往事，強吟風景亂愁腸。"]'),
('5895994c-913c-4df6-9f28-39511432cd56','題壁 二','崇聖寺鬼','唐','唐诗','tang','','[]','策馬暫尋原上路，落花芳草尚依然。',32,'全唐诗/poet.tang.47000.json','["策馬暫尋原上路，落花芳草尚依然。", "家亡國破一場夢，惆悵又逢寒食天。"]'),
('832ce408-5aa4-44ce-9491-71041357cad4','血書詩','任彥思家鬼','唐','唐诗','tang','','[]','物類易遷變，我行人不見。',24,'全唐诗/poet.tang.47000.json','["物類易遷變，我行人不見。", "珍重任彥思，相別日已遠。"]'),
('d65fe3cd-9ae0-4e52-ba07-ffbf30daea86','贈馬植','峽中白衣','唐','唐诗','tang','','[]','截竹爲筒作笛吹，鳳凰池上鳳凰飛。',32,'全唐诗/poet.tang.47000.json','["截竹爲筒作笛吹，鳳凰池上鳳凰飛。", "勞君更向黔南去，即是陶鈞萬類時。"]'),
('eba0c173-6974-4837-9bb9-5da9619bcd13','題芭蕉葉上','張仁寶','唐','唐诗','tang','','[]','寒食家家盡禁煙，野棠風墜小花鈿。',32,'全唐诗/poet.tang.47000.json','["寒食家家盡禁煙，野棠風墜小花鈿。", "如今空有孤魂夢，半在嘉陵半錦川。"]'),
('6403d78f-966f-453a-9d67-1f15803a466b','官坡館聯句','崔常侍','唐','唐诗','tang','','[]','牀頭錦衾班復班，架上朱衣殷復殷。',32,'全唐诗/poet.tang.47000.json','["牀頭錦衾班復班，架上朱衣殷復殷。", "空庭朗月閑復閑，夜長路遠山復山。"]'),
('c1f98f4a-2111-4c9c-b168-d703e15a1e16','亡後見形詩','李煜','唐','唐诗','tang','','[]','異國非所志，煩勞殊清閑。',24,'全唐诗/poet.tang.47000.json','["異國非所志，煩勞殊清閑。", "驚濤千萬里，無乃見鍾山。"]'),
('726e16c3-72c4-410b-a7d8-776511bf3287','同鹿門少年馬紹隆冥遊詩 一','龐德公','唐','唐诗','tang','','[]','千年故國歲華奔，一柱高臺已斷魂。',32,'全唐诗/poet.tang.47000.json','["千年故國歲華奔，一柱高臺已斷魂。", "唯有峴亭清夜月，與君長嘯學蘇門。"]'),
('3b8d2990-8205-43bb-bf3f-d4c06200ae55','同鹿門少年馬紹隆冥遊詩 二','龐德公','唐','唐诗','tang','','[]','高名宋玉遺閑麗，作賦蘭成絕盛才。',32,'全唐诗/poet.tang.47000.json','["高名宋玉遺閑麗，作賦蘭成絕盛才。", "誰似遼東千歲鶴，倚天華表却歸來。"]'),
('b7621d29-d9ee-4cad-bfd3-a59e69f9b6bc','貽常夷詩','朱均','唐','唐诗','tang','','[]','平生遊城郭，殂沒委荒榛。',108,'全唐诗/poet.tang.47000.json','["平生遊城郭，殂沒委荒榛。", "自我辭人世，不知秋與春。", "牛羊久來牧，松柏幾成薪。", "分絕車馬好，甘隨狐兔羣。", "何處清風至，君子幸爲鄰。", "烈烈盛名德，依依佇良賓。", "千年何旦暮，一室動人神。", "喬木如在望，通衢良易遵。", "高門儻無隔，向與析龍津。"]'),
('f0783a8b-1521-476e-9aa0-71ec7e44d0cf','空館夜歌 一','夷陵女郎','唐','唐诗','tang','','[]','明月清風，良宵會同。',30,'全唐诗/poet.tang.47000.json','["明月清風，良宵會同。", "星河易翻，歡娛不終。", "綠樽翠杓，爲君斟酌。"]'),
('b0cdbce8-bc72-46b4-b74f-a42221bab4cc','空館夜歌 二','夷陵女郎','唐','唐诗','tang','','[]','楊柳楊柳，嫋嫋隨風急。',27,'全唐诗/poet.tang.47000.json','["楊柳楊柳，嫋嫋隨風急。", "西樓美人春夢長，繡簾斜捲千條入。"]'),
('8fc2d713-cb2c-4195-9081-fce8058a0cf2','空館夜歌 三','夷陵女郎','唐','唐诗','tang','','[]','[玉]戶金缸，願陪君王。',62,'全唐诗/poet.tang.47000.json','["[玉]戶金缸，願陪君王。", "邯鄲宮中，金石絲簧。", "衛女秦娥，左右成行。", "紈縞繽紛，翠眉紅妝。", "王歡顧盼，爲王歌舞。", "願得君歡，常無災苦。"]'),
('5e5ffc84-b4dd-493d-8261-61a761a6c71f','贈夫詩三首 一','孔氏','唐','唐诗','tang','','[]','不忿成故人，掩涕每盈巾。',24,'全唐诗/poet.tang.47000.json','["不忿成故人，掩涕每盈巾。", "死生今有隔，相見永無因。"]'),
('dad54997-3044-4f7a-9acb-9b4468036f02','贈夫詩三首 二','孔氏','唐','唐诗','tang','','[]','匣裏殘妝粉，留將與後人。',24,'全唐诗/poet.tang.47000.json','["匣裏殘妝粉，留將與後人。", "黃泉無用處，恨作冢中塵。"]'),
('93ee8f36-27b5-4aec-b0b9-1ca8a4160b56','贈夫詩三首 三','孔氏','唐','唐诗','tang','','[]','有意懷男女，無情亦任君。',24,'全唐诗/poet.tang.47000.json','["有意懷男女，無情亦任君。", "欲知腸斷處，明月照孤墳。"]'),
('546705a1-a339-48d2-92fc-575da76445c3','荅夫詩二首 一','唐晅妻張氏','唐','唐诗','tang','','[]','不分殊幽顯，那堪異古今。',24,'全唐诗/poet.tang.47000.json','["不分殊幽顯，那堪異古今。", "陰陽徒自隔，聚散兩難心。"]'),
('266d0111-59ea-45dc-8207-43b7313e1255','荅夫詩二首 二','唐晅妻張氏','唐','唐诗','tang','','[]','蘭階兔月斜，銀燭半含花。',24,'全唐诗/poet.tang.47000.json','["蘭階兔月斜，銀燭半含花。", "自憐長夜客，泉路以爲家。"]'),
('ca49463b-7d9c-4f80-a624-034c826d2eb2','唐晅悼妻詩 一','唐晅妻張氏','唐','唐诗','tang','','[]','寢室悲長簟，妝樓泣鏡臺。',36,'全唐诗/poet.tang.47000.json','["寢室悲長簟，妝樓泣鏡臺。", "獨悲桃李節，不共夜泉開。", "魂兮若有感，髣髴夢中來。"]'),
('eb77a71d-47d1-468a-938d-090b3e178130','唐晅悼妻詩 二','唐晅妻張氏','唐','唐诗','tang','','[]','常時華堂靜，笑語度更籌。',48,'全唐诗/poet.tang.47000.json','["常時華堂靜，笑語度更籌。", "恍惚人事改，冥寞委荒丘。", "陽原歌薤露，陰壑惜藏舟。", "清夜妝臺月，空想畫眉愁。"]'),
('1c964dec-38ac-45db-b886-30f6de4ade44','贈妻詩','唐晅妻張氏','唐','唐诗','tang','','[]','嶧陽桐半死，延津劒一沈。',24,'全唐诗/poet.tang.47000.json','["嶧陽桐半死，延津劒一沈。", "如何宿昔內，空負百年心。"]'),
('36d3d277-5b20-4780-b9bc-23e30308f7cf','贈姊','韋璜','唐','唐诗','tang','','[]','修短各有分，浮華亦非真。',36,'全唐诗/poet.tang.47000.json','["修短各有分，浮華亦非真。", "斷腸泉壤下，幽憂難具陳。", "淒淒白楊風，日暮堪愁人。"]'),
('e058769a-c7eb-450c-8058-1ecfd28acc9e','贈夫二首 一','韋璜','唐','唐诗','tang','','[]','不得長相守，青春夭蕣華。',24,'全唐诗/poet.tang.47000.json','["不得長相守，青春夭蕣華。", "舊遊今永已，泉路却爲家。"]'),
('bc463c0c-a3b6-45c9-a948-fb26b62d09ef','贈夫二首 二','韋璜','唐','唐诗','tang','','[]','早知離別切人心，悔作從來恩愛深。',32,'全唐诗/poet.tang.47000.json','["早知離別切人心，悔作從來恩愛深。", "黃泉冥寞雖長逝，白日屏帷還重尋。"]'),
('f5b6142a-c129-44de-962b-be0aa3b34cb6','贈嫂','韋璜','唐','唐诗','tang','','[]','赤心用盡爲相知，慮後防前秖定疑。',32,'全唐诗/poet.tang.47000.json','["赤心用盡爲相知，慮後防前秖定疑。", "案牘可申生節目，桃符雖聖欲何爲。"]'),
('6766b37d-23ee-41e7-8aa8-023dfe603107','與獨孤穆冥會詩 一','臨淄縣主','唐','唐诗','tang','','[]','江都昔喪亂，闕下多搆兵。',180,'全唐诗/poet.tang.47000.json','["江都昔喪亂，闕下多搆兵。", "豺虎恣吞噬，干戈日縱橫。", "逆徒自外至，半夜開重城。", "膏血浸宮殿，刀槍倚簷楹。", "今知從逆者，廼是公與卿。", "白刃汚黃屋，邦家遂因傾。", "疾風知勁草，世亂識忠臣。", "哀哀獨孤公，臨死乃結纓。", "天地既板蕩，雲雷時未亨。", "今者二百載，幽懷猶未平。", "山河風月古，陵寢露煙青。", "君子秉祖德，方垂忠烈名。", "華軒一惠顧，土室以爲榮。", "丈夫立志操，存沒感其情。", "求義若可託，誰能抱幽貞。"]'),
('b8b2f521-32da-41f6-ada6-59564d956334','與獨孤穆冥會詩 二','臨淄縣主','唐','唐诗','tang','','[]','皇天昔降禍，隋室若綴旒。',192,'全唐诗/poet.tang.47000.json','["皇天昔降禍，隋室若綴旒。", "患難在雙闕，干戈連九州。", "出門皆凶豎，所向多逆謀。", "白日忽然暮，頹波不可收。", "望夷既結釁，宗社亦貽羞。", "溫室兵始合，宮闈血已流。", "憫哉吹簫子，悲啼下鳳樓。", "霜刃徒見逼，玉笄不可求。", "羅襦遺侍者，粉黛成仇讎。", "邦國已淪覆，餘生誓不留。", "英英將軍祖，獨以社稷憂。", "丹血濺黼扆，豐肌染戈矛。", "今來見禾黍，盡日悲宗周。", "玉樹已寂寞，泉臺千萬秋。", "感茲一顧重，願以死節酬。", "幽顯儻不昧，終焉契綢繆。"]'),
('9459c13b-c3c0-4c7e-a151-dda5097025b1','與獨孤穆冥會詩 三','臨淄縣主','唐','唐诗','tang','','[]','平陽縣中樹，久作廣陵塵。',24,'全唐诗/poet.tang.47000.json','["平陽縣中樹，久作廣陵塵。", "不意何郎至，黃泉重見春。"]'),
('b109faf0-132a-4ae3-8851-c3f174bd3b82','與獨孤穆冥會詩 四','臨淄縣主','唐','唐诗','tang','','[]','今閨久無主，羅袂坐生塵。',24,'全唐诗/poet.tang.47000.json','["今閨久無主，羅袂坐生塵。", "願作吹簫伴，同爲騎鳳人。"]'),
('b9302719-9cfa-41e2-aed9-5d2070972ea2','與獨孤穆冥會詩 五','臨淄縣主','唐','唐诗','tang','','[]','朱軒下長路，青草啓孤墳。',24,'全唐诗/poet.tang.47000.json','["朱軒下長路，青草啓孤墳。", "猶勝陽臺上，空看朝暮雲。"]'),
('d6d35c03-5fff-4623-be90-8be88aa676b2','與獨孤穆冥會詩 六','臨淄縣主','唐','唐诗','tang','','[]','露草芊芊，頹塋未遷。',60,'全唐诗/poet.tang.47000.json','["露草芊芊，頹塋未遷。", "自我居此，於今幾年。", "與君先祖，疇昔恩波。", "死生契闊，忽此相過。", "誰謂佳期，尋當別離。", "俟君之北，攜手同歸。"]'),
('15d2d0cc-9042-4e62-ae0c-a923309b1db9','與獨孤穆冥會詩 七','臨淄縣主','唐','唐诗','tang','','[]','伊彼維揚，在天一方。',60,'全唐诗/poet.tang.47000.json','["伊彼維揚，在天一方。", "驅馬悠悠，忽來異鄉。", "情通幽顯，獲此相見。", "義感疇昔，言存繾綣。", "清江桂洲，可以遨遊。", "惟子之故，不遑淹留。"]'),
('c4805eef-d90c-4afa-a9bb-049a46274b84','與李章武贈荅詩 一','王氏婦','唐','唐诗','tang','','[]','鴛鴦綺，知結幾千絲。',22,'全唐诗/poet.tang.47000.json','["鴛鴦綺，知結幾千絲。", "別後尋交頸，應傷未別時。"]'),
('2cad7053-c204-44d6-aee8-1981d3f53e60','與李章武贈荅詩 二','王氏婦','唐','唐诗','tang','','[]','捻指環，相思見環重相憶。',24,'全唐诗/poet.tang.47000.json','["捻指環，相思見環重相憶。", "願君永持翫，循環無終極。"]'),
('45d77514-436f-4446-9fed-a0b8dbc45e62','與李章武贈荅詩 三','王氏婦','唐','唐诗','tang','','[]','河漢已傾斜，神魂欲超越。',24,'全唐诗/poet.tang.48000.json','["河漢已傾斜，神魂欲超越。", "願郎更迴抱，終天從此訣。"]'),
('2763892c-409e-4818-99ee-cf4544bf7d0e','與李章武贈荅詩 四','王氏婦','唐','唐诗','tang','','[]','分從幽顯隔，豈謂有佳期。',24,'全唐诗/poet.tang.48000.json','["分從幽顯隔，豈謂有佳期。", "寧辭重重別，所歎去何之。"]'),
('4d756bfd-759b-411f-bb2e-7ba7c3208f43','與李章武贈荅詩 五','王氏婦','唐','唐诗','tang','','[]','昔辭懷後會，今別便終天。',24,'全唐诗/poet.tang.48000.json','["昔辭懷後會，今別便終天。", "新悲與舊恨，千古閉窮泉。"]'),
('d333b7e3-02d7-4475-bd59-6a2d8c4addb2','與李章武贈荅詩 六','王氏婦','唐','唐诗','tang','','[]','後期杳無約，前恨已相尋。',24,'全唐诗/poet.tang.48000.json','["後期杳無約，前恨已相尋。", "別路無行信，何因得寄心。"]'),
('eb18320f-9135-481a-8c70-805383e9510f','與李章武贈荅詩 七','王氏婦','唐','唐诗','tang','','[]','水不西歸月暫圓，令人惆悵古城邊。',32,'全唐诗/poet.tang.48000.json','["水不西歸月暫圓，令人惆悵古城邊。", "蕭條明早分岐路，知更相逢何歲年。"]'),
('fcd320c3-1872-44a2-8f8a-81afc49de228','李助爲章武賦','王氏婦','唐','唐诗','tang','','[]','石沈遼海闊，劍別楚天長。',24,'全唐诗/poet.tang.48000.json','["石沈遼海闊，劍別楚天長。", "會合知無日，離心滿夕陽。"]'),
('427e5247-4d70-4804-9382-ebc084a8cfa3','與曾季衡冥會詩 一','王麗真','唐','唐诗','tang','','[]','五原分袂真吳越，燕拆鶯離芳草歇。',32,'全唐诗/poet.tang.48000.json','["五原分袂真吳越，燕拆鶯離芳草歇。", "年少煙花處處春，北邙空恨清秋月。"]'),
('c73b1917-7cff-4b0e-9a33-82a78a972435','與曾季衡冥會詩 二','王麗真','唐','唐诗','tang','','[]','莎草青青雁欲歸，玉腮珠淚灑臨岐。',32,'全唐诗/poet.tang.48000.json','["莎草青青雁欲歸，玉腮珠淚灑臨岐。", "雲鬟飄去香風盡，愁見鶯啼紅樹枝。"]'),
('a693c2a5-f0a0-4ac9-a48c-b0fc03d2b1df','贈段何','客戶里女子','唐','唐诗','tang','','[]','樂廣清羸經幾年，姹娘相托不論錢。',32,'全唐诗/poet.tang.48000.json','["樂廣清羸經幾年，姹娘相托不論錢。", "輕盈妙質歸何處，惆悵碧樓紅玉鈿。"]'),
('09ef0a89-4c75-4f6e-803b-ed10b82179bc','湖城廳吟','密陀僧','唐','唐诗','tang','','[]','黃帝上天時，鼎湖元在茲。',24,'全唐诗/poet.tang.48000.json','["黃帝上天時，鼎湖元在茲。", "七十二玉女，化作黃金芝。"]'),
('bdd7952d-1405-4a0c-83a5-bc54d75292cd','謝王軒','西施','唐','唐诗','tang','','[]','妾自吳宮還越國，素衣千載無人識。',32,'全唐诗/poet.tang.48000.json','["妾自吳宮還越國，素衣千載無人識。", "當時心比金石堅，今日爲君堅不得。"]'),
('030a4be5-e7c6-4acf-b93c-870f2e39210b','王軒題西施石詩','西施','唐','唐诗','tang','','[]','嶺上千峰秀，江邊細草春。',24,'全唐诗/poet.tang.48000.json','["嶺上千峰秀，江邊細草春。", "今逢浣紗石，不見浣紗人。"]'),
('2f707ad0-57aa-48ad-bdc7-bd5c2d74d4c9','軒詩','西施','唐','唐诗','tang','','[]','佳人去千載，溪山久寂寞。',48,'全唐诗/poet.tang.48000.json','["佳人去千載，溪山久寂寞。", "野水浮白煙，巖花自開落。", "猨鳥舊清音，風月閑樓閣。", "無語立斜陽，幽情入天幕。"]'),
('6324cedb-99a2-4cbb-8374-ce2bebc4a535','西施詩','西施','唐','唐诗','tang','','[]','高花巖外曉相鮮，幽鳥雨中啼不歇。',32,'全唐诗/poet.tang.48000.json','["高花巖外曉相鮮，幽鳥雨中啼不歇。", "紅雲飛過大江西，從此人間怨風月。"]'),
('c8083dc7-09f6-43ad-acae-850158d085ff','軒詩','西施','唐','唐诗','tang','','[]','當時計拙笑將軍，何事安邦賴美人。',32,'全唐诗/poet.tang.48000.json','["當時計拙笑將軍，何事安邦賴美人。", "一自仙葩入吳國，從茲越國更無春。"]'),
('184771db-dc12-4e83-b701-4f741f09efcb','西施詩','西施','唐','唐诗','tang','','[]','雲霞出沒羣峰外，鷗鳥浮沈一水間。',32,'全唐诗/poet.tang.48000.json','["雲霞出沒羣峰外，鷗鳥浮沈一水間。", "一自越兵齊振地，夢魂不到虎丘山。"]'),
('f37e2c7d-1dcc-458c-8545-ef29d798f436','與蕭曠冥會詩 一','甄后','唐','唐诗','tang','','[]','玉筯凝腮憶魏宮，朱弦一弄洗清風。',32,'全唐诗/poet.tang.48000.json','["玉筯凝腮憶魏宮，朱弦一弄洗清風。", "明晨追賞應愁寂，沙渚煙銷翠羽空。"]'),
('8f1b6e65-1d71-43dc-be1e-f2c87aa2b242','與蕭曠冥會詩 二','甄后','唐','唐诗','tang','','[]','織綃泉底少歡娛，更勸蕭郎盡酒壺。',32,'全唐诗/poet.tang.48000.json','["織綃泉底少歡娛，更勸蕭郎盡酒壺。", "愁見玉琴彈別鶴，又將清淚滴真珠。"]'),
('90cbeeb8-098f-4eaa-a01c-a23511422eea','與蕭曠冥會詩 三','甄后','唐','唐诗','tang','','[]','紅蘭吐豔間夭桃，自喜尋芳數已遭。',32,'全唐诗/poet.tang.48000.json','["紅蘭吐豔間夭桃，自喜尋芳數已遭。", "珠珮鶴橋從此斷，遙天空恨碧雲高。"]'),
('a1184034-c9d6-47a3-a6ae-5f51a5fcbdaf','五原夜吟','沙磧女子','唐','唐诗','tang','','[]','雲鬟消盡轉蓬稀，埋骨窮荒失所依。',32,'全唐诗/poet.tang.48000.json','["雲鬟消盡轉蓬稀，埋骨窮荒失所依。", "牧馬不嘶沙月白，孤魂空逐雁南飛。"]'),
('c10e75d4-faa4-4e28-bfee-c64c71e8c2df','與顏濬冥會詩 一','陳宮妃嬪','唐','唐诗','tang','','[]','秋草荒臺響夜蛩，白楊凋盡減悲風。',32,'全唐诗/poet.tang.48000.json','["秋草荒臺響夜蛩，白楊凋盡減悲風。", "綵箋曾擘欺江總，綺閣塵消玉樹空。"]'),
('da4cb62b-c75a-4b43-8643-a95a411f6c36','與顏濬冥會詩 二','陳宮妃嬪','唐','唐诗','tang','','[]','寶閣排雲稱望仙，五雲高豔擁朝天。',32,'全唐诗/poet.tang.48000.json','["寶閣排雲稱望仙，五雲高豔擁朝天。", "清溪猶有當時月，應照瓊花綻綺筵。"]'),
('57e09b96-f8df-4838-a28b-e355fb080199','與顏濬冥會詩 三','陳宮妃嬪','唐','唐诗','tang','','["\u957f\u6c5f"]','素魄初圓恨翠娥，繁華濃豔竟如何。',32,'全唐诗/poet.tang.48000.json','["素魄初圓恨翠娥，繁華濃豔竟如何。", "南朝唯有長江水，依舊門前作逝波。"]'),
('204b4249-aae6-4e85-ab35-508924d11839','與顏濬冥會詩 四','陳宮妃嬪','唐','唐诗','tang','','[]','簫管清吟怨麗華，秋江寒月綺窗斜。',32,'全唐诗/poet.tang.48000.json','["簫管清吟怨麗華，秋江寒月綺窗斜。", "慚非後主題箋客，得見臨春閣上花。"]'),
('83fd19d2-5f8e-474d-ac46-a0bc550d3789','驛樓誦詩','湘中女子','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u6101\u82e6"]','紅樹醉秋色，碧溪彈夜弦。',24,'全唐诗/poet.tang.48000.json','["紅樹醉秋色，碧溪彈夜弦。", "佳期不可再，風雨杳如年。"]'),
('8864251b-b248-40ab-95b3-a213e7d69d19','贈楊藴中','薛濤','唐','唐诗','tang','','[]','玉漏聲長燈耿耿，東牆西牆時見影。',32,'全唐诗/poet.tang.48000.json','["玉漏聲長燈耿耿，東牆西牆時見影。", "月明窗外子規啼，忍使孤魂愁夜永。"]'),
('01d31485-c23b-47d0-80b7-3710f924195c','葬後見形詩','孟蜀妃張太華','唐','唐诗','tang','','[]','獨臥經秋墮鬢蟬，白楊風起不成眠。',32,'全唐诗/poet.tang.48000.json','["獨臥經秋墮鬢蟬，白楊風起不成眠。", "尋思往日椒房寵，淚濕衣襟損翠鈿。"]'),
('6c579ed2-3dd4-4396-8e03-2d6c98db9a4b','謝李若沖','孟蜀妃張太華','唐','唐诗','tang','','[]','符吏匆匆叩夜扃，便隨金簡出幽冥。',32,'全唐诗/poet.tang.48000.json','["符吏匆匆叩夜扃，便隨金簡出幽冥。", "蒙師薦拔恩非淺，領得生神九過經。"]'),
('e10b58ae-e575-40b5-ac2a-d2f89c200f88','幽恨詩','安邑坊女','唐','唐诗','tang','','[]','卜得上峽日，秋江風浪多。',24,'全唐诗/poet.tang.48000.json','["卜得上峽日，秋江風浪多。", "巴陵一夜雨，腸斷木蘭歌。"]'),
('b3451b23-106e-49cc-84c8-a5458c9745ac','和檢詩','韋檢亡姬','唐','唐诗','tang','','[]','春雨濛濛不見天，家家門外柳和煙。',32,'全唐诗/poet.tang.48000.json','["春雨濛濛不見天，家家門外柳和煙。", "如今腸斷空垂淚，歡笑重追別有年。"]'),
('ec468eb3-5f29-41ff-bfdd-faa75f448a60','檢悼亡姬詩','韋檢亡姬','唐','唐诗','tang','','[]','寶劒化龍歸碧落，嫦娥隨月下黃泉。',32,'全唐诗/poet.tang.48000.json','["寶劒化龍歸碧落，嫦娥隨月下黃泉。", "一杯酒向青春晚，寂寞書窗恨獨眠。"]'),
('affeca76-00ca-4ddc-b5e3-edd9da06adf8','夢後自題','韋檢亡姬','唐','唐诗','tang','','[]','白浪漫漫去不迴，浮雲飛盡日西頹。',32,'全唐诗/poet.tang.48000.json','["白浪漫漫去不迴，浮雲飛盡日西頹。", "始皇陵上千年樹，銀鴨金鳧也變灰。"]'),
('92024527-0c18-44ae-b8b1-3ee1a51ddbc2','與夫同詠詩 一','蘇檢妻','唐','唐诗','tang','','[]','楚水平如鏡，周迴白鳥飛。',24,'全唐诗/poet.tang.48000.json','["楚水平如鏡，周迴白鳥飛。", "金陵幾多地，一去不知歸。"]'),
('0d8575e7-412b-435e-a4f1-81d3b392c8a1','與夫同詠詩 二','蘇檢妻','唐','唐诗','tang','','[]','還吳東去過澄城，樓上清風酒半醒。',32,'全唐诗/poet.tang.48000.json','["還吳東去過澄城，樓上清風酒半醒。", "想得到家春已暮，海棠千樹已凋零。"]'),
('d82d37dd-2404-4599-b1f8-aa17b6cbfde1','冥會詩 一','宮嬪','唐','唐诗','tang','','[]','爭不逢人話此身，此身長夜不知春。',32,'全唐诗/poet.tang.48000.json','["爭不逢人話此身，此身長夜不知春。", "自從國破家亡後，隴上惟添芳草新。"]'),
('9587eb7b-3381-420a-a5d8-ad7ed6550bb4','冥會詩 二','宮嬪','唐','唐诗','tang','','[]','休說人間恨戀多，況逢佳客此相過。',32,'全唐诗/poet.tang.48000.json','["休說人間恨戀多，況逢佳客此相過。", "堂中縱有千般樂，爭及陽春一曲歌。"]'),
('2734c5d1-2cd2-48fc-a6c1-636db69898bf','冥會詩 三','宮嬪','唐','唐诗','tang','','[]','幽谷窮花似妾身，縱懷香豔吐無因。',32,'全唐诗/poet.tang.48000.json','["幽谷窮花似妾身，縱懷香豔吐無因。", "多情公子能相訪，應解回風暫借春。"]'),
('4395d2ce-b601-4287-99e5-0b1bfab62b36','冥會詩 四','宮嬪','唐','唐诗','tang','','[]','恩情未足曉光催，數朵眠花未得開。',32,'全唐诗/poet.tang.48000.json','["恩情未足曉光催，數朵眠花未得開。", "却羨一雙金扼臂，得隨人世出將來。"]'),
('f07b9a00-14d4-495d-9b20-09b89f28dcb3','與謝翶贈荅詩 一','金車美人','唐','唐诗','tang','','[]','陽臺後會杳無期，碧樹煙深玉漏遲。',32,'全唐诗/poet.tang.48000.json','["陽臺後會杳無期，碧樹煙深玉漏遲。", "半夜香風滿庭月，花前空賦別離詩。"]'),
('8c33c30a-7391-4656-a879-73b7c1e81648','與謝翶贈荅詩 二','金車美人','唐','唐诗','tang','','[]','相思無路莫相思，風裏花開只片時。',32,'全唐诗/poet.tang.48000.json','["相思無路莫相思，風裏花開只片時。", "惆悵金閨却歸去，曉鶯啼斷綠楊枝。"]'),
('4f325815-50e2-4fb0-9b20-8f95e9d1e2ba','與謝翶贈荅詩 三','金車美人','唐','唐诗','tang','','[]','一紙華箋灑碧雲，餘香猶在墨猶新。',64,'全唐诗/poet.tang.48000.json','["一紙華箋灑碧雲，餘香猶在墨猶新。", "空添滿目淒涼事，不見三山縹緲人。", "斜月照衣今夜夢，落花啼鳥去年春。", "紅閨更有堪愁處，窗上蟲絲几上塵。"]'),
('fcd2e38c-5aea-493c-bc18-b4b26a2e22c6','與謝翶贈荅詩 四','金車美人','唐','唐诗','tang','','[]','惆悵佳期一夢中，武陵春色盡成空。',64,'全唐诗/poet.tang.48000.json','["惆悵佳期一夢中，武陵春色盡成空。", "欲知離別偏堪恨，只爲音塵兩不通。", "愁態上眉凝淺綠，淚痕侵臉落輕紅。", "雙輪暫與王孫駐，明日西馳又向東。"]'),
('3e27f3f2-a985-4884-a502-ff19873530e8','贈朋詩','魏朋妻','唐','唐诗','tang','','[]','孤墳臨清江，每覩白日晚。',72,'全唐诗/poet.tang.48000.json','["孤墳臨清江，每覩白日晚。", "松影搖長風，蟾光落嵓甸。", "故鄉千里餘，親戚罕相見。", "望望空雲山，哀哀淚如霰。", "恨爲泉臺客，復此異鄉縣。", "願言敦疇昔，勿以棄疵賤。"]'),
('70169124-9a1e-49d1-89ea-bd054f7f1b0b','題明月堂二首 一','劉氏亡婦','唐','唐诗','tang','','[]','蟬鬢驚秋華髮新，可憐紅隙盡埃塵。',32,'全唐诗/poet.tang.48000.json','["蟬鬢驚秋華髮新，可憐紅隙盡埃塵。", "西山一夢何年覺，明月堂前不見人。"]'),
('5e9e715e-7fc9-42ca-a14c-1fc624350465','題明月堂二首 二','劉氏亡婦','唐','唐诗','tang','','[]','玉鉤風急響丁東，回首西山似夢中。',32,'全唐诗/poet.tang.48000.json','["玉鉤風急響丁東，回首西山似夢中。", "明月堂前人不到，庭前一夜老秋風。"]'),
('64a3dde0-580d-474c-a784-f04b3ef6cccb','詩','故臺城妓','唐','唐诗','tang','','[]','歌罷玉樓月，舞殘金縷衣。',48,'全唐诗/poet.tang.48000.json','["歌罷玉樓月，舞殘金縷衣。", "勻鈿收迸節，歛黛別重闈。", "網斷蛛猶織，梁春燕不歸。", "那堪回首處，江步野棠飛。"]'),
('0ffe4c13-9ad6-4985-b231-80361ffed3e9','金陵詞','故臺城妓','唐','唐诗','tang','','[]','宮中細草香紅濕，宮內纖腰碧窗泣。',32,'全唐诗/poet.tang.48000.json','["宮中細草香紅濕，宮內纖腰碧窗泣。", "唯有虹梁春燕雛，猶傍珠簾玉鉤立。"]'),
('46b2443b-fd4d-49ee-85b1-3b5f738e88f4','示宋善威','無名女鬼','唐','唐诗','tang','','[]','月落三株樹，日映九重天。',24,'全唐诗/poet.tang.48000.json','["月落三株樹，日映九重天。", "良夜歡宴罷，暫別庚申年。"]'),
('5bceef88-00b6-443c-a185-c69f3e03b8b7','詩 一','無名鬼','唐','唐诗','tang','','[]','江上檣竿一百尺，山中樓臺十二重。',32,'全唐诗/poet.tang.48000.json','["江上檣竿一百尺，山中樓臺十二重。", "山僧樓上望江上，指點檣竿笑殺儂。"]'),
('d8d30735-3682-4fc1-81c5-1c09a5770ee8','詩 二','無名鬼','唐','唐诗','tang','','[]','仙人未必便仙去，還在人間人不知。',32,'全唐诗/poet.tang.48000.json','["仙人未必便仙去，還在人間人不知。", "手把白鬚從兩鹿，相逢却問姓名誰。"]'),
('caf419a4-a0df-4cb3-bb13-ee47a8ec2926','句','穠華','唐','唐诗','tang','','[]','柏堂新成樂未央，迴來迴去繞裴郎。',16,'全唐诗/poet.tang.48000.json','["柏堂新成樂未央，迴來迴去繞裴郎。"]'),
('34a5445d-4ff6-4f68-a77e-12a45691f68e','句','張守中','唐','唐诗','tang','','[]','薄命蘇秦頻去國，多情潘岳旋興悲。',32,'全唐诗/poet.tang.48000.json','["薄命蘇秦頻去國，多情潘岳旋興悲。", "今夜若棲芳草徑，爲傳幽意達王孫。"]'),
('0e646716-6430-43ad-9aee-c0da45a342bd','句','無名鬼','唐','唐诗','tang','','[]','芫花半落，松風晚清。',10,'全唐诗/poet.tang.48000.json','["芫花半落，松風晚清。"]'),
('a367a96d-c6cd-4696-bcfb-b644f5a36494','渾家門客聯句 一','不詳','唐','唐诗','tang','','[]','自與渾家鄰，馨香遂滿身。',24,'全唐诗/poet.tang.48000.json','["自與渾家鄰，馨香遂滿身。", "無心好清靜，人用去灰塵。"]'),
('f347f297-2fc3-408d-9cef-107caabfd61a','渾家門客聯句 二','不詳','唐','唐诗','tang','','[]','終朝每去依煙火，春至還歸養子孫。',32,'全唐诗/poet.tang.48000.json','["終朝每去依煙火，春至還歸養子孫。", "曾向苻王筆端坐，爾來求食渾家門。"]'),
('56371040-0a1f-4141-97fa-e26b1907feb5','長鬚國駙馬詠妻','不詳','唐','唐诗','tang','','[]','花無葉不妍，女無鬚亦醜。',26,'全唐诗/poet.tang.48000.json','["花無葉不妍，女無鬚亦醜。", "丈人試遣惣無，未必不如惣有。"]'),
('c4a13248-aed5-4408-8d69-678c8e0b39d3','原陵老翁吟','不詳','唐','唐诗','tang','','[]','野田荆棘春，閨閣綺羅新。',260,'全唐诗/poet.tang.48000.json','["野田荆棘春，閨閣綺羅新。", "出沒頭上日，生死眼前人。", "欲知我家在何處，北邙松柏正爲鄰。", "洛陽女兒羅綺多，無奈孤翁老去何，奈爾何。", "正色鴻燾，神思化伐。", "穹施后承，光負玄設。", "嘔淪吐萌，垠倪散截。", "迷腸郗曲，䨴零霾曀。", "雀燬龜水，健馳御屈。", "拿尾研動，袾袾哳哳。", "㳷用祕功，以嶺以穴。", "柂薪伐藥，莽榤萬茁。", "嘔律則祥，佛倫惟薩。", "牡虛無有，頤咽蘂屑。", "肇素未來，晦明興滅。", "五行七曜，成此閏餘。", "上帝降靈，歲且涒徐。", "蛇蛻其皮，吾亦神攄。", "九九六六，束身天除。", "何以充喉，吐納太虛。", "何以蔽踝，霞袂雲袽。", "哀爾浮生，櫛比荒墟。", "吾復麗氣，還形之初。", "在帝左右，道濟忽諸。"]'),
('b21cf19f-854d-4a0a-9c77-3ab33b94193e','嚴含質詩 一','不詳','唐','唐诗','tang','','[]','昔爲仙子今爲虎，流落陰崖足風雨。',32,'全唐诗/poet.tang.48000.json','["昔爲仙子今爲虎，流落陰崖足風雨。", "更將斑毳被余身，千載空山萬般苦。"]'),
('46911494-dfa0-4001-a27d-a8235716ecf3','嚴含質詩 二','不詳','唐','唐诗','tang','','[]','下玄八千億甲子，丹飛先生嚴含質。',49,'全唐诗/poet.tang.48000.json','["下玄八千億甲子，丹飛先生嚴含質。", "謫下中天被斑革，六千甲子，血食澗飲廁猨狖。", "下濁界，景雲元紀升太一。"]'),
('18f2d824-0200-4e23-8dbb-483726bd698e','李微詩','不詳','唐','唐诗','tang','','[]','偶因狂疾成殊類，災患相任不可逃。',64,'全唐诗/poet.tang.48000.json','["偶因狂疾成殊類，災患相任不可逃。", "今日爪牙誰敢敵，當時聲跡共相高。", "我爲異物蓬茅下，君已乘軺氣勢豪。", "此夕溪山對明月，不成長嘯但成嗥。"]'),
('7cbebfdd-2974-46ef-b399-f27a69574b0b','維揚空莊四怪聯句','不詳','唐','唐诗','tang','','[]','齊紈魯縞如霜雪，寥亮高聲予所發。',64,'全唐诗/poet.tang.48000.json','["齊紈魯縞如霜雪，寥亮高聲予所發。", "嘉賓良會清夜時，煌煌燈燭我能持。", "清冷之泉候朝汲，桑綆相牽常出入。", "爨薪貯泉相煎熬，充他口腹我爲勞。"]'),
('6fd8b4cc-de12-4683-b608-f21f1634f690','柳藏經二絕句 一','不詳','唐','唐诗','tang','','[]','寒水停園沼，秋池滿敗荷。',24,'全唐诗/poet.tang.48000.json','["寒水停園沼，秋池滿敗荷。", "杜門窮典籍，所得事今多。"]'),
('1e571c24-326f-47c3-a161-91fb5ff41f23','柳藏經二絕句 二','不詳','唐','唐诗','tang','','[]','誰謂三才貴，余觀萬化同。',24,'全唐诗/poet.tang.48000.json','["誰謂三才貴，余觀萬化同。", "心虛嫌蠹食，年老怯狂風。"]'),
('3c35f75b-cdd0-463c-9e81-d74494772679','太白山魔誑道士詩','不詳','唐','唐诗','tang','','[]','三秋稽顙叩真靈，龍虎交時金液成。',32,'全唐诗/poet.tang.48000.json','["三秋稽顙叩真靈，龍虎交時金液成。", "絳雪既凝身可度，蓬壺頂上彩雲生。"]'),
('6d877cad-559e-40a3-ba25-30eaff832e1e','金缶魅詩','不詳','唐','唐诗','tang','','[]','色分藍葉青，聲比磬中鳴。',24,'全唐诗/poet.tang.48000.json','["色分藍葉青，聲比磬中鳴。", "七月初七夜，吾當示汝形。"]'),
('e2776a09-efd7-4022-b2fa-e44c2a1d9c47','東陽夜怪詩 一','不詳','唐','唐诗','tang','','[]','誰家掃雪滿庭前，萬壑千峰在一拳。',32,'全唐诗/poet.tang.48000.json','["誰家掃雪滿庭前，萬壑千峰在一拳。", "吾心不覺侵衣冷，曾向此中居幾年。"]'),
('1ae73843-88b1-4611-9426-abce7549c85f','東陽夜怪詩 二','不詳','唐','唐诗','tang','','[]','擁褐藏名無定蹤，流沙千里度衰容。',32,'全唐诗/poet.tang.48000.json','["擁褐藏名無定蹤，流沙千里度衰容。", "傳得南宗心地後，此身應便老雙峰。"]'),
('716f33b2-d9e1-4ca3-9089-8ea68e9d1794','東陽夜怪詩 三','不詳','唐','唐诗','tang','','[]','爲有閻浮珍重因，遠離西國赴咸秦。',32,'全唐诗/poet.tang.48000.json','["爲有閻浮珍重因，遠離西國赴咸秦。", "自從無力休行道，且作頭陀不繫身。"]'),
('e2a5a6d2-17ae-43e9-b24d-48b88b84d7de','東陽夜怪詩 四','不詳','唐','唐诗','tang','','[]','長安城東洛陽道，車輪不息塵浩浩。',32,'全唐诗/poet.tang.48000.json','["長安城東洛陽道，車輪不息塵浩浩。", "爭利貪前競著鞭，相逢盡是塵中老。"]'),
('8ef3da5d-c758-46d6-96aa-c6e76dcd26eb','東陽夜怪詩 五','不詳','唐','唐诗','tang','','[]','日晚長川不計程，離羣獨步不能鳴。',32,'全唐诗/poet.tang.48000.json','["日晚長川不計程，離羣獨步不能鳴。", "賴有青青河畔草，春來猶得慰羈情。"]'),
('369deef3-fa19-4b2b-8a31-d5b6f1e9556b','東陽夜怪詩 六','不詳','唐','唐诗','tang','','[]','愛此飄颻六出公，輕瓊冷絮舞長空。',32,'全唐诗/poet.tang.48000.json','["愛此飄颻六出公，輕瓊冷絮舞長空。", "當時正逐秦丞相，騰躑川原喜北風。"]'),
('cf88997e-b729-4d0f-b0bb-b7ebcca84b46','東陽夜怪詩 七','不詳','唐','唐诗','tang','','[]','事君同樂義同憂，那校糟糠滿志休。',32,'全唐诗/poet.tang.48000.json','["事君同樂義同憂，那校糟糠滿志休。", "不是守株空待兔，終當逐鹿出林丘。"]'),
('9becb56d-e25e-4fca-96de-613751da9dbb','東陽夜怪詩 八','不詳','唐','唐诗','tang','','[]','少年長負飢鷹用，內顧曾無寵鶴心。',32,'全唐诗/poet.tang.48000.json','["少年長負飢鷹用，內顧曾無寵鶴心。", "秋草驅除思去宇，平原毛血興從禽。"]'),
('9e6e7829-ac91-4eb3-a1b2-1c9d1d37a5aa','東陽夜怪詩 九','不詳','唐','唐诗','tang','','[]','舞鏡爭鸞綵，臨場定鶻拳。',24,'全唐诗/poet.tang.48000.json','["舞鏡爭鸞綵，臨場定鶻拳。", "正思仙仗日，翹首仰樓前。"]'),
('9e46985e-3191-43cd-8b61-9379099bcb97','東陽夜怪詩 十','不詳','唐','唐诗','tang','','[]','養鬬形如木，迎春質似泥。',24,'全唐诗/poet.tang.48000.json','["養鬬形如木，迎春質似泥。", "信如風雨在，何憚跡卑棲。"]'),
