('832a400e-8878-401c-a250-d2b4a29c147c','青蘿帳女贈穆郎 褰帳','不詳','唐','唐诗','tang','','[]','揉藍綠色麴塵開，靜見三星入坐來。',32,'全唐诗/poet.tang.48000.json','["揉藍綠色麴塵開，靜見三星入坐來。", "桂影已圓攀折後，子孫長作棟梁材。"]'),
('29ef184f-fe89-4e2d-a041-05d4282d112c','青蘿帳女贈穆郎 題碧花牋','不詳','唐','唐诗','tang','','[]','珠露素中書繾綣，青蘿帳裏寄鴛鴦。',32,'全唐诗/poet.tang.48000.json','["珠露素中書繾綣，青蘿帳裏寄鴛鴦。", "自憐孤影清秋夕，灑淚裴回滴冷光。"]'),
('7acc1c4c-bc11-42c8-bdae-5c162c918018','白蘋洲碧衣女子吟','不詳','唐','唐诗','tang','','[]','碧水色堪染，白蓮香正濃。',48,'全唐诗/poet.tang.48000.json','["碧水色堪染，白蓮香正濃。", "分飛俱有恨，此別幾時逢。", "藕隱玲瓏玉，花藏縹緲容。", "何當假雙翼，聲影暫相從。"]'),
('86b8346e-2c20-4395-9921-f0c915658a92','新林驛女吟示歐陽訓','不詳','唐','唐诗','tang','','[]','月明階悄悄，影隻腰身小。',24,'全唐诗/poet.tang.48000.json','["月明階悄悄，影隻腰身小。", "誰是鶱翔人，願爲比翼鳥。"]'),
('9627bc46-36fa-4781-bd99-7b35ad84f967','新林驛女吟示歐陽訓 擊盤歌送歐陽訓酒','不詳','唐','唐诗','tang','','[]','飛燕身輕未是輕，枉將弱質在巖扃。',32,'全唐诗/poet.tang.48000.json','["飛燕身輕未是輕，枉將弱質在巖扃。", "今來不得同鴛枕，相伴神魂入杳冥。"]'),
('50abcf72-68f3-4f67-b83b-b2097f1d50d3','白衣女子木葉上詩','不詳','唐','唐诗','tang','','[]','桃花洞口開，香蘂落莓苔。',24,'全唐诗/poet.tang.48000.json','["桃花洞口開，香蘂落莓苔。", "佳景雖堪翫，蕭郎殊未來。"]'),
('263a7f05-f019-491d-8e58-83331ec38244','白衣女子木葉上詩 席上歌','不詳','唐','唐诗','tang','','[]','洞府深沈春日長，山花無主自芬芳。',32,'全唐诗/poet.tang.48000.json','["洞府深沈春日長，山花無主自芬芳。", "凭闌寂寂看明月，欲種桃花待阮郎。"]'),
('6d7c12f7-d6f1-4311-86ea-474cdbe398eb','鳳皇臺怪和歌四首 一','不詳','唐','唐诗','tang','','[]','深閨閑鎖難成夢，那得同衾共繡牀。',32,'全唐诗/poet.tang.48000.json','["深閨閑鎖難成夢，那得同衾共繡牀。", "一自與郎江上別，霜天更自覺宵長。"]'),
('0e6d6661-bc83-43e9-9690-f369496bdcaf','鳳皇臺怪和歌四首 二','不詳','唐','唐诗','tang','','[]','愁聽黃鶯喚友聲，空閨曙色夢初成。',32,'全唐诗/poet.tang.48000.json','["愁聽黃鶯喚友聲，空閨曙色夢初成。", "窗間總有花牋紙，難寄妾心字字明。"]'),
('21b4db81-318b-4684-b6c0-5c87c06c58e0','鳳皇臺怪和歌四首 三','不詳','唐','唐诗','tang','','[]','寂靜璇閨度歲年，竝頭蓮葉又如錢。',32,'全唐诗/poet.tang.48000.json','["寂靜璇閨度歲年，竝頭蓮葉又如錢。", "愁人獨處那堪此，安得君來獨枕眠。"]'),
('ec2e8459-6da4-4a6f-9466-edcdf3630133','鳳皇臺怪和歌四首 四','不詳','唐','唐诗','tang','','[]','臥病匡牀香屢添，夜深猶有一絲煙。',32,'全唐诗/poet.tang.48000.json','["臥病匡牀香屢添，夜深猶有一絲煙。", "懷君無計能成夢，更恨砧聲到枕邊。"]'),
('6732b2dc-449f-4fae-93ef-48379963e669','夢丹書','肅宗','唐','唐诗','tang','','[]','厥不云乎，惟其惟時。',20,'全唐诗/poet.tang.48000.json','["厥不云乎，惟其惟時。", "上天所保，福祿不虧。"]'),
('cb96429f-19e0-4d34-aa00-a1e3f586cb37','夢黃衣童子歌','代宗','唐','唐诗','tang','','[]','中五之德方峨峨，胡胡呼呼何奈何。',16,'全唐诗/poet.tang.48000.json','["中五之德方峨峨，胡胡呼呼何奈何。"]'),
('50e5dcaf-4519-4191-b3fe-a8cf1cadb302','夢揚州樂妓和詩','劉禹錫','唐','唐诗','tang','','[]','花作嬋娟玉作妝，風流爭似舊徐娘。',32,'全唐诗/poet.tang.48000.json','["花作嬋娟玉作妝，風流爭似舊徐娘。", "夜深曲曲灣灣月，萬里隨君一寸腸。"]'),
('31a93f0b-e4c8-4bf1-a7f6-a04903a159ad','夢中美人歌','邢鳳','唐','唐诗','tang','','[]','長安少女踏春陽，何處春陽不斷腸？舞袖弓彎渾忘却，羅衣空換九秋霜。',32,'全唐诗/poet.tang.48000.json','["長安少女踏春陽，何處春陽不斷腸？舞袖弓彎渾忘却，羅衣空換九秋霜。"]'),
('d77cd87d-1535-457d-a9d7-1c978292b67a','夢中詩','石季武','唐','唐诗','tang','','[]','聳轡排金闕，乘軒上漢槎。',24,'全唐诗/poet.tang.48000.json','["聳轡排金闕，乘軒上漢槎。", "浮名何足戀，高舉入煙霞。"]'),
('3b500309-2aff-43c5-95e3-7b58e4f527ac','葬西施挽歌','王炎','唐','唐诗','tang','','[]','西望吳王國，雲書鳳字牌。',48,'全唐诗/poet.tang.48000.json','["西望吳王國，雲書鳳字牌。", "連江起珠帳，擇地葬金釵。", "滿地紅心草，三層碧玉階。", "春風無處所，悽恨不勝懷。"]'),
('8006fc56-8f6e-4f87-a8d1-463632c8b3db','秦夢詩三首 一','沈亞之','唐','唐诗','tang','','[]','泣葬一枝紅，生同死不同。',48,'全唐诗/poet.tang.48000.json','["泣葬一枝紅，生同死不同。", "金鈿墜芳草，香繡滿春風。", "舊日聞簫處，高樓當月中。", "梨花寒食夜，深閉翠微宮。"]'),
('518c5bb0-46ca-4937-bb3c-521419f7d84e','秦夢詩三首 二','沈亞之','唐','唐诗','tang','','[]','擊髆舞，恨滿煙光無處所。',56,'全唐诗/poet.tang.48000.json','["擊髆舞，恨滿煙光無處所。", "淚如雨，欲擬著辭不成語。", "金鳳銜紅舊繡衣，幾度宮中同看舞。", "人間春日正歡樂，日暮東風何處去。"]'),
('c0135625-b581-4537-9dc8-7281af2b4273','秦夢詩三首 三','沈亞之','唐','唐诗','tang','','[]','君王多感放東歸，從此秦宮不復期。',32,'全唐诗/poet.tang.48000.json','["君王多感放東歸，從此秦宮不復期。", "春景似傷秦喪主，落花如雨淚燕脂。"]'),
('51b1fb56-a714-4666-9fb4-939d90464ca0','夢中詩','盧獻卿','唐','唐诗','tang','','[]','卜築郊原古，青山無四鄰。',24,'全唐诗/poet.tang.48000.json','["卜築郊原古，青山無四鄰。", "扶疎遶屋樹，寂寞獨歸人。"]'),
('f0875b11-a161-49cc-9bda-6a5337996edf','夢爲吳泰伯作勝兒歌','劉景復','唐','唐诗','tang','','[]','繁弦已停雜吹歇，勝兒調弄邏娑撥。',256,'全唐诗/poet.tang.48000.json','["繁弦已停雜吹歇，勝兒調弄邏娑撥。", "四弦攏撚三五聲，喚起邊風駐明月。", "大聲嘈嘈奔淈淈，浪蹙波翻倒溟渤。", "小弦切切怨颸颸，鬼哭神悲秋窸窣。", "倒腕斜挑摯流電，春雷直戛騰秋鶻。", "漢妃徒得端正名，秦女虛誇有仙骨。", "我聞天寶十年前，涼州未作西戎窟。", "麻衣右衽皆漢民，不省胡塵暫蓬勃。", "太平之末狂胡亂，犬豕崩騰恣唐突。", "玄宗未到萬里橋，東洛西京一時沒。", "漢土民皆沒爲虜，飲恨吞聲空嗢咽。", "時看漢月望漢天，怨氣衝星成彗孛。", "國門之西八九鎮，高城深壘閉閑卒。", "河湟咫尺不能收，輓粟推車徒兀兀。", "今朝聞奏涼州曲，使我心神暗超忽。", "勝兒若向邊塞彈，征人淚血應闌干。"]'),
('0290882c-a58a-42c6-a885-adc856521bc3','夢中辭','郭仁表','唐','唐诗','tang','','[]','飄風暴雨可思惟，鶴望巢門歛翅飛，吾道之宗正可依。',24,'全唐诗/poet.tang.48000.json','["飄風暴雨可思惟，鶴望巢門歛翅飛，吾道之宗正可依。"]'),
('aaa35a16-6b58-44c9-b85a-f43d701e4f4b','夢崔嘏妻詩','國邵南','唐','唐诗','tang','','[]','莫以真留妾，從他理管弦。',24,'全唐诗/poet.tang.48000.json','["莫以真留妾，從他理管弦。", "容華難久駐，知得幾多年。"]'),
('836fe1c0-1ada-4158-8669-378e166e6347','夢白衣婦人歌詞 一','盧絳','唐','唐诗','tang','','["\u6292\u60c5"]','玉京人去秋簫索，畫簷鵲起梧桐落。',52,'全唐诗/poet.tang.48000.json','["玉京人去秋簫索，畫簷鵲起梧桐落。", "欹枕悄無言，月和殘夢圓。", "背燈惟暗泣，甚處碪聲急。", "眉黛小山攢，芭蕉生暮寒。"]'),
('798c2db1-a126-4f31-bd61-fed5d6e87026','夢白衣婦人歌詞 二','盧絳','唐','唐诗','tang','','[]','清風明月夜深時，箕箒盧郎恨已遲。',32,'全唐诗/poet.tang.48000.json','["清風明月夜深時，箕箒盧郎恨已遲。", "他日孟家坡上約，再來相見是佳期。"]'),
('98368183-d8a9-4d4b-a45b-c6fbbaea78e1','夢舜撫琴歌','張生','唐','唐诗','tang','','[]','南風薰薰兮草芊芊，妙有之音兮歸清弦。',43,'全唐诗/poet.tang.48000.json','["南風薰薰兮草芊芊，妙有之音兮歸清弦。", "蕩蕩之教兮由自然，熈熈之化兮吾道全，薰薰兮思何傳。"]'),
('81693941-5773-4626-b828-65416b22ebd9','夢康仙示詩','漳郡守','唐','唐诗','tang','','[]','賣藥因循未得還，却因耽酒到人間。',32,'全唐诗/poet.tang.48000.json','["賣藥因循未得還，却因耽酒到人間。", "有心只戀琵琶坂，無意更登山上山。"]'),
('8f68f36e-80ab-45ae-bfe6-318ae1fbb473','夢中歌','獨孤遐叔妻白氏','唐','唐诗','tang','','[]','今夕何夕，存耶沒耶。',27,'全唐诗/poet.tang.48000.json','["今夕何夕，存耶沒耶。", "良人去兮天之涯，園樹傷心兮三見花。"]'),
('15f660ce-d6c6-48b1-a38c-787bc38874e6','夢中歌 一','張生妻','唐','唐诗','tang','','[]','歎衰草，絡緯聲切切。',26,'全唐诗/poet.tang.48000.json','["歎衰草，絡緯聲切切。", "良人一去不復還，今夕坐愁鬢如雪。"]'),
('5f8a2d08-2a69-4f8a-86df-8bc7a677c157','夢中歌 二','張生妻','唐','唐诗','tang','','[]','勸君酒，君莫辭。',20,'全唐诗/poet.tang.48000.json','["勸君酒，君莫辭。", "落花徒繞枝，流水無返期。"]'),
('2e315b31-af38-4361-8147-571ee2cde3c5','夢中歌 三','張生妻','唐','唐诗','tang','','[]','怨空閨，秋日亦難暮。',22,'全唐诗/poet.tang.48000.json','["怨空閨，秋日亦難暮。", "夫壻斷音書，遙天鴈空度。"]'),
('100e82db-454f-48fd-8f2d-2862c0d8b89e','夢中歌 四','張生妻','唐','唐诗','tang','','[]','切切夕風急，露滋庭草濕。',24,'全唐诗/poet.tang.48000.json','["切切夕風急，露滋庭草濕。", "良人去不回，焉知掩閨泣。"]'),
('a6308ad2-713e-4866-a3ae-776ffb5ff69c','夢中歌 五','張生妻','唐','唐诗','tang','','[]','螢火穿白楊，悲風入荒草。',24,'全唐诗/poet.tang.48000.json','["螢火穿白楊，悲風入荒草。", "疑是夢中遊，愁迷故園道。"]'),
('8d5d5a9d-ab75-4ad0-88ff-d14cb6536d5e','夢中歌 六','張生妻','唐','唐诗','tang','','[]','花前始相見，花下又相送。',24,'全唐诗/poet.tang.48000.json','["花前始相見，花下又相送。", "何必言夢中，人生盡如夢。"]'),
('f4340ea4-f288-4ab2-9085-feee0fcfe948','夢王尚書口授吟','張氏女','唐','唐诗','tang','','[]','鬟梳鬧掃學宮妝，獨立閑庭納夜涼。',32,'全唐诗/poet.tang.48000.json','["鬟梳鬧掃學宮妝，獨立閑庭納夜涼。", "手把玉簪敲砌竹，清歌一曲月如霜。"]'),
('92827562-54bf-4aa0-8db0-1ccb15c93a01','歌 一','病狂人','唐','唐诗','tang','','[]','踏陽春，人間三月雨和塵。',28,'全唐诗/poet.tang.48000.json','["踏陽春，人間三月雨和塵。", "陽春踏，秋風起，腸斷人間白髮人。"]'),
('28122823-f99f-49a0-a7b1-b2019a77a36a','歌 二','病狂人','唐','唐诗','tang','','[]','五靈華，曉玲瓏，天府由來汝府中。',32,'全唐诗/poet.tang.48000.json','["五靈華，曉玲瓏，天府由來汝府中。", "惆悵此情言不盡，一丸蘿蔔火吾宮。"]'),
('597f9b00-dbab-49ac-b9a4-38e7ea891af0','題禪窟蘭若','陳季卿','唐','唐诗','tang','','[]','霜鐘鳴時夕風急，亂鴉又望寒林集。',32,'全唐诗/poet.tang.48000.json','["霜鐘鳴時夕風急，亂鴉又望寒林集。", "此時輟櫂悲且吟，獨向蓮華一峰立。"]'),
('e95b166d-5bbc-4c13-9b3f-dd0382ee6435','題潼關普通院門','陳季卿','唐','唐诗','tang','','[]','度關悲失志，萬緒亂心機。',48,'全唐诗/poet.tang.48000.json','["度關悲失志，萬緒亂心機。", "下坂馬無力，掃門塵滿衣。", "計謀多不就，心口自相違。", "已作羞歸計，還勝羞不歸。"]'),
('e46afb60-4162-47d7-8622-667cd957ebc3','江亭晚望題書齋','陳季卿','唐','唐诗','tang','','[]','立向江亭滿目愁，十年前事信悠悠。',64,'全唐诗/poet.tang.48000.json','["立向江亭滿目愁，十年前事信悠悠。", "田園已逐浮雲散，鄉里半隨逝水流。", "川上莫逢諸釣叟，浦邊難得舊沙鷗。", "不緣齒發未遲暮，吟對遠山堪白頭。"]'),
('2d151bde-42b8-4e4d-8ed8-e3f1d47a8d27','別妻','陳季卿','唐','唐诗','tang','','[]','月斜寒露白，此夕去留心。',48,'全唐诗/poet.tang.48000.json','["月斜寒露白，此夕去留心。", "酒至添愁飲，詩成和淚吟。", "離歌悽鳳管，別鶴怨瑤琴。", "明夜相思處，秋風吹半衾。"]'),
('a45a02ed-ec8f-4516-9f36-c5d542cdeb87','別兄弟','陳季卿','唐','唐诗','tang','','[]','謀身非不早，其奈命來遲。',48,'全唐诗/poet.tang.48000.json','["謀身非不早，其奈命來遲。", "舊友皆霄漢，此身猶路岐。", "北風微雪後，晚景有雲時。", "惆悵清江上，區區趁試期。"]'),
('a5e77086-1ce8-433b-a28a-3e7fe95fc389','夢中句','周延翰','唐','唐诗','tang','','[]','紫髯之伴有丹砂。',8,'全唐诗/poet.tang.48000.json','["紫髯之伴有丹砂。"]'),
('2666126c-e959-4244-8de8-3eece65eec8d','夢中和句','任玠','唐','唐诗','tang','','[]','故國路遙歸去來，春風天遠望不盡。',16,'全唐诗/poet.tang.48000.json','["故國路遙歸去來，春風天遠望不盡。"]'),
('cf6dd7ae-a2bc-4f6d-80cc-565192ae63d6','夢中語','杜牧','唐','唐诗','tang','','[]','辭春不及秋，昆脚與皆頭。',12,'全唐诗/poet.tang.48000.json','["辭春不及秋，昆脚與皆頭。"]'),
('e195121c-3ace-4c2c-968b-082772f9597b','夢中詩','胥偃','唐','唐诗','tang','','[]','昔作樹頭花，今爲塚中骨。',12,'全唐诗/poet.tang.48000.json','["昔作樹頭花，今爲塚中骨。"]'),
('2b295157-55b9-4ef1-b480-d66d1e626e60','夢中語','曾崇範妻','唐','唐诗','tang','','[]','田頭有鹿跡，由尾著日炙。',12,'全唐诗/poet.tang.48000.json','["田頭有鹿跡，由尾著日炙。"]'),
('a57f658a-f9fe-44f0-bba4-5fb3666e8a56','紀夢句','張孜','唐','唐诗','tang','','[]','上天知我憶其人，使向人間夢中見。',16,'全唐诗/poet.tang.48000.json','["上天知我憶其人，使向人間夢中見。"]'),
('e91b22e8-ba3f-4ecf-bab0-01f48a13fee1','嘲蘇世長','高祖','唐','唐诗','tang','','[]','名長意短，口正心邪。',24,'全唐诗/poet.tang.48000.json','["名長意短，口正心邪。", "棄忠貞於鄭國，忘信義於吾家。"]'),
('2e7923c1-27ba-4e95-bd7d-ed572fa60f8b','戲題畫','睿宗','唐','唐诗','tang','','[]','喚出眼，何用苦深藏。',20,'全唐诗/poet.tang.48000.json','["喚出眼，何用苦深藏。", "縮却鼻，何畏不聞香。"]'),
('f8c40dac-d201-4bf5-80b2-a4c3e889b288','嘲蕭瑀射','歐陽詢','唐','唐诗','tang','','[]','急風吹緩箭，弱手馭強弓。',48,'全唐诗/poet.tang.48000.json','["急風吹緩箭，弱手馭強弓。", "欲高飜復下，應西還更東。", "十迴俱著地，兩手幷擎空。", "借問誰爲此，乃應是宋公。"]'),
('70652987-854b-46c9-ac28-36eae35702a0','與歐陽詢互嘲 一','長孫無忌','唐','唐诗','tang','','[]','聳膊成山字，埋肩不出頭。',24,'全唐诗/poet.tang.48000.json','["聳膊成山字，埋肩不出頭。", "誰家麟角上，畫此一獼猴。"]'),
('c856a9b8-f782-4410-9439-86de2e9a8cb6','與歐陽詢互嘲 二','長孫無忌','唐','唐诗','tang','','[]','索頭連背暖，漫襠畏肚寒。',24,'全唐诗/poet.tang.48000.json','["索頭連背暖，漫襠畏肚寒。", "只因心渾渾，所以面團團。"]'),
('b7f111d9-7d30-4a69-920f-f55998e470b9','爲溫僕射嘲竹','裴略','唐','唐诗','tang','','[]','竹，風吹青肅肅，凌冬葉不凋，經春子不熟。',36,'全唐诗/poet.tang.48000.json','["竹，風吹青肅肅，凌冬葉不凋，經春子不熟。", "虚心未得待國士，皮上何湏生節目。"]');
